import Header from "../../components/Layout/Header";
import Content from "../../components/Layout/Content";
import Button from "../../components/CustomButtons/Button";
import Footer from "../../components/Layout/Footer";

import { makeStyles } from "@material-ui/core/styles";
import Primary from "../../components/Typography/Primary";
import ArrowRight from "assets/svg/ArrowRight";
import InsAthlete from "components/Card/InsAthlete";
import DietIcon from "assets/svg/DietIcon";
import Instructor from "assets/svg/Coach"
import Athlete from "assets/svg/WeightLifting"
import List from '@material-ui/core/List';
import ListItem from '@material-ui/core/ListItem';
import ListItemText from '@material-ui/core/ListItemText';
import ListItemAvatar from '@material-ui/core/ListItemAvatar';
import Earth from "assets/svg/Earth"
import Money from "assets/svg/Money"
import CustomTabs from "components/CustomTabs/CustomTabs.js";
import CustomInput from "components/CustomInput/CustomInput.js";
import ReactFlagsSelect from 'react-flags-select';
import axios from "utils/axios";
import api from "utils/api"
import 'react-flags-select/css/react-flags-select.css';
import PhoneInput from 'react-phone-input-2'
import './location.css'
const useStyles = makeStyles((theme) => ({
  root: {
    padding: "0px 30px 0px 30px",
  },
  title: {
    fontFamily: "Proxima Nova",
    fontWeight: "bold",
   fontSize:22,
  
    marginTop:2,
    color:"#172A44",
    paddingLeft: 25,
  },
  mainDiv: {
    padding: "15px 25px 15px 25px",

    flexDirection: "column",

    fontFamily: "Proxima Nova",
  },
  child1: {
    display: "flex",
    paddingBottom: "10px",
    flex: 1,
    width: "100%",
    flexDirection: "column",
    alignItems: "center",
  },
  child2: {
    flex: 2,
    paddingTop: "10px",
    display: "flex",
    flexDirection: "column",
    alignItems: "center",
    width: "100%",
    justifyContent: "space-around"
  },

  Footer: {
    margin: "0px 20px 20px 20px",
  },
  list:{
    width: '100%',
  },
  primary:{
    fontWeight: "bold",
    fontSize: 18,
    lineHeight: "18px",

  },
  secondary:{
      fontFamily: "Proxima Nova",
      marginTop:12,
      color: "rgba(23,42,68,0.75)",
    fontWeight:"normal",
    fontSize: 16,
    lineHeight: "22px",
    /* or 129% */
    paddingLeft: 25,
    paddingRight:25

  },
  icon:{
      fontSize:45,
      marginRight:25
  },
  CountryInput:{
      width:"300px",
      border:"1px solid grey"
  },
  label:{
      fontWeight:"bold",
      color:"#172A44",
      fontSize: "16px",
lineHeight: "29px",
marginBottom:10,
marginLeft:3
  },
  centeredDiv:{
    flexGrow: 1,
    display: "flex",
    justifyContent: "center",
    flexDirection: "column",
    flex:1,

  }
}));

export default function Screen2(props) {
  const classes = useStyles();
const [location,setLocation]=useState(props.Onboarding.country?props.Onboarding.country:"US")


const changeLocation=(country)=>{
  setLocation(country)

}

useEffect(() => {console.log(props.location)})



  const handleNext = () => {
    
  props.updateOnboarding({location})
    axios.post(`${api.protocol}${api.baseUrl}${api.userSignup}`,{...props.Onboarding,location}).then((response)=>{
      props.updateFeedback({loading:false,snackbar:true,message:"Figgs account created succesfully",severity:"success"})
      props.updateOnboarding({token:response.data.token})
      localStorage.setItem("token",response.data.token)
      axios.defaults.headers.common['Authorization']=response.data.token
      props.initProfile({...response.data.userData,password:"",...response.data})
    
    
    
      props.history.push("/profile/welcome",props.location.state)
    
  

})
.catch((error)=>{
  return props.updateFeedback({loading:false,snackbar:true,message:"Unexpected error! Please try again",severity:"error"})
})
};
  
   

const skip = () => {
    
  props.updateFeedback({loading:true})
    axios.post(`${api.protocol}${api.baseUrl}${api.userSignup}`,{...props.Onboarding}).then((response)=>{
      props.updateFeedback({loading:false,snackbar:true,message:"Figgs account created succesfully",severity:"success"})
      props.updateOnboarding({token:response.data.token})
     
      localStorage.setItem("token",response.data.token)
      axios.defaults.headers.common['Authorization']=response.data.token
      props.initProfile({...response.data.userData,password:"",...response.data})
    
    
    
      props.history.push("/profile/welcome",props.location.state)

})
.catch((error)=>{
  return props.updateFeedback({loading:false,snackbar:true,message:"Unexpected error! Please try again",severity:"error"})
})
};



  return (
    <Container>
     <Header  />

      <Content flex>
      <div className={classes.centeredDiv}>
        <span className={classes.title}>Location</span>
       
        <div className={classes.mainDiv}>
         
        <ReactFlagsSelect
        onSelect={changeLocation}
        defaultCountry={location}
    searchable={true}
    searchPlaceholder="Search for a country" />
        </div>
        </div>
      </Content>
      <Footer actionButton>
        <Button
         onClick={handleNext}
          variant="contained"
          fullWidth
          size="lg"
          bold
          startIcon={<span style={{ marginLeft: 10 }}></span>}
          sideIcons
          endIcon={<ArrowRight />}
        >
          Next
        </Button>

        <Button
        onClick={skip}
         style={{color:"#172A44",marginTop:10}}
          fullWidth
          size="lg"
          bold
        
        >
          Skip
        </Button>
      </Footer>
    </Container>
  );
}
