import React, { Component } from 'react'
import { Router, Route, Switch } from "react-router-dom";
import ChatDetails from "../Screens/Chat/ChatUser2"

import InstructorProfile from "../Screens/common/profileInstructor"
import {createChat,getChatUsers,getChats,setUserChatDetails,createAttachment,updateChat,AddChatData,updateChatRead} from "../store/actions/chat"
import ProgramControl from "../Screens/common/ProgramControl"
import {deleteProgram} from "../store/actions/createProgram"

import {connect } from "react-redux"
 class Chat extends Component {

 
    render() {
        return (
            <div>
            
                   <Route exact  path={`${this.props.match.path}/dt/:id`} render={(props)=><ChatDetails {...this.props} id={props.match.params.id} state={this.props.history.location.state?this.props.history.location.state:null}/>} />
          
            </div>
        )
    }
}

const mapStateToProps =(state) => {
    return {
       
        Profile:state.Profile,
        Chat:state.Chat
    }
}


export default connect(mapStateToProps,{deleteProgram,createChat,getChatUsers,getChats,setUserChatDetails,createAttachment,updateChat,AddChatData,updateChatRead})(Chat)