import React, { Component ,useState} from "react";
import Container from "../../components/Layout/Container";
import Header from "../../components/Layout/Header";
import Content from "../../components/Layout/Content";
import Button from "../../components/CustomButtons/Button";
import Footer from "../../components/Layout/Footer";

import { makeStyles } from "@material-ui/core/styles";
import Primary from "../../components/Typography/Primary";
import ArrowRight from "assets/svg/ArrowRight";
import InsAthlete from "components/Card/InsAthlete";
import DietIcon from "assets/svg/DietIcon";
import Instructor from "assets/svg/Coach"
import Athlete from "assets/svg/WeightLifting"
const useStyles = makeStyles((theme) => ({
  root: {
    padding: "0px 30px 0px 30px",
  },
  title: {
    fontFamily: "Proxima Nova",
    fontWeight: "bold",
   fontSize:22,
    marginBottom: 5,
    marginTop:2,

    paddingLeft: 25,
  },
  mainDiv: {
    display: "flex",
    flex: 1,
    padding: 30,
    marginBottom:50,
    flexDirection: "column",
    justifyContent: "space-around",
    alignItems: "center",
    fontFamily: "Proxima Nova",
  },
  child1: {
    display: "flex",
    paddingBottom: "10px",
    flex: 1,
    width: "100%",
    flexDirection: "column",
    alignItems: "center",
  },
  child2: {
    flex: 1,
    paddingTop: "10px",
    display: "flex",
    flexDirection: "column",
    alignItems: "center",
    width: "100%",
  },
  bottomText: {
    marginTop: "20px",
  },
  Footer: {
    margin: "0px 20px 20px 20px",
  },
}));

export default function Screen2(props) {
  const classes = useStyles();
const type=props.Onboarding.type
 const setType=(value) =>{
   props.updateOnboarding({ type:value });
 }
  return (
    <Container>
      <Header />

      <Content flex>
     

        <div className={classes.mainDiv}>
          <div className={classes.child1}>
            <InsAthlete
            selected={type=="Athlete"}
              Title={"Athlete"}
              onClick={()=>setType("Athlete")}
             
              Icon={(cls) => <Athlete className={cls} />}
            />
          </div>
          <div className={classes.child2}>
            <InsAthlete
             selected={type=="Instructor"}
              onClick={()=>setType("Instructor")}
              Title={"Instructor"}
             
              Icon={(cls) => <Instructor className={cls} />}
            />
          </div>
        </div>
      </Content>
      <Footer actionButton>
        {<Button
        onClick={()=>props.history.push("/onboarding/account-summary",props.location.state)}
          variant="contained"
          fullWidth
          size="lg"
          bold
          disabled={type==null}
          startIcon={<span style={{ marginLeft: 10 }}></span>}
          sideIcons
          endIcon={<ArrowRight />}
        >
          Continue
        </Button>}
      </Footer>
    </Container>
  );
}
