import React, { Component ,useState} from "react";
import Container from "../../components/Layout/Container";
import Header from "../../components/Layout/Header";
import Content from "../../components/Layout/Content";
import Button from "../../components/CustomButtons/Button";
import Footer from "../../components/Layout/Footer";
import axios from "utils/axios";
import api from "utils/api"
import UploadIcon from "assets/svg/HealthReport.js"
import UploadCard from "components/Widget/AddImages"
import { makeStyles } from "@material-ui/core/styles";
import Primary from "../../components/Typography/Primary";
import ArrowRight from "assets/svg/ArrowRight";
import InsAthlete from "components/Card/InsAthlete";
import DietIcon from "assets/svg/DietIcon";
import Instructor from "assets/svg/Coach"
import Athlete from "assets/svg/WeightLifting"
import List from '@material-ui/core/List';
import ListItem from '@material-ui/core/ListItem';
import ListItemText from '@material-ui/core/ListItemText';
import ListItemAvatar from '@material-ui/core/ListItemAvatar';
import Earth from "assets/svg/Earth"
import Money from "assets/svg/Money"
import CustomTabs from "components/CustomTabs/CustomTabs.js";
import CustomInput from "components/CustomInput/CustomInput.js";
import PhoneInput from 'react-phone-input-2'
import Camera from "assets/svg/Camera"
import 'react-phone-input-2/lib/style.css'
const useStyles = makeStyles((theme) => ({
  root: {
    padding: "0px 30px 0px 30px",
  },
  title: {
    fontFamily: "Proxima Nova",
    fontWeight: "700",
    marginBlockStart: 0,
    marginBottom: 5,
    color:"#172A44",
    paddingLeft: 25,
  },
  mainDiv: {
    display: "flex",
    flex: 1,
    padding: 25,
    paddingTop:10,
    flexDirection: "column",

    fontFamily: "Proxima Nova",
  },
  child1: {
    display: "flex",
    paddingBottom: "10px",
    flex: 1,
    width: "100%",
    flexDirection: "column",
    alignItems: "center",
  },
  child2: {
    flex: 2,
    paddingTop: "10px",
    display: "flex",
    flexDirection: "column",
    alignItems: "center",
    width: "100%",
    justifyContent: "space-around"
  },

  Footer: {
    margin: "0px 20px 20px 20px",
  },
  list:{
    width: '100%',
  },
  primary:{
    fontWeight: "bold",
    fontSize: 16,
    lineHeight: "18px",
    color: "#172A44",
  },
  secondary:{
      fontFamily: "Proxima Nova",
      marginTop:12,
      color: "rgba(23,42,68,0.75)",
    fontWeight:500,
    fontSize: 16,
    lineHeight: "22px",
    /* or 129% */
    paddingLeft: 25,
    paddingRight:25

  },
  icon:{
      fontSize:45,
      marginRight:25
  }
}));

export default function Screen2(props) {
  const classes = useStyles();
  const[verificationCode,setCode]=useState("")
  const setHealtInfo=(att,value) => {
    props.updateOnboarding({healthInfo:{...props.Onboarding.healthInfo,[att]:value}})
  }
  


  return (
    <Container>
      <Header />

      <Content flex >
        <h2 className={classes.title}>Health information 2</h2>
        <p className={classes.secondary}>
        This information will be private unless
you give access to instructors.
        </p>
        <div className={classes.mainDiv}>
         
      
        <CustomInput
                 multiline
                 labelText="Allergies and reactions"
                    bottomUnderline
        inputProps={{
          defaultValue:props.Onboarding.healthInfo.allergiesAndReactions,
            type: "text",
            style:{marginTop: 10 },
            placeholder:"Add yours",
            onBlur:(e)=>setHealtInfo("allergiesAndReactions",e.target.value)
        }}
                        formControlProps={{
                          fullWidth: true,
                          
                        }}
                      />
                         <br/>
        <CustomInput
                 multiline
                 labelText="Medications and supplements"
                    bottomUnderline
        inputProps={{
          defaultValue:props.Onboarding.healthInfo.medications,
            type: "text",
            style:{marginTop: 10 },
            placeholder:"Add yours",
            onBlur:(e)=>setHealtInfo("medications",e.target.value)
        }}
                        formControlProps={{
                          fullWidth: true,
                          
                        }}
                      />
                       
                       <br/>
                       <div className={classes.primary}>Health Document</div>
    <br/>
    <div>
   <UploadCard A4 files={props.Onboarding.healthInfo.healthDocumnents?props.Onboarding.healthInfo.healthDocumnents:[]} sm Title={""} Icon={(cls)=><UploadIcon color="primary" style={{fontSize:50,marginLeft:10}}/>}  handleUpdate={(files)=>props.updateOnboarding({healthInfo:{...props.Onboarding.healthInfo,healthDocumnents:files}})} />
    </div>
        </div>
      </Content>
      <Footer actionButton>
        <Button
          onClick={()=>props.type=="profile"?props.history.push(`/profile/profile-preview`,props.location.state):props.history.push(`/onboarding/location`,props.location.state)}
        
          variant="contained"
          fullWidth
          size="lg"
          bold
          startIcon={<span style={{ marginLeft: 10 }}></span>}
          sideIcons
          endIcon={<ArrowRight />}
        >
          Submit
        </Button>
        <Button
     onClick={()=>props.history.push(`/onboarding/location`,props.location.state)}
         style={{color:"#172A44",marginTop:10}}
          fullWidth
          size="lg"
          bold
        
        >
          Skip
        </Button>
      </Footer>
    </Container>
  );
}
