export default function Screen2(props) {
  const classes = useStyles();
const changeName=(event) =>{
 
  props.updateOnboarding({name:event.target.value})
}

const handleNext=()=>{
  if(props.Onboarding.name.length>0){
    props.history.push("/onboarding/account-dob",props.location.state)
  }
  else{
    return props.updateFeedback({loading:false,snackbar:true,message:"Please enter a valide name!",severity:"warning"})
  }
}
  return (
    <Container>
      <Header />

      <Content flex>
        <span className={classes.title}>Add your name</span>
        <p className={classes.secondary}>Adding your name will make people know that you are on figgs</p>
        <div className={classes.mainDiv}>
         
        <CustomInput
                      
                        id="float"
        inputProps={{
            onChange: changeName,
            value:props.Onboarding.name,
           placeholder:"Full name"
        }}
                        formControlProps={{
                          fullWidth: true,
                          
                        }}
                      />
        </div>
      </Content>
      <Footer actionButton>
        <Button
         onClick={handleNext}
          variant="contained"
          fullWidth
          size="lg"
          bold
          startIcon={<span style={{ marginLeft: 10 }}></span>}
          sideIcons
          endIcon={<ArrowRight />}
        >
          Next
        </Button>
      </Footer>
    </Container>
  );
}
