const useStyles = makeStyles((theme) => ({
 
  title: {
    fontFamily: "Proxima Nova",
    fontWeight: "700",
    marginBlockStart: 0,
    marginBottom: 5,
paddingTop:10,
fontSize: "24px",
color:"#172A44",
    paddingLeft: 25,
  },
  mainDiv: {
    display: "flex",
    flexDirection: "column",
    height: "100%",
    padding: 25,
    paddingTop:25,
   

    fontFamily: "Proxima Nova",
  },
 
 

  Footer: {
    margin: "0px 20px 20px 20px",
  },
  list:{
    width: '100%',
  },
  primary:{
    fontFamily: "Proxima Nova",
   paddingLeft:3,
       fontWeight: "bold",
       fontSize: "16px",
       lineHeight: "38px",
       color: "#172A44"
  },
  
 

  icon:{
position: "absolute",

top:0, 
right:"10vw"
  },
 
  Avatar:{
      position:"absolute",
      bottom:-25,
      width:60,
      height:60,
      left:30
  },
 
  label:{
    fontFamily:"Proxima Nova",
fontSize:"14px",
padding:25,
color: "#007EA0",
display:"flex",
flexDirection:"row",
alignItems:"center",

  }
}));

export default function Screen2(props) {
  const classes = useStyles();

  const uploadDietFile=(e)=>{
    props.updateFeedback({loading:true})
    handleuploadImage(e).then((result)=>{
      props.updateFeedback({loading:false})
props.updateProgram({DietPlan:{...props.ProgramDetails.DietPlan,file:result.data.Location}})
    },err=> props.updateFeedback({loading:false}))
  }

  return (
    <Container>
      <Header button={<Button onClick={()=>props.history.push(`${props.match.url}/upload-banner`)}>Skip</Button>} />

      <Content flex>
        <input type="file" id={"dietFile"} onChange={uploadDietFile} style={{display:"none"}}/>
        <h2 className={classes.title}>Diet plan</h2>
       {/* <div className={classes.label} onClick={()=>document.getElementById("dietFile").click()}>
           <AddFolder color="primary" style={{marginRight:10}}/>
          { !props.ProgramDetails.DietPlan.file?"Upload file":"Change File"}</div>



          {props.ProgramDetails.DietPlan.file&& <div className={classes.label} style={{paddingTop:0}} >
           <AttachmentIcon color="primary" style={{marginRight:10}}/>
           {props.ProgramDetails.DietPlan.file.split("-").pop()}</div>} */}



        <div className={classes.mainDiv}>
       <Grid container spacing={2}>
<Grid item xs={12}>
<CustomInput
                        labelText="TItle"
                        id="float"
                        bottomUnderline
                      
        inputProps={{
          style:{marginTop:5},
            value:props.ProgramDetails.DietPlan.Title,
            onChange:(e)=>props.updateProgram({ DietPlan:{...props.ProgramDetails.DietPlan,Title:e.target.value}}),
            placeholder:"Example, low carb, bulk"
           
        }}
                        formControlProps={{
                          fullWidth: true,
                          
                        }}
                      />
</Grid>
<br/>
<Grid item xs={12}>
<CustomInput
                        labelText="Food"
                        id="float"
                        multiline
                        bottomUnderline
                        rows={6}
        inputProps={{
          value:props.ProgramDetails.DietPlan.Description,
          onChange:(e)=>props.updateProgram({ DietPlan:{...props.ProgramDetails.DietPlan,Description:e.target.value}}),
            placeholder:"Meal 1: fruits etc",
           style:{marginTop:12}
        }}
                        formControlProps={{
                          fullWidth: true,
                          
                        }}
                      />
</Grid>
 </Grid>
        </div>
      </Content>
      <Footer actionButton>
      
        <Button
        onClick={()=>props.history.push(`${props.match.url}/upload-banner`)}
          variant="contained"
          fullWidth
          size="lg"
          bold
          disabled={props.ProgramDetails.DietPlan.Description==null||props.ProgramDetails.DietPlan.Description.length<2}
          startIcon={<span style={{ marginLeft: 10 }}></span>}
          sideIcons
          endIcon={<ArrowRight />}
        >
          Next
        </Button>
   
      </Footer>
    </Container>
  );
}
