import React, { Component } from "react";
import Container from "../../components/Layout/Container";
import Header from "../../components/Layout/Header";
import Content from "../../components/Layout/Content";
import Button from "../../components/CustomButtons/Button";
import Footer from "../../components/Layout/Footer";
import UploadCard from "components/Card/UploadCard"
import { makeStyles } from "@material-ui/core/styles";
import Primary from "../../components/Typography/Primary";
import ArrowRight from "assets/svg/ArrowRight";
import InsAthlete from "components/Card/InsAthlete";
import ReactPlayer from 'react-player'
import DietIcon from "assets/svg/DietIcon";
import Instructor from "assets/svg/Coach"
import Athlete from "assets/svg/WeightLifting"
import Camera from "assets/svg/Camera"
import AddVideo from "assets/svg/CamVid"
import Grid from "@material-ui/core/Grid"
import {theme} from "assets/css/theme"
const useStyles = makeStyles((theme) => ({
  root: {
    padding: "0px 30px 0px 30px",
  },
  title: {
    fontFamily: "Proxima Nova",
    fontWeight: "bold",
   fontSize:24,
   marginBlockStart: 0,
    marginBottom: 5,
    marginTop:10,
    color:"#172A44",
    paddingLeft: 25,
  },
  mainDiv: {
    display: "flex",
    flexDirection: "column",
    height: "100%",
    padding: 25,
    paddingTop:10,

    fontFamily: "Proxima Nova",
  },
  child1: {
    display: "flex",
    paddingBottom: "10px",
    flex: 1,
    width: "100%",
    flexDirection: "column",
    alignItems: "center",
  },
  child2: {
    flex: 1,
    paddingTop: "10px",
    display: "flex",
    flexDirection: "column",
    alignItems: "center",
    width: "100%",
  },
  bottomText: {
    marginTop: "20px",
  },
  Footer: {
    margin: "0px 20px 20px 20px",
  },
  label:{
    fontFamily:"Proxima Nova",
fontSize:"16px",
padding:5,
fontWeight:"bold",
color:"#172A44"
  },
  text:{
    fontFamily:"Proxima Nova",
fontSize:"14px",
padding:5,
paddingLeft:25,
paddingRight:25,
marginBottom:10,
color:"#747F8F"
  }
}));

export default function Screen2(props) {
  const classes = useStyles();
  const onSkip=()=>{
    props.history.push(`${props.match.url}/${props.mode=="edit"?"setup-payment":"clientDetails"}`)
  }
  return (
    <Container>
      <Header button={<Button onClick={onSkip}>Skip</Button>}  />

      <Content flex>
        <h2 className={classes.title}>Cover photo</h2>
     
        <div className={classes.text}>You can add a cover image for the program you have created</div>


        <div className={classes.mainDiv}>
     
          <Grid container spacing={2}>
            <Grid item xs={12} style={{height:"48vw"}}>
             
            <UploadCard 
               Title={"Choose a file"}
               text={"Discover programs made by instructors and use them to reach your fitness goals"} 
               Icon={(cls)=><Camera style={{fontSize:50,color:props.ProgramDetails.BannerImage?"#fff":"#007EA0"}}/>} 
               file={props.ProgramDetails.BannerImage}
               image
               handleSuccess={(file)=>props.updateProgram({BannerImage:file})}
               handleError={()=>props.updateFeedback({loading:false,snackbar:true,message:"Error in uploading banner video",severity:"error"})}
               />
            </Grid>
        
          </Grid>
          
        </div>
      </Content>
      <Footer actionButton>
    
     
        <Button
        onClick={()=>props.history.push(`${props.match.url}/${props.mode=="edit"?"setup-payment":"clientDetails"}`)}
          variant="contained"
          fullWidth
          size="lg"
          bold
          startIcon={<span style={{ marginLeft: 10 }}></span>}
          sideIcons
          endIcon={<ArrowRight />}
        >
          Next
        </Button>

     
      </Footer>
    </Container>
  );
}
