import React, { Component, useState } from "react";
import Container from "../../components/Layout/Container";
import Header from "../../components/Layout/Header";
import Content from "../../components/Layout/Content";
import Button from "../../components/CustomButtons/Button";
import Footer from "../../components/Layout/Footer";
import { handleuploadImage } from "utils/uploader";
import { makeStyles } from "@material-ui/core/styles";
import Primary from "../../components/Typography/Primary";
import ArrowRight from "assets/svg/ArrowRight";
import InsAthlete from "components/Card/InsAthlete";
import DietIcon from "assets/svg/DietIcon";
import Instructor from "assets/svg/Coach";
import Athlete from "assets/svg/WeightLifting";
import List from "@material-ui/core/List";
import ListItem from "@material-ui/core/ListItem";
import ListItemText from "@material-ui/core/ListItemText";
import ListItemAvatar from "@material-ui/core/ListItemAvatar";
import AddIcon from "assets/svg/AddOutlined";
import ProfileImg from "assets/img/screens/profile.png";
import CustomTabs from "components/CustomTabs/CustomTabs.js";
import CustomInput from "components/CustomInput/CustomInput.js";
import PhoneInput from "react-phone-input-2";
import "react-phone-input-2/lib/style.css";
const useStyles = makeStyles((theme) => ({
  root: {
    padding: "0px 30px 0px 30px",
  },
  title: {
    fontFamily: "Proxima Nova",
    fontWeight: "bold",
    fontSize: 22,
    marginBottom: 5,
    marginTop: 2,
    color:"#172A44",
    paddingLeft: 25,
  },
  mainDiv: {
    display: "flex",
    flex: 1,
    padding: 25,
    paddingTop: 10,
    flexDirection: "column",
    justifyContent: "center",
    alignItems: "center",
    fontFamily: "Proxima Nova",
  },
  child1: {
    display: "flex",
    paddingBottom: "10px",
    flex: 1,
    width: "100%",
    flexDirection: "column",
    alignItems: "center",
  },
  child2: {
    flex: 2,
    paddingTop: "10px",
    display: "flex",
    flexDirection: "column",
    alignItems: "center",
    width: "100%",
    justifyContent: "space-around",
  },

  Footer: {
    margin: "0px 20px 20px 20px",
  },
  list: {
    width: "100%",
  },
  primary: {
    fontWeight: "bold",
    fontSize: 18,
    lineHeight: "18px",
  },
  secondary: {
    fontFamily: "Proxima Nova",
    marginTop: 12,
    color: "rgba(23,42,68,0.75)",
    fontWeight: "normal",
    fontSize: 16,
    lineHeight: "22px",
    /* or 129% */
    paddingLeft: 25,
    paddingRight: 25,
  },
  Image: {
    width: "45vw",
    height: "45vw",
    background: "#FAFAFA",
    borderRadius: "50%",
  },
  icon: {
    position: "absolute",

    top: 0,
    right: "10vw",
  },
}));

export default function Screen2(props) {
  const classes = useStyles();
  const [open, close] = useState(false);
  const [profilePic, setPic] = useState(props.Onboarding.profilePic);

  const uploadImage = (e) => {
    props.updateFeedback({ loading: true });
    handleuploadImage(e).then(
      (res) => {
        setPic(res.data.Location);
        props.updateFeedback({ loading: false });
      },
      (rej) => {
        if (rej == "size")
          return props.updateFeedback({
            loading: false,
            snackbar: true,
            message: "Image size should be less than 5 mb",
            severity: "warning",
          });
        else
          return props.updateFeedback({
            loading: false,
            snackbar: true,
            message: "Error in uploading image please try again later",
            severity: "warning",
          });
      }
    );
  };

  const handleNext = () => {
    props.updateOnboarding({ profilePic: profilePic });
    if (props.Onboarding.type == "Instructor") {
      props.history.push(`${props.match.url}/account-bio`,props.location.state);
    } else {
      props.history.push(`${props.match.url}/health-goals`,props.location.state);
    }
  };

  const handleSkip = () => {
    props.updateOnboarding({ profilePic: "" });

    if (props.Onboarding.type == "Instructor") {
      props.history.push(`${props.match.url}/account-bio`,props.location.state);
    } else {
      props.history.push(`${props.match.url}/health-goals`,props.location.state);
    }
  };

  return (
    <Container>
      <Header />
      <input
        type="file"
        onChange={uploadImage}
        id="profile-img"
        style={{ display: "none" }}
      />
      <Content flex={true}>
        <span className={classes.title}>Profile photo</span>
        <p className={classes.secondary}>
          Your profile photo will be viewed in your figgs profile
        </p>
        <div
          className={classes.mainDiv}
          onClick={() => document.getElementById("profile-img").click()}
        >
          <div style={{ position: "relative" }}>
            <div
              style={{
                backgroundImage: `url(${profilePic ? profilePic : ProfileImg})`,
                backgroundSize: "cover",
              }}
              
              className={classes.Image}
            ></div>
            {!profilePic && (
              <AddIcon
                style={{
                  fontSize: 80,
                  position: "absolute",
                  top: 0,
                  right: "-5vw",
                }}
              />
            )}
          </div>
          <br />
          {profilePic && (
            <Button size="sm" variant="outlined">
              Change photo
            </Button>
          )}
        </div>
      </Content>
      <Footer actionButton>
        <Button
          onClick={handleNext}
          variant="contained"
          fullWidth
          size="lg"
          bold
          disabled={!profilePic}
          startIcon={<span style={{ marginLeft: 10 }}></span>}
          sideIcons
          endIcon={<ArrowRight />}
        >
          Add photo
        </Button>

        <Button
          onClick={handleSkip}
          style={{ color: "#172A44", marginTop: 10 }}
          fullWidth
          size="lg"
          bold
        >
          Skip
        </Button>
      </Footer>
    </Container>
  );
}
