import axios from "utils/axios"
import api from "utils/api"
import socketIOClient from "socket.io-client";
import {store} from "store"
import {fetchNotification} from "store/actions/Notifications"
import {hadleNewMessage,getChatCount} from "store/actions/chat"
export const signOut = () => {

localStorage.removeItem("token")
store.dispatch({type:"INIT_NEW_PROGRAM"})

setTimeout(() =>window.location="/",1000)
    return (dispatch) => {

store.dispatch({type:"InitAP"})
store.dispatch({type:"INIT_PROFILE"})
store.dispatch({type:"INIT_NEW_PROGRAM"})
store.dispatch({type:"RESET_NOTIFICATIONS"})
store.dispatch({type:"INIT_PL"})
store.dispatch({type:"INIT_CLIENT_EXERCISE"})
store.dispatch({type:"INITIALIZE_CHAT"})
        dispatch({ type:"LOG_OUT"})
  };
};

export const searchUser = (qry)=>{
 
  return new Promise((res,reject)=>{
   
    axios.get(`${api.protocol}${api.baseUrl}${api.searchUser}${qry}`).then((response)=>{
    
        return res(response.data.result)
      }).catch((err)=>{
          
            return reject("error")
            })


        })
      
}

export const fetchUser = (id)=>{
 
  return new Promise((res,reject)=>{
    store.dispatch({ type:"UPDATE_FEED", payload: {loading:true}})
   
    axios.get(`${api.protocol}${api.baseUrl}${api.fetchUsers}_id=${id}`).then((response)=>{
      store.dispatch({ type:"UPDATE_FEED", payload: {loading:false}})
        return res(response.data.ServerResponse[0])
      }).catch((err)=>{
        store.dispatch({ type:"UPDATE_FEED", payload: {loading:false}})
            return reject("error")
            })


        })

  
      
}

export const fetchPrograms = (id)=>{
 
  return new Promise((res,reject)=>{

   
    axios.get(`${api.protocol}${api.baseUrl}${api.allPrograms}createdBy=${id}`).then((response)=>{

        return res(response.data.ServerResponse)
      }).catch((err)=>{

            return reject("error")
            })


        })

  
      
}


export const createOrder = (data)=>{
 
  return new Promise((res,reject)=>{
    store.dispatch({ type:"UPDATE_FEED", payload: {loading:true}})
   
    axios.post(`${api.protocol}${api.baseUrl}${api.createOrder}`,{...data}).then((response)=>{
      store.dispatch({ type:"UPDATE_FEED", payload: {loading:false}})
        return res(response.data.ServerResponse)
      }).catch((err)=>{
        store.dispatch({ type:"UPDATE_FEED", payload: {loading:false}})
            return reject("error")
            })


        })

  
      
}

export const getSentPrograms = (id)=>{
 
  return new Promise((res,reject)=>{
    store.dispatch({ type:"UPDATE_FEED", payload: {loading:true}})
   
    axios.get(`${api.protocol}${api.baseUrl}${api.getSentPrograms}${id}`).then((response)=>{
      store.dispatch({ type:"UPDATE_FEED", payload: {loading:false}})
        return res(response.data)
      }).catch((err)=>{
        store.dispatch({ type:"UPDATE_FEED", payload: {loading:false}})

        if(err.response&&err.response.status==404){
          store.dispatch({ type:"UPDATE_FEED", payload: {loading:false,snackbar:true,message:"Upable to find requested resource",severity:"error"}})
          window.location="/"
        }
            return reject(err)

            })


        })

  
      
}


export const addProgram = (id)=>{
 
  return new Promise((res,reject)=>{
    store.dispatch({ type:"UPDATE_FEED", payload: {loading:true}})
   
    axios.post(`${api.protocol}${api.baseUrl}${api.addOrder}${id}`).then((response)=>{
      store.dispatch({ type:"UPDATE_FEED", payload: {loading:false,snackbar:true,message:"Program added to your account",severity:"success"}})
        
     return res(response.data)

      }).catch((err)=>{
        store.dispatch({ type:"UPDATE_FEED", payload: {loading:false,snackbar:true,message:"Upable to add requested resource",severity:"error"}})

        if(err.response&&err.response.status==500){
          store.dispatch({ type:"UPDATE_FEED", payload: {loading:false,snackbar:true,message:"Upable to add requested resource",severity:"error"}})
    
        }
            return reject(err)

            })


        })

  
      
}


export const getStats = (id)=>{

return new Promise((res,reject)=>{

axios.get(`${api.protocol}${api.baseUrl}${api.getStats}${id}`).then((response)=>{
console.log(response.data)
return res(response.data)
})

})


}


export const socketConnection=()=>{
  if (store.getState().Profile.token) {
    const socket = socketIOClient(`${api.protocol}${api.socketurl}`, {
      query: "token=" + store.getState().Profile._id,
    });

    socket.on("connect", () => {});

   socket.on(store.getState().Profile._id,(data)=>{
    
       
       if(data.type=="new-notification" )
     { 
       
      fetchNotification(0,30,data.data)


      
      
      }
      
    })

    socket.on(store.getState().Profile._id,(data)=>{
    
       
      if(data.type=="new-message" )
    { 
      
     hadleNewMessage(data.data)


     
     
     }
     
   })



   getChatCount()
    store.dispatch({type:"ADD_SOCKET", payload: {socket}})
    

  }



}