import React, { Component } from "react";
import Container from "../../components/Layout/Container";
import Header from "../../components/Layout/Header";
import Content from "../../components/Layout/Content";
import Button from "../../components/CustomButtons/Button";
import Footer from "../../components/Layout/Footer";

import { makeStyles } from "@material-ui/core/styles";
import Primary from "../../components/Typography/Primary";
import ArrowRight from "assets/svg/ArrowRight";
import InsAthlete from "components/Card/InsAthlete";
import DietIcon from "assets/svg/DietIcon";
import Instructor from "assets/svg/Coach"
import Earth from "assets/svg/Earth"
import LockOutlinedIcon from '@material-ui/icons/LockOutlined';
import Athlete from "assets/svg/WeightLifting"
const useStyles = makeStyles((theme) => ({
  root: {
    padding: "0px 30px 0px 30px",
  },
  title: {
    fontFamily: "Proxima Nova",
    fontWeight: "bold",
   fontSize:22,
    marginBottom: 5,
    marginTop:2,
    color:"#172A44",

    paddingLeft: 25,
  },
  mainDiv: {
    display: "flex",
    flex: 1,
    padding: 25,
    flexDirection: "column",
    justifyContent: "space-around",
    alignItems: "center",
    fontFamily: "Proxima Nova",
  },
  child1: {
    display: "flex",
    paddingBottom: "10px",
    flex: 1,
    width: "100%",
    flexDirection: "column",
    alignItems: "center",
  },
  child2: {
    flex: 1,
    paddingTop: "10px",
    display: "flex",
    flexDirection: "column",
    alignItems: "center",
    width: "100%",
  },
  bottomText: {
    marginTop: "20px",
  },
  Footer: {
    margin: "0px 20px 20px 20px",
  },
}));

export default function Screen2(props) {
  const classes = useStyles();

  return (
    <Container>
      <Header />

      <Content flex>
        <span className={classes.title}>Choose a type</span>

        <div className={classes.mainDiv}>
          <div className={classes.child1}>
            <InsAthlete
            onClick={()=>props.updateProgram({Type:"public"})}
selected={props.ProgramDetails.Type=="public"}
              Title={"Public"}
              text={
               "Your program will be discovered by clients in marketplace"
              }
              Icon={(cls) => <Earth className={cls} />}
            />
          </div>
          <div className={classes.child2}>
            <InsAthlete
         selected={props.ProgramDetails.Type=="private"}
              onClick={()=>props.updateProgram({Type:"private"})}
              Title={"Private"}
              text={
                "Send the program privately for clients. Cannot be shown in figgs discovery"
              }
              Icon={(cls) => <LockOutlinedIcon className={cls} />}
            />
          </div>
        </div>
      </Content>
      <Footer actionButton>
        <Button
        onClick={()=>props.history.push(`${props.match.url}/update-details`)}
        disabled={props.ProgramDetails.Type==null}
          variant="contained"
          fullWidth
          size="lg"
          bold
          startIcon={<span style={{ marginLeft: 10 }}></span>}
          sideIcons
          endIcon={<ArrowRight />}
        >
          Continue
        </Button>
      </Footer>
    </Container>
  );
}
