export default function Screen2(props) {
  const classes = useStyles();

  return (
    <Container>
      <Header />

      <Content flex>
  <span className={classes.title}>Welcome {props.Onboarding.name}</span>
        <p className={classes.secondary}>Continue set to up your instructor<br/> account. you can <b style={{color:"#007ea0"}}>change username</b> or<br/> <b style={{color:"#007ea0"}}>change account</b> type.</p>
        <div className={classes.mainDiv}>
         
      
        </div>
      </Content>
      <Footer actionButton>
        <Button
        onClick={()=>props.Onboarding.type =="Instructor"?props.history.replace("/instructor"):props.history.replace("/athlete")}
          variant="contained"
          fullWidth
          size="lg"
          bold
          startIcon={<span style={{ marginLeft: 10 }}></span>}
          sideIcons
          endIcon={<ArrowRight />}
        >
          Next
        </Button>
      </Footer>
    </Container>
  );
}
