import React, {useState,useEffect} from 'react';
import Badge from '@material-ui/core/Badge';
import Avatar from '@material-ui/core/Avatar';
import classNames from "classnames";
import { makeStyles, withStyles } from '@material-ui/core/styles';
import SocketContext from "context/SocketContext"
import {connect } from "react-redux"
import socketIOClient from "socket.io-client";
const StyledBadge = withStyles((theme) => ({

  imageHeight:{
  width:"100%",
  height: "auto",
    objectFit:"fill"
  },
  badge: {
    backgroundColor: '#44b700',
    color: '#44b700',
    boxShadow: `0 0 0 2px ${theme.palette.background.paper}`,
    '&::after': {
      position: 'absolute',
      top: 0,
      left: 0,
      width: '100%',
      height: '100%',
      borderRadius: '50%',
      animation: '$ripple 1.2s infinite ease-in-out',
      border: '1px solid currentColor',
      content: '""',
    },
  },
  '@keyframes ripple': {
    '0%': {
      transform: 'scale(.2)',
      opacity: 1,
    },
    '100%': {
      transform: 'scale(1.8)',
      opacity: 0,
    },
  },
}))(Badge);

const SmallAvatar = withStyles((theme) => ({
  root: {
    width: 22,
    height: 22,
    border: `2px solid ${theme.palette.background.paper}`,
  },
}))(Avatar);

const useStyles = makeStyles((theme) => ({
  root: {
    display: 'flex',
    '& > *': {
      margin: theme.spacing(1),
    },
  },
}));

function BadgeAvatars(props) {
  const classes = useStyles();
const [IsOnline,setOnline]=useState(false)

useEffect(() => {

 
 if(props.socket){
  
  
  props.socket.emit("getStatus",props.userId,(data) => {
    console.log("emmiting",data)
    if(data.type=="status" && data.isConnected==true)
    setOnline(true)
    else
    if(data.type=="status"&& data.isConnected==false)
    setOnline(false)
  })

      props.socket.on(props.userId,(data)=>{
        console.log("socket change")
         
         if(data.type=="status" && data.isConnected==true)
         setOnline(true)
         else
         if(data.type=="status"&& data.isConnected==false)
         setOnline(false)
      }
      
      
      )}

     

},[props.userId,props.socket])

console.log("called")
  return (
<>

{IsOnline?
      <StyledBadge
      className={props.AvatarPosition}
        overlap="circle"
        anchorOrigin={{
          vertical: 'bottom',
          horizontal: 'right',
        }}
        variant="dot"
      >
         <Avatar src={props.src} imgProps={{style:{width: "100%",height: "auto",objectFit: "fill"}}}  {...props} classes={{img:classes.imageHeight,root:classNames(props.className)}}  />
      </StyledBadge>:
      <Avatar src={props.src} imgProps={{style:{width: "100%",height: "auto",objectFit: "fill"}}}  {...props} classes={{img:classes.imageHeight,root:classNames(props.className,props.AvatarPosition)}} />
      }
    </>
  );
}

const LiveAvatar = props => (
    <SocketContext.Consumer>
    {socket => <BadgeAvatars {...props} socket={socket} />}
    </SocketContext.Consumer>
  )

  const mapStateToProps =(state) => {
    return({_id:state.Profile._id,})
  }

  export default connect(mapStateToProps,{})( LiveAvatar)