export default function Screen2(props) {
  const classes = useStyles();
  const next=()=>{
    let {Discount}=props.ProgramDetails
    if((Discount==null||Discount<0)){
      props.updateFeedback({loading:false,snackbar:true,message:"Please seklect valid discount amount",severity:"warning"})
    }
    else{
      props.history.push(`${props.match.url}/greeting`)
    }
  }

  return (
    <Container>
      <Header button={<Button onClick={next}>Next</Button>} />

      <Content flex>
        <h2 className={classes.title}>Set up a discount</h2>
      
        <div className={classes.mainDiv}>
       <Grid container spacing={2} justify="center" alignItems="center">
<Grid item xs={12}>
<div className={classes.list} style={{borderBottom:"1px solid #E8F2F6"}}>
    <div className={classes.listKey}>Current Price</div>
    <div className={classes.listValue}>${props.ProgramDetails.Price}</div>
    
</div>
</Grid>
<Grid item xs={12}>
<div className={classes.list} style={{borderBottom:"1px solid #E8F2F6"}}>
    <div className={classes.listKey}>Discount</div>
    <div className={classes.listValue}>${props.ProgramDetails.Discount}</div>
    
</div>
</Grid>

<Grid item xs={12}>
<div className={classes.list} >
    <div className={classes.listKey}>Total</div>
    <div className={classes.listValue}>${(props.ProgramDetails.Price-props.ProgramDetails.Discount).toFixed(2)}</div>
    
</div>
</Grid>
<Grid item xs={10} style={{marginTop:20}}>
<CustomInput
                
                id="error"
                lgCentered
                error

                formControlProps={{
                  
                  fullWidth: true
                }}
                inputProps={{
                  value:props.ProgramDetails.Discount,
                  onChange:(e)=>props.updateProgram({Discount:e.target.value}),
                  placeholder:"0.00",
                  type:"number"
                }}
              />
</Grid>
 </Grid>
        </div>
      </Content>
      <Footer actionButton>
        <Button
        onClick={next}
          variant="contained"
          fullWidth
          size="lg"
          bold
          startIcon={<span style={{ marginLeft: 10 }}></span>}
          sideIcons
          endIcon={<ArrowRight />}
        >
          Next
        </Button>
      </Footer>
    </Container>
  );
}
