import React from "react";
// @material-ui/core components
import { makeStyles } from "@material-ui/core/styles";

// core components
import GridContainer from "components/Grid/GridContainer.js";
import GridItem from "components/Grid/GridItem.js";
import classNames from "classnames";
import Button from "@material-ui/core/Button";
import Toolbar from "@material-ui/core/Toolbar";
import AppBar from "@material-ui/core/AppBar";
import IconButton from "@material-ui/core/IconButton";
import ListItem from "@material-ui/core/ListItem";
import ListItemText from "@material-ui/core/ListItemText";
import ListItemAvatar from "@material-ui/core/ListItemAvatar";
import ArrowRight from "assets/svg/ArrowRight";
import Avatar from "@material-ui/core/Avatar";
import ListItemSecondaryAction from "@material-ui/core/ListItemSecondaryAction";
import DietIcon from "assets/svg/DietIcon";
import Typography from "@material-ui/core/Typography";

const useStyles = makeStyles((theme) => ({
  avatar: {
    background: "#F9FCFD",
    borderRadius: "11px",
  },

  containerCol: {
    flexDirection: "column",
    justifyContent: "space-between",
    alignItems: "flex-start",
  },

  bordered: {
    borderTop: "0.5px solid #DDDDDD",
  },

  child: {
    display: "flex",
    flexDirection: "row",
    alignItems: "center",
  },
  title: {
    fontSize: 16,
    fontWeight: "bold",
    fontFamily: "Proxima Nova",
    lineHeight: "24px",
    color: "#172A44",
  },
  value: {
    fontSize: "12px",
    lineHeight: "16px",
    color: "#007EA0",
  },
  Icon: {
    fontSize: 32,
  },
  value: {
    fontFamily: "Proxima Nova",
    marginRight: 20,
    color: "#007EA0",
  },
  row: { 
      display: "flex" ,
flexDirection: "row",
alignItems:"center",
fontSize:16,
textTransform:"capitalize"


},

smallAvatar: {
    width:22,
    height:22,
    marginRight:5,
}
}));
export default function SectionNavbars(props) {
  const classes = useStyles();
  const container = classNames({
    [classes.container]: true,
    [classes.containerCol]: props.component,
    [classes.bordered]: props.bordered,
  });
  return (
    <ListItem button onClick={props.onClick} style={{paddingTop:15,paddingBottom:15,borderBottom:props.bordered?"0.5px solid #DDDDDD":"none"}}>
      <ListItemAvatar style={{paddingRight:10}}>
      
        {props.icon}
     
       
      </ListItemAvatar>
      <ListItemText
        primary={
          <React.Fragment>
            <h4 style={{ margin: 0,textTransform:"capitalize",fontSize:16,color: "#172A44"}}>{props.Title}</h4>
          </React.Fragment>
        }
        secondary={
          <React.Fragment>
            <div className={classes.row}>
              {props.url&&<Avatar src={props.url} className={classes.smallAvatar}></Avatar>}<span style={{color:"rgba(23,42,68,0.5)"}}>{props.Secondary}</span>
            </div>
          </React.Fragment>
        }
      />
      <ListItemSecondaryAction>
        <IconButton edge="end" aria-label="delete">
          <ArrowRight color="primary" style={{ fontSize: 22 }} />
        </IconButton>
      </ListItemSecondaryAction>
    </ListItem>
  );
}
