const useStyles = makeStyles((theme) => ({
  root: {
    padding: "0px 30px 0px 30px",
  },
  title: {
    fontFamily: "Proxima Nova",
    fontWeight: "700",
    marginBlockStart: 0,
    marginBottom: 5,
    color:"#172A44",
fontSize:24,
    paddingLeft: 25,
  },
  mainDiv: {
    display: "flex",
    flex: 1,
    padding: 25,
    paddingTop:10,
    flexDirection: "column",

    fontFamily: "Proxima Nova",
  },
  child1: {
    display: "flex",
    paddingBottom: "10px",
    flex: 1,
    width: "100%",
    flexDirection: "column",
    alignItems: "center",
  },
  child2: {
    flex: 2,
    paddingTop: "10px",
    display: "flex",
    flexDirection: "column",
    alignItems: "center",
    width: "100%",
    justifyContent: "space-around"
  },

  Footer: {
    margin: "0px 20px 20px 20px",
  },
  list:{
    width: '100%',
  },
  primary:{
    fontWeight: "bold",
    fontSize: 18,
    lineHeight: "18px",

  },
  secondary:{
      fontFamily: "Proxima Nova",
      marginTop:12,
      color: "rgba(23,42,68,0.75)",
    fontWeight:500,
    fontSize: 16,
    lineHeight: "22px",
    /* or 129% */
    paddingLeft: 25,
    paddingRight:25

  },
  icon:{
      fontSize:45,
      marginRight:25
  },


  validator:{
marginTop:8,
width: "80%",

  },
  validatorItem:{
    lineHeight: "29px",
    display: "flex",
    flexDirection: "row",
    alignItems:"center",
    fontSize:14,
    justifyContent:"space-between",
    fontFamily: "Proxima Nova",
    paddingBottom:10
  },


  colorLight:{
color:"rgba(23, 42, 68, 0.5);"
  },
  colorDark:{
    color:"#007EA0"
  }
}));

export default function Screen2(props) {
  const classes = useStyles();
const [showPass,setShowPass]=useState(false);
const [confirmPass,setConfirmPassword]=useState("");
const [showConfirmPass,setShowConfirmPass]=useState(false);

const [cEmail,setcEmail]=useState(false);
const [sLength,setsLength]=useState(false);
const [cSym,setcSym]=useState(false);


const password=props.Onboarding.password

  
const setPassword=(e)=>{

  props.updateOnboarding({password:e.target.value})
let pass=e.target.value
  let containsEmail=pass.includes(props.Onboarding.email)
  
  let length=pass.length>=8
  var regularExpression  = /^(?=.*[0-9])(?=.*[!@#$%^&*])[a-zA-Z0-9!@#$%^&*]/;
 
  let testSymbol=regularExpression.test(pass)

  setsLength(length)
  setcSym(testSymbol)
}

 const next=()=>{
  
  
 if(!sLength||!cSym){
  return props.updateFeedback({loading:false,snackbar:true,message:"Password should match below criteria",severity:"warning"})
 }

   if(validatePassword(password)&&password==confirmPass){


if(props.location.state&&props.location.state.accountType=="Athlete"){
  props.updateOnboarding({type:"Athlete"})
  props.history.push("/onboarding/account-summary",props.location.state)
}
else
 return props.history.push("/onboarding/account-type",props.location.state)



   }
   else{
     if(password!==confirmPass){
       return props.updateFeedback({loading:false,snackbar:true,message:"Password does not match",severity:"warning"})
     }
     else
    return props.updateFeedback({loading:false,snackbar:true,message:"Length of password must be greater than or equal to 8",severity:"warning"})
   }

 }








  
  return (
    <Container>
      <Header />

      <Content flex>
        <h2 className={classes.title}>Enter Password</h2>
        <br/>
        <div className={classes.mainDiv}>

          
         
        <CustomInput
                      labelText="Password"
                      
                      bottomUnderline
        inputProps={{
        
          defaultValue:props.Onboarding.password,
         onChange:setPassword,
         placeholder:"8 characters password",
         type:!showPass?"password":"text",
        endAdornment:!showPass?<VisibilityOffIcon onClick={()=>setShowPass(true)}/>:<VisibilityIcon onClick={()=>setShowPass(false)}/>
          
        }}
                        formControlProps={{
                          fullWidth: true,
                          
                        }}
                      />

                      <br/>

                       <CustomInput
                      labelText="Repeat password"
                    
                      bottomUnderline
        inputProps={{
         
          defaultValue:confirmPass,
          placeholder:"Enter password again",
         onChange:(e)=>setConfirmPassword(e.target.value),
         type:!showConfirmPass?"password":"text",
        endAdornment: !showConfirmPass?<VisibilityOffIcon onClick={()=>setShowConfirmPass(true)}/>:<VisibilityIcon onClick={()=>setShowConfirmPass(false)}/>
          
        }}
                        formControlProps={{
                          fullWidth: true,
                          
                        }}
                      />
<div className={classes.validator}>


<div className={classNames(classes.validatorItem,sLength?classes.colorDark:classes.colorLight)}>
Must at least 8 characters &nbsp;&nbsp; <CheckCircleOutlineOutlinedIcon/>
</div>

<div className={classNames(classes.validatorItem,cSym?classes.colorDark:classes.colorLight)}>
Contain symbol or number &nbsp;&nbsp; <CheckCircleOutlineOutlinedIcon/>
</div>


</div>


        </div>
      </Content>
      <Footer actionButton>
        <Button
          // onClick={()=>props.history.push(`/onboarding/account-name`)}
          onClick={next}
          variant="contained"
          fullWidth
          
          size="lg"
          bold
          startIcon={<span style={{ marginLeft: 10 }}></span>}
          sideIcons
          endIcon={<ArrowRight />}
        >
          Submit
        </Button>
      </Footer>
    </Container>
  );
}
