const initialState = {
    parent:{},
    children:[],
    ancestors:[],

  
      
     };
     
     export default (state = initialState, action) => {
       switch (action.type) {
         case "UPDATE_LIBRARY":
           return {
             ...state,
             ...action.payload,
           };
        case "DELETE_ITEM":
          let index=state.children.findIndex(item => item._id==action.payload._id)
          let children=[...state.children]
          children.splice(index,1)
          return{
            ...state,
            children
          }
     
      
     
         default:
           return state;
       }
     };
     