import React from "react";
// nodejs library to set properties for components
import PropTypes from "prop-types";
// nodejs library that concatenates classes
import classNames from "classnames";
// @material-ui/core components
import { makeStyles } from "@material-ui/core/styles";
import FormControl from "@material-ui/core/FormControl";
import InputLabel from "@material-ui/core/InputLabel";
import Input from "@material-ui/core/Input";
import PhoneInput from 'react-phone-input-2'

import styles from "assets/jss/material-kit-react/components/customInputStyle.js";
import 'react-phone-input-2/lib/style.css'
const useStyles = makeStyles(styles);

export default function CustomInput(props) {
  const classes = useStyles();
  const {
    formControlProps,
    labelText,
    id,
    labelProps,
    inputProps,
    error,
    white,
lgCentered,
    success,
    boxed,
    mobile,
    multiline,
    rows,
    bottomUnderline,
    helperText

  } = props;


  const underlineClasses = classNames({
    [classes.underline]: true,
[classes.whitebaseUnderLine]:white,
[classes.borderedWhite]:lgCentered,
    [classes.BottomUL]: bottomUnderline
 
  });

 
  const root = classNames({
    [classes.root]:true,
    [classes.whitebase]:white,
    [classes.rootBoxed]:boxed,
    [classes.rootUnderlined]:bottomUnderline,
    [classes.inputError]:error
  });
  const inputClasses = classNames({
    [classes.lgCentered]:lgCentered,
    [classes.input]: (lgCentered||boxed)?false:true,
    [classes.boxed]:boxed,
    [classes.underlineInput]:bottomUnderline,

    
   
    
  });
 
const labelRoot=classNames({
  [classes.labelRoot]: true,
  [classes.labelUnderline]:bottomUnderline,
  [classes.labelError]:error
})





  var formControlClasses;
  if (formControlProps !== undefined) {
    formControlClasses = classNames(
      formControlProps.className,
      classes.formControl
    );
  } else {
    formControlClasses = classes.formControl;
  }
  return (
    <FormControl {...formControlProps} className={formControlClasses}   >
    {labelText !== undefined ? (
        <div
          className={labelRoot }
          htmlFor={id}
          {...labelProps}
        >
          {labelText}
        </div>
      ) : null}
      {!mobile?<Input
        classes={{
          input: inputClasses,
          root: root,
        
          disabled: classes.disabled,
          underline: underlineClasses
        }}
        id={id}
        {...inputProps}
        multiline={multiline}
        rows={rows}
      />:
      <PhoneInput
      {...props}
   containerClass={classes.mobile}
   buttonClass={classes.mobileButton}
   inputClass={classes.mobileInput}
   country={"us"}
   buttonStyle={{backgroundColor:"white",padding:10,borderRadius:"12px 0px 0px 12px",border:"none"}}
      inputStyle={{border:"none",marginLeft:10,width:"100%"}}
      inputProps={inputProps}

/>}
{helperText&&<span className={classes.helperError}>Hello this is helper</span>}
    </FormControl>
  );
}

CustomInput.propTypes = {
  labelText: PropTypes.node,
  labelProps: PropTypes.object,
  id: PropTypes.string,
  inputProps: PropTypes.object,
  formControlProps: PropTypes.object,
  inputRootCustomClasses: PropTypes.string,
  error: PropTypes.bool,
  success: PropTypes.bool,
  white: PropTypes.bool
};
