import React, { Component } from 'react'
import { Router, Route, Switch } from "react-router-dom";
import ProfilePage from "../Screens/createProfile/profileMain"
import PrivatePlan from "../Screens/createProfile/PrivatePlan"
import PrivateInfo from "../Screens/createProfile/PrivateInfo"
import ProfilePreview from "../Screens/createProfile/Profilepage"
import ProfileComplete from "../Screens/createProfile/ProfileComplete"
import ProfileClient from "../Screens/createProfile/profileClient"
import {connect} from "react-redux"
import {updateOnboarding} from "../store/actions/Onboarding"
import {updateFeedback} from "../store/actions/feedback"
import {updateProfile,updateInfo} from "../store/actions/Profile"
import Category from "../Screens/createProfile/Category"
import Location from "../Screens/createProfile/location"
import Bio from "../Screens/createProfile/bio.js"
import AccountWelcome from "../Screens/createProfile/Welcome"
import AccountPic from "../Screens/createProfile/ProfilePic"
import DOB from "../Screens/createProfile/dob"
import Name from "../Screens/createProfile/name"
import EditEmail from "../Screens/createProfile/updateEmail"
import Verification from "../Screens/createProfile/verification"
import Gender from "../Screens/createProfile/gender"
import ProfileEdit from "../Screens/createProfile/clientProfileEdit"
import HealthInfo1 from "../Screens/onboarding/HealthInfo1"
import HealthInfo2 from "../Screens/onboarding/HealthInfo2"
import BodyImages from "../Screens/createProfile/bodyImages"
import HealthInfo from "../Screens/createProfile/HealthInfo"
import { fetchUser } from "store/actions/common";
class Onboarding extends Component {

componentWillUnmount(){
    //this.props.updateProfile({...this.props.Profile})
}
    render() {
        return (
            <div>
            
                   <Route exact  path={`${this.props.match.path}/`} render={()=>this.props.Profile.type=="Instructor"?<ProfilePage {...this.props}/> :<ProfileClient {...this.props}/>  } />
                   <Route exact  path={`${this.props.match.path}/edit`} render={()=>this.props.Profile.type=="Instructor"?<ProfilePreview {...this.props}/>:<ProfileEdit {...this.props}/>} />
                   <Route exact  path={`${this.props.match.path}/healthInfo`} render={()=><HealthInfo {...this.props}/>} />
                   <Route exact  path={`${this.props.match.path}/private-plan`} render={()=><PrivatePlan {...this.props}/>} />
                   <Route exact  path={`${this.props.match.path}/private-info`} render={()=><PrivateInfo {...this.props}/>} />
                   <Route exact  path={`${this.props.match.path}/profile-preview`} render={()=>this.props.Profile.type=="Instructor"?<ProfilePage {...this.props}/> :<ProfileClient {...this.props}/>  }/>
                   <Route exact  path={`${this.props.match.path}/profile-complete`} render={()=><ProfileComplete {...this.props}/>} />
                   <Route exact path={`${this.props.match.path}/welcome`} render={()=><AccountWelcome {...this.props}/>}/>
                <Route exact path={`${this.props.match.path}/photo`} render={()=><AccountPic {...this.props}/>}/>
                <Route exact path={`${this.props.match.path}/bio`} render={()=><Bio {...this.props} />}/>
                <Route exact path={`${this.props.match.path}/category`} render={()=><Category {...this.props}/>}/>
                <Route exact path={`${this.props.match.path}/category/:edit`} render={(props)=><Category {...this.props} editmode={props.match.params.edit}/>}/>
                <Route exact path={`${this.props.match.path}/account-profile`} render={()=><ProfilePreview {...this.props}/>}/>
                <Route exact path={`${this.props.match.path}/location`} render={()=><Location {...this.props}/>}/>
                <Route exact path={`${this.props.match.path}/location/:edit`} render={(props)=><Location {...this.props} editmode={props.match.params.edit}/>}/>
                <Route exact path={`${this.props.match.path}/edit-name`} render={()=><Name {...this.props}/>}/>
                <Route exact path={`${this.props.match.path}/edit-dob`} render={()=><DOB {...this.props}/>}/>
                <Route exact path={`${this.props.match.path}/update-gender`} render={()=><Gender {...this.props}/>}/>
                <Route exact path={`${this.props.match.path}/body-images`} render={()=><BodyImages {...this.props}  updateOnboarding={this.props.updateProfile} Onboarding={this.props.Profile} type="profile"/>}/>
                <Route exact path={`${this.props.match.path}/health-info1`} render={()=><HealthInfo {...this.props} updateOnboarding={this.props.updateProfile} Onboarding={this.props.Profile}/>}/>
                <Route exact path={`${this.props.match.path}/health-info2`} render={()=><HealthInfo2 {...this.props} updateOnboarding={this.props.updateProfile} Onboarding={this.props.Profile} type="profile"/>}/>
                <Route exact path={`${this.props.match.path}/edit-phone-email/:type`} render={(props)=><EditEmail {...this.props} type={props.match.params.type}/>}/>
                <Route exact path={`${this.props.match.path}/verification/:type/:data`} render={(props)=><Verification {...this.props} type={props.match.params.type} data={props.match.params.data}/>}/>
            </div>
        )
    }
}
const mapStateToProps =(state) => {
    return {
        Onboarding:state.Onboarding,
        Profile:state.Profile
    }
}

export default connect(mapStateToProps,{updateOnboarding,updateProfile,updateFeedback,updateInfo,fetchUser})(Onboarding)