import React, { Component } from "react";
import { Router, Route, Switch } from "react-router-dom";
import Settings from "../Screens/accountSettings/Screen11.js";
import PasswordReset from "../Screens/accountSettings/Screen12.js";
import ResetMethod from "../Screens/accountSettings/Screen13.js";
import Codemobile from "../Screens/accountSettings/Screen14.js";
import EditDetail from "../Screens/accountSettings/EditDetail";
import ResetPass from "../Screens/accountSettings/Screen15.js";
import {connect} from "react-redux"
 class Onboarding extends Component {
  render() {
    return (
      <div>
        <Route
          exact
          path={`${this.props.match.path}/`}
          render={() => <Settings {...this.props} />}
        />
        <Route
          exact
          path={`${this.props.match.path}/password-reset`}
          render={() => <PasswordReset {...this.props}
         
          />}
        />
        <Route
          exact
          path={`${this.props.match.path}/reset-method`}
          render={() => <ResetMethod {...this.props} />}
        />
        <Route
          exact
          path={`${this.props.match.path}/verify-account`}
          component={() => <Codemobile {...this.props} />}
        />
        <Route
          exact
          path={`${this.props.match.path}/edit-detail-username`}
          component={() => <EditDetail {...this.props} 
          type={"Username"} 
          value={"m.galeziowski"} 
          message={"New username?"} 
          onDone={()=>console.log("done")}
          onEdit={()=>console.log("new")}
          />}
        />
        
       
        <Route
          exact
          path={`${this.props.match.path}/edit-detail-email`}
          component={() => <EditDetail {...this.props} 
          type={"Email"} 
          value={"m.galeziowski@gmail.com"} 
          message={"New email address?"} 
          onDone={()=>console.log("done")}
          onEdit={()=>console.log("new")}
          />}
        />
        <Route
          exact
          path={`${this.props.match.path}/edit-detail-number`}
          component={() => <EditDetail {...this.props} 
          type={"Mobile number"} 
          value={"+1 732 252 177"} 
          message={"New phone number?"} 
          onDone={()=>console.log("done")}
          onEdit={()=>console.log("new")}
          />}
        />
        <Route
          exact
          path={`${this.props.match.path}/edit-detail-country`}
          component={() => <EditDetail {...this.props} 
          type={"Country"} 
          value={"Poland"} 
          message={"Change your country?"} 
          onDone={()=>console.log("done")}
          onEdit={()=>console.log("new")}
          />}
        />
        <Route
          exact
          path={`${this.props.match.path}/reset-pass`}
          component={() => <ResetPass {...this.props} />}
        />
      </div>
    );
  }
}

const mapStateToProps =(state) => {
  return {
      Onboarding:state.Onboarding,
      Profile:state.Profile
  }
}

export default connect(mapStateToProps,{})(Onboarding)