import Footer from "../../components/Layout/Footer";

import { makeStyles } from "@material-ui/core/styles";
import Primary from "../../components/Typography/Primary";
import ArrowRight from "assets/svg/ArrowRight";
import InsAthlete from "components/Card/InsAthlete";
import DietIcon from "assets/svg/DietIcon";
import Instructor from "assets/svg/Coach"
import Athlete from "assets/svg/WeightLifting"
import List from '@material-ui/core/List';
import ListItem from '@material-ui/core/ListItem';
import ListItemText from '@material-ui/core/ListItemText';
import ListItemAvatar from '@material-ui/core/ListItemAvatar';
import Earth from "assets/svg/Earth"
import Money from "assets/svg/Money"
import CustomTabs from "components/CustomTabs/CustomTabs.js";
import CustomInput from "components/CustomInput/CustomInput.js";
import PhoneInput from 'react-phone-input-2'
import 'react-phone-input-2/lib/style.css'
const useStyles = makeStyles((theme) => ({
  root: {
    padding: "0px 30px 0px 30px",
  },
  title: {
    fontFamily: "Proxima Nova",
    fontWeight: "bold",
   fontSize:22,
    marginBottom: 5,
    marginTop:2,

    paddingLeft: 25,
  },
  mainDiv: {
    display: "flex",
    flex: 1,
    padding: 25,
    paddingTop:10,
    flexDirection: "column",

    fontFamily: "Proxima Nova",
  },
  child1: {
    display: "flex",
    paddingBottom: "10px",
    flex: 1,
    width: "100%",
    flexDirection: "column",
    alignItems: "center",
  },
  child2: {
    flex: 2,
    paddingTop: "10px",
    display: "flex",
    flexDirection: "column",
    alignItems: "center",
    width: "100%",
    justifyContent: "space-around"
  },

  Footer: {
    margin: "0px 20px 20px 20px",
  },
  list:{
    width: '100%',
  },
  primary:{
    fontWeight: "bold",
    fontSize: 18,
    lineHeight: "18px",

  },
  secondary:{
      fontFamily: "Proxima Nova",
      marginTop:12,
      color: "#172A44",
    fontWeight:"normal",
    fontSize: 16,
    lineHeight: "22px",
    /* or 129% */
    paddingLeft: 25,
    paddingRight:25

  },
  icon:{
      fontSize:45,
      marginRight:25
  }
}));

export default function Screen2(props) {
  const classes = useStyles();
  const [bio,updateBio]=useState("")
const changeBio=(e)=>{
  updateBio(e.target.value)
}

const handleNext=()=>{
  props.updateProfile({bio:bio}).then(result =>{
    props.history.replace("/profile/category")
  })

}
  return (
    <Container>
     <Header button={<Button onClick={()=>props.history.replace("/profile/category")}>Skip</Button>} />

      <Content flex>
        <span className={classes.title}>About you</span>
        <p className={classes.secondary}>What do you want your clients and 
potential clients know about you ?</p>
        <div className={classes.mainDiv}>
         
        <CustomInput
                      
                      multiline
                      rows={4}
                      id="float"

        inputProps={{
          defaultValue:props.Profile.bio,
        
            onChange:changeBio,
           placeholder:"your bio here"
        }}
                        formControlProps={{
                          fullWidth: true,
                          
                        }}
                      />
        </div>
      </Content>
      <Footer actionButton>
        <Button
         onClick={handleNext}
          variant="contained"
          fullWidth
          size="lg"
          bold
          startIcon={<span style={{ marginLeft: 10 }}></span>}
          sideIcons
          endIcon={<ArrowRight />}
        >
          Next
        </Button>
      </Footer>
    </Container>
  );
}
