import React from "react";
// nodejs library to set properties for components
import PropTypes from "prop-types";
// nodejs library that concatenates classes
import classNames from "classnames";
import DietIcon from "assets/svg/DietIcon"
// @material-ui/core components
import makeStyles from "@material-ui/core/styles/makeStyles";
import Avatar from "@material-ui/core/Avatar"

const makeComponentStyles = makeStyles(() => ({
  mainDiv: {
    position: "relative",
    width: "100%",

borderRadius:"16px",
fontFamily:"Proxima Nova",
background:"#fff",
border: "1px solid #F3F3F3",
boxShadow: "0px 14px 24px rgba(200, 200, 200, 0.2)"

  },

  white:{
    background:"#fff",
    boxShadow: "15px 15px 35px rgba(112, 124, 151, 0.05), 10px 10px 25px rgba(112, 124, 151, 0.05)",
    border: "1px solid rgba(112, 124, 151, 0.1)",
boxSizing: "border-box",
  }
,
  content:{
      width: "100%",
      display:"flex",
      flexDirection: "column",
      justifyContent:"space-between",
  
    height:"100%",

     
  },


  childDiv:{
   
    top: 0,
    left: 0,
    bottom: 0,
    width: "100%",
    height: "100%",
    display:"flex",
    alignItems:"center",
    flexDirection:"column",

     borderRadius:"16px"
    
    
  },

 icon:{
fontSize: 60
 },
  title:{ 
     display:"flex",
    color: "#172A44",
    alignItems:"center",
      
      fontWeight:"bolder",
      fontSize: "14px",
lineHeight: "20px",

    },

    subTitle:{
        color: "#172A44",
        fontWeight:500,
      padding:10,
        fontSize: "16px",
  lineHeight: "20px",
    fontWeight:"bold"
    },

  image:{
  
   width:"93%",
 marginTop: "10px",
    paddingTop: "56.3%",
     background:"grey",
     borderRadius:"16px",
     
    
  },

data:{
    

    /* or 161% */
    
    
    color: "#F73B3B",
      fontWeight:"bold",
        fontSize: "18px",
  lineHeight: "28px",
}
,
sub:{
    
    fontWeight:"bold",
      fontSize: "14px",
lineHeight: "28px",
textDecorationLine: "line-through",
marginLeft:10,
color: "#CECECE",
}
,


}));

const AnnouncCard = React.forwardRef((props, ref) => {

const {selected, 
Title, 
Text, 
Icon,
Time,
white,
Images

}=props
  const classes = makeComponentStyles();
  const mainDiv=classNames({
    [classes.mainDiv]: true,

})
  
    const icon=classNames({
[classes.icon]: true,
[classes.selected]: selected
    })

    const title=classNames({
        [classes.title]: true,
        [classes.selected]: selected
    })

    const subtitle=classNames({
        [classes.subTitle]: true,
 
    })
  
  return (
  
     <div className={mainDiv} onClick={props.onClick}>
         <div className={classes.childDiv}>
         <div className={classes.image} style={{backgroundImage:`url(${props.BannerImage?props.BannerImage:"https://img.freepik.com/free-photo/athletes-floor-dumbbell-lift-with-one-hand_94347-858.jpg?size=626&ext=jpg"})`,backgroundSize: "cover"}} >

</div>
         <div className={classes.content}>

{/* <div  className={title}><Avatar style={{height:30,width:30}}></Avatar>&nbsp;&nbsp;&nbsp;S. Goswamy</div> */}
<div className={classes.subTitle}>{props.Title}</div>

<div style={{paddingLeft:10}} >
<div className={classes.data}>${(props.Price-props.Discount).toFixed(2)}</div>

<sub className={classes.sub}>${props.Price}</sub>
</div>

</div>
          
</div>
         </div>

   


 
  );
});


export default AnnouncCard;
