import React from "react";
// @material-ui/core components
import { makeStyles } from "@material-ui/core/styles";

// core components
import GridContainer from "components/Grid/GridContainer.js";
import GridItem from "components/Grid/GridItem.js";
import classNames from "classnames";
import Button from "@material-ui/core/Button";
import Toolbar from "@material-ui/core/Toolbar"
import AppBar from "@material-ui/core/AppBar"
import IconButton from "@material-ui/core/IconButton"

import ArrowRight from "assets/svg/ArrowRight"

import Typography from "@material-ui/core/Typography"

const useStyles = makeStyles((theme) => ({
  container: {

    padding: "15px 0px 15px 0px",
    display: 'flex',
    flexDirection: "row",
    // justifyContent: 'space-between',
    alignItems: 'center',
   
  
  },

  containerCol:{
    flexDirection: "column",
    // justifyContent: 'space-between',
    alignItems: 'flex-start',
  },

  bordered:{
    borderTop: "0.5px solid #DDDDDD"
  },
  borderedBoth:{
    borderTop: "0.5px solid #DDDDDD",
    borderBottom: "0.5px solid #DDDDDD"
  },

  child:{
    display: 'flex',
    flexDirection: "row",
    alignItems: 'center',
    
  },
  title:{
fontSize:16,
fontWeight:"bold",
fontFamily: "Proxima Nova",
lineHeight: "24px",
color: "#172A44",
  },
  value:{
    fontSize: "12px",
    lineHeight: "16px" ,
    color: "#007EA0"
  },
  Icon:{
fontSize:22,
color: "#172A44"
  },
  value:{
     fontFamily: "Proxima Nova" ,
     marginRight:20,
     color: "#007EA0"
  }

}));
export default function SectionNavbars(props) {
  const classes = useStyles();
  const container = classNames({
  [classes.container]:true,
  [classes.containerCol]:props.component,
  [classes.bordered]: props.bordered,
  [classes.borderedBoth]: props.borderedBoth
  });
  return (
    <div className={container} onClick={props.onClick}>
        <div className={classes.child} style={{flex:1}}>
            <span className={classes.title}>{props.title}</span>
        </div>
      { !props.component&& <div className={classes.child} style={{flex:2}}>
<div className={classes.value}>{props.value}</div>
{!props.noIcon&&<ArrowRight className={classes.Icon} />}
        </div>}

        {props.component}


    </div>
  );
}
