import React, { Component, useState } from "react";
import Container from "../../components/Layout/Container";
import Header from "../../components/Layout/Header";
import Content from "../../components/Layout/Content";
import Button from "../../components/CustomButtons/Button";
import Footer from "../../components/Layout/Footer";
import IconButton from "@material-ui/core/IconButton";
import { makeStyles } from "@material-ui/core/styles";
import Primary from "../../components/Typography/Primary";
import ArrowRight from "assets/svg/ArrowRight";
import InsAthlete from "components/Card/InsAthlete";
import DietIcon from "assets/svg/DietIcon";
import Instructor from "assets/svg/Coach";
import Athlete from "assets/svg/WeightLifting";
import Camera from "assets/svg/Camera";
import AddVideo from "assets/svg/CamVid";
import Grid from "@material-ui/core/Grid";
import WeekCard from "components/Card/workout3";
import CustomTabs from "components/CustomTabs/WeekTabs.js";
import UploadCard from "components/Card/UploadCard";
import AddIcon from "@material-ui/icons/Add";
import Drawer from "@material-ui/core/Drawer";
import InputBase from "@material-ui/core/InputBase";
import Toggle from "assets/svg/Toggle";
import Toggleh from "assets/svg/Toogleh";
import Divider from "@material-ui/core/Divider";
import EditDayExercise from "components/CreateProgram/ListDetails";
import EditWeeks from "components/CreateProgram/RepeatWeek";
import { handleuploadImage } from "utils/uploader/";
import VideoThumbnail from "react-video-thumbnail";
import WorkoutContainer from "components/Card/workout4";
import { theme } from "assets/css/theme";
import AddExerciseDrawer from "components/AddDays/AddExercise";
import ScrollList from "components/CustomTabs/Scrolllist";
import { defaultProps } from "recompose";
import DeleteModal from "components/Dialogue/delete";
import SelectUploadType from "Screens/createProgram/SelectUploadType"
const useStyles = makeStyles((thme) => ({
  root: {
    padding: "0px 30px 0px 30px",
  },
  title: {
    fontFamily: "Proxima Nova",
    fontWeight: "bold",
    fontSize: 24,
    marginBottom: 5,
    marginTop: 10,
color: "#172A44",
    paddingLeft: theme.padding,
  },
  mainDiv: {
    display: "flex",
    flexDirection: "column",
    height: "100%",
    padding: 20,
    paddingLeft: theme.padding,
    paddingRight: theme.padding,
    paddingTop: 0,
    fontFamily: "Proxima Nova",
  },

  Footer: {
    margin: "0px 20px 20px 20px",
  },
  label: {
    fontFamily: "Proxima Nova",
    fontSize: "16px",
    padding: 5,
    fontWeight: "bold",
    color: "#172A44",
  },
  text: {
    fontFamily: "Proxima Nova",
    fontSize: "14px",
    padding: 5,
    marginBottom: 10,
    color: "#172A44",
  },

  drawer: {
    borderRadius: "26px 26px 0px 0px",
 
    
  },
  drawerInside: {
    padding: "30px 15px 20px 15px",
    position: "relative",
    height: "100%",
  },
  headDrawer: {
    display: "flex",
    flexDirection: "row",
    width: "100%",
    alignItems: "center",
justifyContent: "space-between",
    fontFamily: "Proxima Nova",
    fontSize: "18px",
    lineHeight: "29px",
    color: "#172A44",
    marginBottom: 15,
   

  },

  icon: {
    fontSize: "16px",
  },
  input: {
    padding: "0px 0px 0px 0px",
    fontSize: "18px",
    width: "80%",
  },
  drawerContent: {
    marginTop: 10,
    width: "100%",
    maxHeight: "45vh",
    overflowY: "scroll",
  },
  HeaderDrawer: {
    display: "inline-flex",
    flexDirection: "row",
justifyContent: "flex-start",
    alignItems: "center",
    fontSize: 18,
  },
}));

export default function Screen2(props) {
  const classes = useStyles();
  const [value, setValue] = React.useState(0);
  const [drawer, toggleDrawer] = React.useState(false);
  const [drawerVal, setDrawerVal] = React.useState(null);
  const [currentWeek, setCurrentWeek] = React.useState(0);
  const [currentDay, setCurrentDay] = React.useState(0);
  const [weeks, setWeekQ] = useState([]);
  const [deleteModal, setDeleteModal] = useState(false);
  const [deleteId, setDeleteId] = useState(null);
  const [view, setView] = useState("h");
  const onChange = (checked, index) => {
    let data = [...weeks];
    if (checked) {
      data.push(index);
      setWeekQ(data);
    } else {
      data.splice(
        data.findIndex((item) => item == index),
        1
      );
      setWeekQ(data);
    }
    console.log(weeks);
  };

  const handleChange = (value) => {
    console.log(value);
    props.setState({ currentWeek: value });
  };

  const setWeek = (week) => {
    console.log(week);
    props.setState({ currentWeek: week, });
  };

  const addExercise = (week, day) => {
    props.setState({ currentDay: day, drawerState:true});
  
   
    setDrawerVal("add");
  };

  const settings = (week, day) => {
    props.setState({ currentDay: day });
    setCurrentWeek(week);
    setCurrentDay(day);
    toggleDrawer(true);
    setDrawerVal("setting");
  };

  const repeatDay = () => {
    setDrawerVal("repeat");
    setWeekQ([]);
  };

  const onRepeatDay = () => {
    let plan = props.ProgramDetails.ExercisePlan;

    weeks.map((item) => {
      plan[item][props.currentDay] =
        {...props.ProgramDetails.ExercisePlan[props.currentWeek][props.currentDay]};
    });

    props.updateProgram({ ExercisePlan: plan });
    setDrawerVal(null);
  };

  const addWeek = () => {
    let plan = props.ProgramDetails.ExercisePlan;
    plan.push([
      { Title: "", IsRest: false, Exercise: [] },
      { Title: "", IsRest: false, Exercise: [] },
      { Title: "", IsRest: false, Exercise: [] },
      { Title: "", IsRest: false, Exercise: [] },
      { Title: "", IsRest: false, Exercise: [] },
      { Title: "", IsRest: false, Exercise: [] },
      { Title: "", IsRest: false, Exercise: [] },
    ]);
    props.updateProgram({ ExercisePlan: plan });
  };

  const deleteWeek = (val) => {
    if (props.ProgramDetails.ExercisePlan.length > 1) {
      let plan = [...props.ProgramDetails.ExercisePlan];
      plan.splice(val, 1);

      if (props.ProgramDetails.ExercisePlan.length == val + 1) {
        props.setState({ currentWeek: val - 1 });
      }
      if (props.ProgramDetails.ExercisePlan.length == props.currentWeek + 1) {
        props.setState({ currentWeek: props.currentWeek - 1 });
      }
      props.updateProgram({ ExercisePlan: plan });
    } else {
      props.updateFeedback({
        snackbar: true,
        message: "Require at least one week in exercise plan",
        severity: "info",
      });
    }
  };

  const addWorkout = (e) => {
    let file = e.target.files[0];
    let blobURL = URL.createObjectURL(file);
    props.setState({ file: blobURL });
  };

  const editDay = (data) => {
    let plan = props.ProgramDetails.ExercisePlan;
    plan[props.currentWeek][props.currentDay] = {
      ...plan[props.currentWeek][props.currentDay],
      ...data,
    };
    props.updateProgram({ ExercisePlan: plan });
  };

  const uploadCover = (e) => {
    props.updateFeedback({ loading: true });
    toggleDrawer(false);
    handleuploadImage(e).then(
      (res) => {
        props.updateFeedback({ loading: false });
        let plan = props.ProgramDetails.ExercisePlan;
        plan[props.currentWeek][props.currentDay] = {
          ...plan[props.currentWeek][props.currentDay],
          Cover: res.data.Location,
        };
        props.updateProgram({ ExercisePlan: plan });
      },
      (rej) => {
        props.updateFeedback({
          loading: false,
          snackbar: true,
          message: "Oops caught some error! Please try again",
          severity: "error",
        });
      }
    );
  };

  const deleteExercise = (id) => {
    let plan = props.ProgramDetails.ExercisePlan;
    plan[props.currentWeek][props.currentDay].Exercise.splice(id, 1);
    props.updateProgram({ ExercisePlan: plan });
  };

  const saveProgram=()=>{
    props.saveProgram().then((result)=>{
        props.history.push(`${props.match.url}`)
    })
}

  return (
    <Container>

<DeleteModal open={deleteModal}  delete={()=>{deleteWeek(deleteId);setDeleteModal(false)}} handleClose={()=>setDeleteModal(false) } />
      <Header />

      <Content flex>
        <h2 className={classes.title}>Workout Calender</h2>
        {/* <input type="file" id="add workout" onChange={addWorkout}/> */}
        <div className={classes.mainDiv}>
          <CustomTabs
            value={props.currentWeek}
            onChange={handleChange}
            weekTab
            plainTabs
            scrollButtons="off"
            selected={props.currentWeek}
            addWeek={addWeek}
            hadleClick={setWeek}
            deleteWeek={val=>{setDeleteModal(true);setDeleteId(val)}}
            variant="scrollable"
            tabs={props.ProgramDetails.ExercisePlan}
          />

          <div style={{ width: "100%", marginTop: 15 }}>
            <Grid container spacing={2}>
              {props.ProgramDetails.ExercisePlan[props.currentWeek].map(
                (item, index) => {
                  return (
                    <Grid item xs={6}>
                      <WeekCard
                      length={item.Exercise.length}
                        Image={item.Cover}
                        icon={item.Exercise.length ? false : true}
                        onClickMore={() => settings(value, index)}
                        onClickAdd={() => addExercise(value, index)}
                        Title={"Day " + (index + 1)}
                        Text={item.Title ? item.Title : ""}
                      />
                    </Grid>
                  );
                }
              )}
            </Grid>
          </div>
        </div>
      </Content>
      <Footer actionButton>
       
          {props.custom ? (
            <Button
              onClick={
                saveProgram
              }
              variant="contained"
              fullWidth
              size="lg"
              bold
            >
              Save
            </Button>
          ) : (
            <Button
              onClick={() =>
                props.history.push(`${props.match.url}/create-diet`)
              }
              variant="contained"
              fullWidth
              size="lg"
              bold
              startIcon={<span style={{ marginLeft: 10 }}></span>}
              sideIcons
              endIcon={<ArrowRight />}
            >
              Next
            </Button>
          )}
  
      </Footer>

      <Drawer
        anchor={"bottom"}
        open={props.drawerState }
        onClose={() => props.setState({drawerState:false})}
        className={classes.drawer}
        classes={{ paper: classes.drawer }}
      >
        <div className={classes.drawerInside}>
          <div className={classes.headDrawer}>
            <div className={classes.HeaderDrawer}>
            <div>  &nbsp;&nbsp;Day {currentDay + 1}:&nbsp;&nbsp;</div>
              <InputBase
                style={{ padding: "0px 0px 0px 0px", fontSize: 16,width:"70%",display: "flex",flexDirection:"row"}}
               classes={{ input: classes.input }}
                placeholder="Title"
                value={
                  props.ProgramDetails.ExercisePlan[props.currentWeek][
                    props.currentDay
                  ].Title
                }
                onChange={(e) => editDay({ Title: e.target.value })}
              />
            </div>
            <Button
            size="sm"
            
              onClick={() => props.setState({drawerState:false})}
            >
              Done
            </Button>
          </div>
        <center>  <Divider variant="middle" style={{width: "50%"}} /></center>
          <div className={classes.drawerContent}>
            <AddExerciseDrawer
              handleClickView={props.ViewExercise}
              {...props}
              deleteExercise={deleteExercise}
              view={"v"}
            />
          </div>
          <div style={{paddingTop:10}}>
            <Button   variant="outlined"
            size="lg"
        fullWidth
        onClick={() =>{setDrawerVal("upload"); props.setState({drawerState:false});toggleDrawer(true)}
        }
        fullWidth>Add Exercise</Button>
       
          </div>
     
          
          <center>  <Divider variant="middle" style={{width: "50%",marginTop:25,marginBottom:15}} /></center>
         
<center style={{fontSize:18,color:"rgba(23, 42, 68, 0.5)",fontFamily: "Proxima Nova"}}>
          {props.ProgramDetails.ExercisePlan[props.currentWeek][
                    props.currentDay
                  ].Exercise.length} Exercises
                  </center>
        </div>
      </Drawer>

      <Drawer
        anchor={"bottom"}
        open={drawer && drawerVal == "repeat"}
        onClose={() => toggleDrawer(false)}
        className={classes.drawer}
        classes={{ paper: classes.drawer }}
      >
        <div className={classes.drawerInside}>
          <div className={classes.headDrawer}>
            <b style={{ marginLeft: 20 }}>Repeat Workout</b>
            <Button
              style={{ position: "absolute", right: 30, top: 20 }}
              onClick={onRepeatDay}
            >
              <b>Done</b>
            </Button>
          </div>
          <div className={classes.drawerContent}>
            <EditWeeks {...props} onChange={onChange} weeks={weeks} />
          </div>
        </div>
      </Drawer>

      <Drawer
        anchor={"bottom"}
        open={drawer && drawerVal == "setting"}
        onClose={() => toggleDrawer(false)}
        className={classes.drawer}
        classes={{ paper: classes.drawer }}
      >
        <div className={classes.drawerInside}>
          <div className={classes.headDrawer}>
            &nbsp;&nbsp; Day {currentDay + 1}:&nbsp;&nbsp;
            <InputBase
              style={{ padding: "0px 0px 0px 0px" }}
              classes={{ input: classes.input }}
              placeholder="Title"
              value={
                props.ProgramDetails.ExercisePlan[props.currentWeek][
                  props.currentDay
                ].Title
              }
              onChange={(e) => editDay({ Title: e.target.value })}
            />
            <Button
              style={{ position: "absolute", right: 30, top: 20 }}
              onClick={() => toggleDrawer(false)}
            >
              Done
            </Button>
          </div>
          <div className={classes.drawerContent}>
            <EditDayExercise
              onRepeat={() => repeatDay()}
              onUploadCover={uploadCover}
              onEdit={() => {
                toggleDrawer(true);
                addExercise(props.currentWeek, props.currentWeek);
              }}
            />

            {drawerVal == "repeat" && <EditWeeks />}
          </div>
        </div>
      </Drawer>



      <Drawer
        anchor={"bottom"}
        open={drawer && drawerVal == "upload"}
        onClose={() => toggleDrawer(false)}
        className={classes.drawer}
        classes={{ paper: classes.drawer }}
      >
        <div className={classes.drawerInside}>
         <SelectUploadType {...props} toggleDrawer={toggleDrawer}/>
        </div>
      </Drawer>


    </Container>
  );
}
