import React from "react";
// nodejs library that concatenates classes
import classNames from "classnames";
// nodejs library to set properties for components
import PropTypes from "prop-types";
import Badge from "@material-ui/core/Badge";
// material-ui components
import { makeStyles } from "@material-ui/core/styles";
import BottomNavigation from '@material-ui/core/BottomNavigation';
import BottomNavigationAction from '@material-ui/core/BottomNavigationAction';
import ExercisePlan from 'assets/svg/ExcercisePlan'
import Message from "assets/svg/Message"
import Client from "assets/svg/Client"
import RestoreIcon from "@material-ui/icons/Restore";
import FavoriteIcon from "@material-ui/icons/Favorite";
import LocationOnIcon from "@material-ui/icons/LocationOn";


const useStyles = makeStyles({
  root: {
    borderRadius: "29px 29px 0px 0px",
    background: "white",
    boxShadow: "0px -15px 35px rgba(112, 124, 151, 0.05), 0px -10px 25px rgba(112, 124, 151, 0.05)",
paddingTop:5,
paddingBottom:10,

  },
  rootAction: {
    fontSize: 14,
    fontFamily: "Proxima Nova",
    color: "#D7D7D7",
    "& .MuiTouchRipple-root":{
      borderRadius:"25px",
      backgroundColor: 'white !important',
      opacity: 0,
    },
  
  },
  label:{
    fontWeight:"bold",
    fontFamily:"Proxima Nova",
    fontSize:14
  },
  selected: {
  
    "& svg": {
        color:"#007EA0"
      },
    color:"#007EA0",
  
  },
});

export default function BottomNav(props) {
  const classes = useStyles();
  const [value, setValue] = React.useState(0);
  return (
    <BottomNavigation
      value={props.value}
      onChange={(event, newValue) => {
        props.setValue(newValue);
      }}
      showLabels
      className={classes.root}
    >
      <BottomNavigationAction
        classes={{ root: classes.rootAction, 
            selected: classes.selected ,
          label: classes.label}}
        label="Programs"
        icon={<ExercisePlan style={{marginBottom:3}} />}
      />
      <BottomNavigationAction
        classes={{ root: classes.rootAction, 
            selected: classes.selected,
            label: classes.label }}
        label="Clients"
        icon={<Client style={{marginBottom:3}}/>}
      />
      <BottomNavigationAction
        classes={{ root: classes.rootAction,
             selected: classes.selected,
             label: classes.label }}
        label="Message"
        icon={
          <Badge
         
           anchorOrigin={{
             vertical: 'top',
             horizontal: 'right',

           }}
           color="primary"
           badgeContent={props.chatCount}
           >
        <Message style={{marginBottom:5}}/>
      
      </Badge>
      
      }
      />
    </BottomNavigation>
  );
}
