import React, { Component } from 'react'
import { Router, Route, Switch } from "react-router-dom";
import ProgramDetails from "../Screens/common/programDetails"
import SelectProgram from "../Screens/instructorTabs/SelectProgramToSell"
import Overview from "../Screens/instructorTabs/Overview"
import SetupProgram from "../Screens/instructorTabs/SetupProgram"
import SendProgram from "../Screens/instructorTabs/SendProgram"
import ClientMessage from "../Screens/instructorTabs/ClientMessage"
import {updateFeedback} from "../store/actions/feedback"
import {createProgram,getSpecificProgram,sendProgram} from "../store/actions/createProgram"
import EditAndSend from "./EditAndSend"
import EditContainer from "../Screens/instructorTabs/EditSend"
import {connect } from "react-redux"

import {getAllPrograms} from "../store/actions/createProgram"
 class Common extends Component {

    state={
        ProgramDetails:{
            SendTo:[],
            PaymentType:null,
            Price:null,
        },
length:1,
    }

    componentDidMount=()=>{
this.setState({length:this.props.history.length})
        if(this.props.match.params.id){
   

    this.props.getSpecificProgram(this.props.match.params.id).then(data =>{
      this.setState({ProgramDetails:{...data}})
     // store.dispatch({ type:"SET_BUFFER",payload:data})
    })


        }

if(this.props.match.params.figgsID){
    this.setState({ProgramDetails:{...this.state.ProgramDetails,SendTo:[this.props.match.params.figgsID]}})

   
}


       
    }


    updateProgram=(data)=>{
this.setState({ProgramDetails:{...this.state.ProgramDetails,...data}})
    }


    
    render() {
        return (
            <div>
             <Route exact   path={`${this.props.match.url}/`} render={(props)=><SelectProgram {...this.props}  /> } />
                   <Route exact  path={`${this.props.match.url}/selector/:type`} render={(props)=><SelectProgram {...this.props} type={props.match.params.type} /> } />
                   <Route exact  path={`${this.props.match.url}/send/:id`} render={(props)=><SendProgram {...this.props} ProgramDetails={this.state.ProgramDetails} updateProgram={this.updateProgram} id={props.match.params.id}/>} />
                   <Route exact  path={`${this.props.match.url}/setupProgram/:id`} render={(props)=><SetupProgram {...this.props} ProgramDetails={this.state.ProgramDetails} updateProgram={this.updateProgram} id={props.match.params.id}/>} />
                   <Route exact  path={`${this.props.match.url}/overview/`} render={(props)=><Overview {...this.props} ProgramDetails={this.state.ProgramDetails} updateProgram={this.updateProgram} id={props.match.params.id} userId={this.props.match.params.userId} returnIndex={this.state.length} />} />
                   <Route exact path={`${this.props.match.url}/message`} render={(props)=><ClientMessage {...this.props} updateProgram={this.updateProgram} ProgramDetails={this.state.ProgramDetails} id={this.state.ProgramDetails._id}/>}/>
                   <Route exact path={`${this.props.match.url}/selectionType`} render={(props)=><EditContainer {...this.props} updateProgram={this.updateProgram} ProgramDetails={this.state.ProgramDetails} id={this.state.ProgramDetails._id}/>}/>
                   <Route  path={`${this.props.match.url}/editAndSend/:id`} render={(props)=><EditAndSend {...props} sendProgram={this.props.sendProgram} updateProgram={this.updateProgram} ProgramDetails={this.state.ProgramDetails} id={props.match.params.id} returnIndex={this.state.length} figgsId={this.props.match.params.figgsID}/>}/>
            </div>
        )
    }
}

const mapStateToProps =(state) => {
    return {
        ProgramList:state.ProgramList,
        Profile:state.Profile
    }
}


export default connect(mapStateToProps,{getAllPrograms,getSpecificProgram,sendProgram,updateFeedback})(Common)