import React from "react";
// nodejs library to set properties for components
import PropTypes from "prop-types";
// nodejs library that concatenates classes
import classNames from "classnames";
import DietIcon from "assets/svg/DietIcon"
// @material-ui/core components
import makeStyles from "@material-ui/core/styles/makeStyles";
import Avatar from "@material-ui/core/Avatar"
import Strength from "assets/svg/Strength"
const makeComponentStyles = makeStyles(() => ({
  mainDiv: {
    position: "relative",
    width: "100%",
minHeight:"180px",
height: "100%",
borderRadius:"11px",
fontFamily:"Proxima Nova",
background:"#fff",
border: "2px solid #E4F0F4",
boxSizing: "border-box"

  },

  white:{
    background:"#fff",
    boxShadow: "15px 15px 35px rgba(112, 124, 151, 0.05), 10px 10px 25px rgba(112, 124, 151, 0.05)",
    border: "1px solid rgba(112, 124, 151, 0.1)",
boxSizing: "border-box",
  }
,
  content:{
      
      display:"flex",
      flexDirection: "column",
      justifyContent:"center",
      padding:20,
alignItems:"center"
     
  },


  childDiv:{
    position:  "absolute",
    top: 0,
    left: 0,
    bottom: 0,
    width: "100%",
    height: "100%",
    display:"flex",
    flexDirection:"row",
 
    borderRadius:"22px"
    
    
  },

 icon:{
fontSize: 60

 },
  title:{ 
     textAlign: "center",
    color: "#172A44",
      fontWeight:"bold",
    marginTop:10,
      fontSize: "16px",
lineHeight: "20px",

    },

    subTitle:{
        color: "#007EA0",
        fontWeight:"bold",
      textAlign:"center",
        fontSize: "13px",
  lineHeight: "20px",

    
    },

  image:{
   
     width: "45%",
     height: "100%",
     background:"grey",
     borderRadius:"22px"
    
  },

data:{
    color: "#172A44",
     
      
        fontSize: "14px",
  lineHeight: "20px",
}
,


}));

const AnnouncCard = React.forwardRef((props, ref) => {

const {selected, 
Title, 
Text, 
Icon,
Time,
white,
Images

}=props
  const classes = makeComponentStyles();
  const mainDiv=classNames({
    [classes.mainDiv]: true,

})
  
    const icon=classNames({
[classes.icon]: true,
[classes.selected]: selected
    })

    const title=classNames({
        [classes.title]: true,
        [classes.selected]: selected
    })

    const subtitle=classNames({
        [classes.subTitle]: true,
 
    })
  
  return (
  
     <div className={mainDiv} onClick={props.onClick}>
         <div className={classes.childDiv}>


         <div className={classes.content}>

         
      {props.icon?props.icon:  <  Strength className={classes.icon}/>}
    
<div className={classes.title}>{props.title?props.title:"Custom Plan"}</div>

<div className={classes.subTitle}>{props.text?props.text:"Request a customize plan"}</div>


          
</div>
         </div>

     </div>


 
  );
});


export default AnnouncCard;
