import React, { Component } from "react";
import AthleteSummary from "./ClientSummary"
import InstructorSummary from "./InstructorSummary"


export default function Screen2(props) {


  return (
   <>
   {props.Onboarding.type=="Athlete"?
   
   <AthleteSummary {...props}/>
   :
   
   <InstructorSummary {...props}/>
   }
   </>
  );
}
