import React from 'react';
import { makeStyles } from '@material-ui/core/styles';
import Button from '@material-ui/core/Button';
import Backdrop from '@material-ui/core/Backdrop';
import SpeedDial from '@material-ui/lab/SpeedDial';
import SpeedDialIcon from '@material-ui/lab/SpeedDialIcon';
import SpeedDialAction from '@material-ui/lab/SpeedDialAction';
import FileCopyIcon from '@material-ui/icons/FileCopyOutlined';
import SaveIcon from '@material-ui/icons/Save';
import PrintIcon from '@material-ui/icons/Print';
import ShareIcon from '@material-ui/icons/Share';
import FavoriteIcon from '@material-ui/icons/Favorite';
import FitnessCenterIcon from '@material-ui/icons/FitnessCenter';
import CreateNewFolderIcon from '@material-ui/icons/CreateNewFolder';
const useStyles = makeStyles((theme) => ({
 
  speedDial: {
    position: 'absolute',
    bottom: theme.spacing(2),
    right: theme.spacing(2),
  },
  fab:{
      background:"rgba(0,0,0,0.8)",
      fontColor:"white",
      color:"#fafafa"
  },
  staticTooltip:{
    background:"rgba(0,0,0,0.8)",
   color:"#fafafa"
  }
}));

const actions = [
  { icon: <FitnessCenterIcon />, name: 'Workout' },
  { icon: <CreateNewFolderIcon />, name: 'Folder' },

];

export default function SpeedDialTooltipOpen(props) {
  const classes = useStyles();
  const [open, setOpen] = React.useState(false);
  const [hidden, setHidden] = React.useState(false);

  const handleVisibility = () => {
    setHidden((prevHidden) => !prevHidden);
  };

  const handleOpen = () => {
    setOpen(true);
  };

  const handleClose = () => {
    setOpen(false);
  };

  return (
  
    
   <>
 
      <SpeedDial
        ariaLabel="SpeedDial tooltip example"
        className={classes.speedDial}
        hidden={hidden}
        icon={<SpeedDialIcon />}
        onClose={handleClose}
        onOpen={handleOpen}
        open={open}
      >
        
          <SpeedDialAction
          classes={{fab:classes.fab,staticTooltipLabel:classes.staticTooltip}}
            key={"Exercise"}
            icon={<FitnessCenterIcon />}
            tooltipTitle={"Exercise"}
            tooltipOpen
            onClick={()=>props.addWorkout()}
          />
            <SpeedDialAction
          classes={{fab:classes.fab,staticTooltipLabel:classes.staticTooltip}}
            key={"Folder"}
            icon={<CreateNewFolderIcon />}
            tooltipTitle={"Folder"}
            tooltipOpen
            onClick={()=>props.addFolder()}
          />
    
      </SpeedDial>
   </>
  );
}