export default function Screen2(props) {
  const classes = useStyles();
const [open,close]=useState(false)
  return (
    <Container>
      <Header />

      <Content flex={true}>
        <span className={classes.title}>Account settings</span>
      
        <div className={classes.mainDiv}>
        <ListItem 
        title="Email"
        value={props.Profile.email?props.Profile.email:"N/A"}
        onClick={()=>props.history.push(`/profile/edit-phone-email/email`)}
        />
        <ListItem 
        title="Phone"
        value={props.Profile.phone?props.Profile.phone:"N/A"}
        onClick={()=>props.history.push(`/profile/edit-phone-email/phone`)}
        bordered/>
         <ListItem 
      title="Gender"
      value={props.Profile.gender?props.Profile.gender:"N/A"}
      onClick={()=>props.history.push(`/profile/update-gender`)}
      bordered/>
         <ListItem 
       title="Birthday"
       value={props.Profile.DOB?moment(props.Profile.DOB).format('ll'):""}
       onClick={()=>props.history.push(`/profile/edit-dob`)}
       bordered/>

<ListItem 
        title="Password"
        value="******"
        onClick={()=>props.history.push(`/reset-password/profile`)}
      
       bordered/>
      
        </div>
      </Content>
      <Footer actionButton>
        <Button
        
          variant="contained"
          fullWidth
          size="lg"
          bold
          startIcon={<span style={{ marginLeft: 10 }}></span>}
          sideIcons
          endIcon={<ArrowRight />}
        >
          Next
        </Button>
      </Footer>
    </Container>
  );
}
