import React, { Component, useState, useEffect } from "react";
import Container from "../../components/Layout/Container";
import Header from "../../components/Layout/HeaderWithProfile";
import Content from "../../components/Layout/Content";
import {theme} from "assets/css/theme"
import { makeStyles } from "@material-ui/core/styles";
import List from "@material-ui/core/List";
import ListItem from "@material-ui/core/ListItem";
import ListItemText from "@material-ui/core/ListItemText";
import ListItemAvatar from "@material-ui/core/ListItemAvatar";
import Drawer from "@material-ui/core/Drawer";
import CreateProgramIcon from "assets/svg/CreateProgram";
import CreateProgramNewIcon from "assets/svg/CreateProgIcon"
import SellProgramIcon from "assets/svg/SellProgram"
import SendProgramIcon from "assets/svg/SendProgram"
import CustomInput from "components/CustomInput/CustomInput.js";
import Divider from "@material-ui/core/Divider";
import Editlist from "components/List/ProgramControlList"
import IconButton from "@material-ui/core/IconButton";
import InputAdornment from "@material-ui/core/InputAdornment";
import SearchIcon from "assets/svg/Search";
import ProgramCard from "components/Card/ProgramCard";
import CancelIcon from '@material-ui/icons/Cancel';
import DeleteModal from "components/Dialogue/delete";
import Fuse from "fuse.js"
import {store} from "../../store"
import AddProgram from "assets/svg/CreateProgramIcon"
import "react-phone-input-2/lib/style.css";
import Button from "components/CustomButtons/Button";
const useStyles = makeStyles((th) => ({
  root: {
    padding: "0px 30px 0px 30px",
  },
  title: {
    fontFamily: "Proxima Nova",
    fontWeight: "700",
    marginBlockStart: 0,
    marginBottom: 5,
    color:"#172A44",
    fontSize: 24,
    paddingTop: 15,
    paddingLeft: theme.padding,
  },

  mainDiv2: {
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
    flexDirection: "column",
   flexGrow: 1,

    padding: "0px 35px 80px 35px",
    textAlign: "center",
    fontSize: 18,
    fontFamily: "Proxima Nova",
  },

  mainDiv: {
    //  display: "flex",
    //  justifyContent: "center",
    //  alignItems:"center",
    //  flexDirection:"column",
    overflowY: "scroll",
    
    fontFamily: "Proxima Nova",
  },
  child1: {
    display: "flex",
    paddingBottom: "10px",
    flex: 1,
    width: "100%",
    flexDirection: "column",
    alignItems: "center",
  },
  child2: {
    flex: 2,
    paddingTop: "10px",
    display: "flex",
    flexDirection: "column",
    alignItems: "center",
    width: "100%",
    justifyContent: "space-around",
  },

  Footer: {
    margin: "0px 20px 20px 20px",
  },
  list: {
    width: "100%",
  },
  primary: {
    fontWeight: "bold",
    fontSize: 18,
    lineHeight: "18px",
  },
  secondary: {
    fontFamily: "Proxima Nova",

    color: "rgba(23, 42, 68, 0.5)",
    fontWeight: 500,
    fontSize: 16,
    lineHeight: "24px",
    paddingLeft: theme.padding,
    paddingRight: theme.padding,
    /* or 129% */
  },
  titleContainer: {
    width: "95%",
    display: "flex",
    flex: 1,
    flexDirection: "row",
    justifyContent: "space-between",
  },
  Button: {
    padding: 25,
    paddingTop: 10,
    paddingBottom: 0,
  },
  searchBar: {
    display: "flex",
    flexDirection: "row",
    paddingLeft:theme.padding,
    paddingRight:theme.padding,
    padding: "20px 20px 0px 20px",
  },
  IconButton: {
    marginLeft: 12,
    width: 53,
    height: 53,
    background: "#F9FCFD",
    border: "1px solid rgba(0, 126, 160, 0.5)",
    boxSizing: "border-box",
    borderRadius: "11px",
  },
  drawer: {
    borderRadius: "26px 26px 0px 0px",
    maxHeight:"80vh"
  },
  drawerInside: {
    padding: "20px 16px 20px 16px",
    position: "relative",
    height: "100%",
  },

  primaryList:{
    fontSize:18,
    color:"#172A44"
  }

}));

export default function Screen2(props) {
  const classes = useStyles();
  const [value, setValue] = React.useState("");
  const [drawer, toggleDrawer]=useState(false)
  const [drawer2, toggleDrawer2]=useState(false)
  const [deleteModal, setDeleteModal] = useState(false);
  const [selectId,setSelectedId]=useState(null)
  useEffect(() => {
    props.getAllPrograms();
  }, []);
  const options = {
    minMatchCharLength:3,
    keys: [
      "Title",
      "createdBy.name",
      "Description"
    ]
  }
  const fuse = new Fuse(props.ProgramList.Programs, options);



  let programList=value?fuse.search(value):props.ProgramList.Programs

  const onEdit=()=>{

    store.dispatch({ type:"EDIT_ID",payload:{editId:selectId}})
    props.history.push(`/edit-program/${selectId}`)
  }

  const deleteProgram=()=>{
    props.deleteProgram(selectId).then((res)=>{
props.history.push("/instructor")
    })


  }

  return (
    <>
             <DeleteModal open={deleteModal}  delete={()=>{deleteProgram();setDeleteModal(false)}} handleClose={()=>setDeleteModal(false) } />
      {props.ProgramList.Programs&&props.ProgramList.Programs.length == 0? (
        <Content flex >
          {/* <h2 className={classes.title}>Programs</h2> */}
         
 
          <div className={classes.searchBar}>
            <CustomInput
              id="material"
              inputProps={{
                style: { background: "#fafafa" },
                placeholder: "Search program ",
                startAdornment: (
                  <InputAdornment position="start">
                    <SearchIcon style={{color: "rgba(23,42,68,0.3)"}} />
                  </InputAdornment>
                ),
                endAdornment: (
                 <>{value? <InputAdornment position="end" onClick={e=>console.log("")}>
                  <CancelIcon />
                </InputAdornment>:null}</>
                 )
              }}
              formControlProps={{
                fullWidth: true,
              }}
            />
            <IconButton className={classes.IconButton} onClick={()=>toggleDrawer(true)}>
              <CreateProgramNewIcon style={{ fontSize: 45 }} />
            </IconButton>
          </div>

          <div className={classes.mainDiv2}>
            <div>
            You have no programs created.<br/>
create your first program.<br/>

<Button variant="outlined" style={{marginTop:20,padding:8,fontSize:16,paddingLeft:15,paddingRight:15}} onClick={()=>props.history.push("/create-program")} size="md" startIcon={<CreateProgramNewIcon style={{fontSize:40}}/>}>Create program</Button>
             
            </div>
          </div>
        </Content>
      ) : (
        <Content flex >
          {/* <h2 className={classes.title}>Programs</h2> */}
         
          <div className={classes.searchBar}>
            <CustomInput
              id="material"
              inputProps={{
                style: { background: "#fafafa" },
                placeholder: "Search program",
                value:value,
                onChange:(e)=>setValue(e.target.value),
                startAdornment: (
                  <InputAdornment position="start">
                    <SearchIcon style={{color: "rgba(23,42,68,0.3)"}}/>
                  </InputAdornment>
                ),
                endAdornment: (
                 <>{value?<InputAdornment position="end" onClick={e=>setValue("")}>
                  <CancelIcon />
                </InputAdornment>:""}</>
                 )
              }}
              formControlProps={{
                fullWidth: true,
              }}
            />
            <IconButton className={classes.IconButton} onClick={()=>toggleDrawer(true)}>
              <CreateProgramNewIcon style={{ fontSize: 45 }} />
            </IconButton>
          </div>

          {/* <div style={{ padding: 20, paddingBottom: 10 }}>
            <CustomInput
              id="material"
              inputProps={{
                style: { background: "#fafafa" },
                placeholder: "Search for the instructor",
                startAdornment: (
                  <InputAdornment position="start">
                    <SearchIcon />
                  </InputAdornment>
                ),
              }}
              formControlProps={{
                fullWidth: true,
              }}
            />
          </div> */}

          <div className={classes.mainDiv}>
            {programList.map((itemMap) => {

let item=value?itemMap.item:itemMap
              return (
                <div
                  onClick={() =>
                   {if(item.IsDraft){toggleDrawer2(true);setSelectedId(item._id)}else props.history.push("/common/programControl/" + item._id)}
                  }
                >
                  <ProgramCard noAvatar {...item} {...item.createdBy} />
                </div>
              );
            })}
          </div>
        </Content>
      )}

<Drawer
        anchor={"bottom"}
        open={drawer}
        onClose={() => toggleDrawer(false)}
        className={classes.drawer}
        classes={{ paper: classes.drawer }}
      >
 <div className={classes.drawerInside}>


 <List >
      <ListItem button onClick={()=>props.history.push("/create-program")}>
        <ListItemAvatar>
        <CreateProgramNewIcon style={{fontSize:45}}/>
        </ListItemAvatar>
        <ListItemText primary="Create program" classes={{primary:classes.primaryList}} />
      </ListItem>

<Divider style={{marginLeft:15,marginRight:15}}/>
<ListItem button onClick={()=>props.history.push("/sendProgram/selector/send")}>
        <ListItemAvatar>
        <SendProgramIcon style={{fontSize:45}}/>
        </ListItemAvatar>
        <ListItemText primary="Send program" classes={{primary:classes.primaryList}} />
      </ListItem>

      </List>



 </div>
          </Drawer>




          <Drawer
        anchor={"bottom"}
        open={drawer2}
        onClose={() => toggleDrawer2(false)}
        className={classes.drawer}
        classes={{ paper: classes.drawer }}
      >
 <div className={classes.drawerInside}>


<Editlist
onEdit={onEdit}
onDelete={()=>setDeleteModal(true)}
onView={()=>props.history.push(`/common/programViewInstructor/${props.id}`)}
/>
 </div>
          </Drawer>
    </>
  );
}
