import React ,{useState,useEffect} from "react";
// nodejs library to set properties for components
import PropTypes from "prop-types";
// nodejs library that concatenates classes
import classNames from "classnames";
import DietIcon from "assets/svg/DietIcon";
// @material-ui/core components
import makeStyles from "@material-ui/core/styles/makeStyles";
import Avatar from "@material-ui/core/Avatar";
import MoreHorizIcon from "@material-ui/icons/MoreHoriz";
import VideoThumbnail from 'react-video-thumbnail';
const makeComponentStyles = makeStyles(() => ({
  mainDiv: {
    width: "100%",
    position: "relative",
    borderRadius: "22px",
    fontFamily: "Proxima Nova",
    background: "#fff",
    paddingTop: "115%",
  },

  white: {
    background: "#fff",
    boxShadow:
      "15px 15px 35px rgba(112, 124, 151, 0.05), 10px 10px 25px rgba(112, 124, 151, 0.05)",
    border: "1px solid rgba(112, 124, 151, 0.1)",
    boxSizing: "border-box",
  },
  content: {
    width: "80%",
    display: "flex",
    flexDirection: "row",
    justifyContent: "space-between",
    marginTop: "20px",
    marginBottom: "20px",
  },

  childDiv: {
    position: "absolute",
    top: 0,
    left: 0,
    bottom: 0,
    width: "100%",
    height: "100%",
    display: "flex",
    alignItems: "center",
    flexDirection: "column",
    justifyContent: "center",

    borderRadius: "22px",
  },
  overlay:{
    background: "rgba(0, 126, 160, 0.75)",
  },

  icon: {
    width: "100%",
    display: "flex",
    flexDirection: "row",
    justifyContent: "flex-end",
    position: "absolute",
    top:0,
     borderRadius: "22px 22px 0px 0px",
zIndex:10,
    
    background: "linear-gradient(0deg, rgba(0, 0, 0, 0) 0%, #000000 100%)",
    opacity: 0.85,
    backdropFilter: "blur(1px)",
  },
  title: {
    color: "#fff",
    alignItems: "center",
    textTransform:"capitalize",
    fontWeight: "bold",
    fontSize: "20px",
    width:"90%",
    lineHeight: "29px",
  },

  subTitle: {
    fontWeight: "normal",
    fontSize: "16px",
    lineHeight: "20px",
    textTransform:"capitalize",
    color: "#fff",
  },

  image: {
    width: "93%",

    paddingTop: "56.3%",
    background: "grey",
    borderRadius: "16px",
    marginBottom: 10,
  },

  bottom: {
    width: "100%",
    position: "absolute",
    background: "linear-gradient(180deg, rgba(0, 0, 0, 0) 0%, #000000 100%)",
    opacity: 0.85,
    backdropFilter: "blur(4px)",
    bottom: "0",

    display: "flex",
    flexDirection: "column",
    justifyContent: "center",
    alignItems: "center",

    borderRadius: "0px 0px 22px 22px",
  },
  top: {
    width: "100%",
    position: "absolute",
    background: "linear-gradient(180deg, rgba(0, 0, 0, 0) 0%, #000000 100%)",
    opacity: 0.85,
    backdropFilter: "blur(4px)",
    top:0,

    display: "flex",
    flexDirection: "column",
    justifyContent: "center",
    alignItems: "center",

    borderRadius: "0px 0px 22px 22px",
  },
  sub: {
  textTransform:"capitalize",
    fontSize: "14px",
    lineHeight: "29px",
    paddingBottom: 10,
fontFamily: "Proxima Nova",
    color: "#fff",
  },
}));

const AnnouncCard = React.forwardRef((props, ref) => {
  const { selected, title1, title2, sub1,Icon ,overlay} = props;
  const classes = makeComponentStyles();
  const mainDiv = classNames({
    [classes.mainDiv]: true,
  });

  const childDiv = classNames({
    [classes.childDiv]: true,
    [classes.overlay]: overlay,
  });

  const title = classNames({
    [classes.title]: true,
    [classes.selected]: selected,
  });

  const subtitle = classNames({
    [classes.subTitle]: true,
  });

  const [thumb,setThumb] =useState("https://img.freepik.com/free-photo/athletes-floor-dumbbell-lift-with-one-hand_94347-858.jpg?size=626&ext=jpg")

// useEffect(()=>
// {if(props.banner)
//   setThumb(props.banner)}
// ,[props.banner])
  return (
    <>
   
    <div
      className={mainDiv}
      style={{
        backgroundImage: `url(${props.banner?props.banner:thumb})`,
        backgroundSize: "cover",
      }}
    >
            <div className={classes.icon}>{Icon}</div>
      <div className={childDiv} onClick={props.onClick}>
      
        <div className={classes.title}>{title1}</div>
        <div className={classes.top}>

        </div>
       {(title2||sub1) &&<div className={classes.bottom}>
          <span className={classes.subTitle}>{title2}</span>
          <span className={classes.sub}>{sub1}</span>
        </div>}
      </div>
    </div>
    </>
  );
});

export default AnnouncCard;
