import React, { Component } from "react";
import { Router, Route, Switch } from "react-router-dom";
import SharedProgram from "../Screens/Public/SharedProgram";

import { connect } from "react-redux";
import {updateProfile} from "../store/actions/Profile"
import { updateFeedback } from "../store/actions/feedback";
import {
  getClientPrograms,
  switchExercise,
  getOrder,
  updateStatus
} from "store/actions/clientExercise";
import { getSpecificPublicProgram,sharedProgramData } from "../store/actions/createProgram";
class PublicScreens extends Component {

  render() {
    return (
      <div>
        <Route
          exact
          path={`${this.props.match.path}/sharedProgram/:id`}
        
          render={(props) => (
            <SharedProgram
              {...this.props}
              id={props.match.params.id}
            />
          )}
        />
        
      </div>
    );
  }
}

const mapStateToProps = (state) => {
  return {
   Profile: state.Profile,
    token: state.Profile.token,
  };
};

export default connect(mapStateToProps, {

  getSpecificPublicProgram,
  sharedProgramData,
  updateProfile,
  updateFeedback,
  updateStatus,

})(PublicScreens);
