function NumberFormatCustom(props) {
  const { inputRef, onChange, ...other } = props;

  return (
    <NumberFormat
      {...other}
      getInputRef={inputRef}
      onValueChange={(values) => {
        onChange({
          target: {
            name: props.name,
            value: values.value,
          },
        });
      }}
      thousandSeparator
      isNumericString
      prefix="$ "
    />
  );
}


export default function Screen2(props) {
  const classes = useStyles();


  useEffect(() => {
 props.getSpecificProgram(props.id).then(data =>{
        props.updateProgram(data)
       // store.dispatch({ type:"SET_BUFFER",payload:data})
      })
  },[props.id])
  
  const next=()=>{
    let {PaymentType,Price,SendTo}=props.ProgramDetails
    if((PaymentType==null||PaymentType=="")||(Price==null||Price<=0)){
      props.updateFeedback({loading:false,snackbar:true,message:"Please seklect valid payment type and enter valid amount",severity:"warning"})
    }
    else if(SendTo.length==0){
        props.updateFeedback({loading:false,snackbar:true,message:"Please select type atleast on email or figss id to send",severity:"warning"})
      }
    else{

  
            props.sendProgram({_id:props.ProgramDetails._id,Title:props.ProgramDetails.Title,SendTo:props.ProgramDetails.SendTo,Price:0}).then((program) => {
            
              props.history.push("/instructor");
            });
          
          
    }
  }

  const removeChip=(chip,index)=>{
     let Chips=[...props.ProgramDetails.SendTo]
    Chips.splice(index,1)
    props.updateProgram({SendTo:Chips})

  }

  const onAdd=(chip)=>{

    let Chips=[...props.ProgramDetails.SendTo]

    Chips.push(chip.toLowerCase())
    props.updateProgram({SendTo:Chips})
  }


  const onSkip=()=>{
    props.updateProgram({Price:0,SendTo:[]})
    props.history.push(`${props.match.url}/greeting`)
  }

  return (
    <Container>
      <Header />

      <Content>
        <h2 className={classes.title}>Client details</h2>
      
        <div className={classes.mainDiv}>


        <Grid container style={{ marginTop: 15 }}>
                <Grid item xs={5}>
                  <div
                    className={classes.image}
                    style={{
                      backgroundImage: `url(${
                        props.ProgramDetails.BannerImage
                          ? props.ProgramDetails.BannerImage
                          : "https://img.freepik.com/free-photo/athletes-floor-dumbbell-lift-with-one-hand_94347-858.jpg?size=626&ext=jpg"
                      })`,
                      backgroundSize: "cover",
                    }}
                  ></div>
                </Grid>
                <Grid item xs={7}>
                  <div className={classes.prDetails}>
                    {props.ProgramDetails.Title}
                  </div>
                </Grid>
              </Grid>

       <Grid container spacing={2} justify="center" alignItems="center" style={{marginTop:25}}>

<Grid item xs={12}>
<div className={classes.label}>To</div>
       <ChipInput
    
       fullWidth
       value={props.ProgramDetails.SendTo}
       defaultValue={[...props.ProgramDetails.SendTo]}
       onAdd={onAdd}
       onDelete={removeChip}
       InputProps={{
        placeholder:"Email or figgs ID",
        style:{marginBottom:10}
      }}
      blurBehavior={"add"}
     
       
       
       
       />
         </Grid>







 </Grid>
        </div>
      </Content>
   
      <Footer actionButton>
   
        <Button
        onClick={()=>props.history.push(`${props.match.url}/selectionType`)}
          variant="contained"
          fullWidth
          size="lg"
          bold
          disabled={props.ProgramDetails.SendTo.length==0}
          startIcon={<span style={{ marginLeft: 10 }}></span>}
          sideIcons
          endIcon={<ArrowRight />}
        >
         Next
        </Button>
    
      </Footer>
    </Container>
  );
}
