import React, { Component, useState } from "react";
import Container from "../../components/Layout/Container";
import Header from "../../components/Layout/Header";
import Content from "../../components/Layout/Content";
import Button from "../../components/CustomButtons/Button";
import Footer from "../../components/Layout/Footer";
import axios from "utils/axios";
import api from "utils/api";
import { makeStyles } from "@material-ui/core/styles";
import Primary from "../../components/Typography/Primary";
import ArrowRight from "assets/svg/ArrowRight";
import InsAthlete from "components/Card/InsAthlete";
import DietIcon from "assets/svg/DietIcon";
import Instructor from "assets/svg/Coach";
import Athlete from "assets/svg/WeightLifting";
import List from "@material-ui/core/List";
import ListItem from "@material-ui/core/ListItem";
import ListItemText from "@material-ui/core/ListItemText";
import ListItemAvatar from "@material-ui/core/ListItemAvatar";
import Earth from "assets/svg/Earth";
import Money from "assets/svg/Money";
import CustomTabs from "components/CustomTabs/CustomTabs.js";
import CustomInput from "components/CustomInput/CustomInput.js";
import PhoneInput from "react-phone-input-2";
import Grid from "@material-ui/core/Grid";
import Height from "assets/svg/Height";
import Weight from "assets/svg/Weight";
import LeanMass from "assets/svg/LeanMass";
import  Body from "assets/svg/Body";
import Other from "components/Card/HealthInfo";
import "react-phone-input-2/lib/style.css";
const useStyles = makeStyles((theme) => ({
  root: {
    padding: "0px 30px 0px 30px",
  },
  title: {
    fontFamily: "Proxima Nova",
    fontWeight: "700",
    marginBlockStart: 0,
    marginBottom: 5,
    color:"#172A44",
    paddingLeft: 25,
  },
  mainDiv: {
    display: "flex",
    flex: 1,
    padding: 25,
    paddingTop: 10,
    flexDirection: "column",

    fontFamily: "Proxima Nova",
  },
  child1: {
    display: "flex",
    paddingBottom: "10px",
    flex: 1,
    width: "100%",
    flexDirection: "column",
    alignItems: "center",
  },
  child2: {
    flex: 2,
    paddingTop: "10px",
    display: "flex",
    flexDirection: "column",
    alignItems: "center",
    width: "100%",
    justifyContent: "space-around",
  },

  Footer: {
    margin: "0px 20px 20px 20px",
  },
  list: {
    width: "100%",
  },
  primary: {
    fontWeight: "bold",
    fontSize: 18,
    lineHeight: "18px",
  },
  secondary: {
    fontFamily: "Proxima Nova",
    marginTop: 12,
    color: "rgba(23,42,68,0.75)",
    fontWeight: 500,
    fontSize: 16,
    lineHeight: "22px",
    /* or 129% */
    paddingLeft: 25,
    paddingRight: 25,
  },
  icon: {
    fontSize: 45,
    marginRight: 25,
  },
}));

export default function Screen2(props) {
  const classes = useStyles();

const setHealtInfo=(att,value) => {
  props.updateOnboarding({healthInfo:{...props.Onboarding.healthInfo,[att]:value}})
}

  return (
    <Container>
      <Header />

      <Content flex >
        <h2 className={classes.title}>Health Information 1</h2>
        <p className={classes.secondary}>
        This information will be private unless
you give access to instructors.
        </p>
        <div className={classes.mainDiv}>
          <Grid container spacing={2}>
            <Grid item xs={6}>
              <Other
                Title={"Height"}
                placeholder={"00 cm"}
                small
                IconAv={<Height style={{ fontSize: 30 }} />}
                Text={props.Onboarding.healthInfo.height}
                Images={[]}
                onBlur={(e) =>setHealtInfo("height", e.target.value)}
              />
            </Grid>
            <Grid item xs={6}>
              <Other
                Title={"Weight"}
                placeholder={"00 kg"}
                small
                IconAv={<Weight style={{ fontSize: 30 }} />}
                Text={props.Onboarding.healthInfo.weight}
                Images={[]}
                onBlur={(e) =>setHealtInfo("weight", e.target.value)}
              />
            </Grid>
           
            <Grid item xs={6}>
              <Other
                Title={"Body Fat"}
                placeholder={"00 %"}
                small
                IconAv={<Body style={{ fontSize: 30 }} />}
                Text={props.Onboarding.healthInfo.bodyFat}
                Images={[]}
                onBlur={(e) =>setHealtInfo("bodyFat", e.target.value)}
              />
            </Grid>
            <Grid item xs={6}>
              <Other
                Title={"Lean Mass"}
                placeholder={"00 gm"}
                small
                IconAv={<LeanMass style={{ fontSize: 30 }} />}
                Text={props.Onboarding.healthInfo.leanMass}
                Images={[]}
                onBlur={(e) =>setHealtInfo("leanMass", e.target.value)}
              />
            </Grid>
          </Grid>
          <br/>
          <br/>
          <CustomInput
                 multiline
              labelText="Injuries"
                    bottomUnderline

        inputProps={{
    defaultValue:props.Onboarding.healthInfo.injuries,
            type: "text",
           
            onBlur:(e)=>setHealtInfo("injuries",e.target.value),
            style:{marginTop: 10 },
            placeholder:"Add yours",
        }}
                        formControlProps={{
                          fullWidth: true,
                          
                        }}
                      />
                      <br/>

          <CustomInput
                 multiline
              labelText="Medical conditions"
                    bottomUnderline

        inputProps={{
    defaultValue:props.Onboarding.healthInfo.medicalCondition,
            type: "text",
            placeholder:"Add yours",
            onBlur:(e)=>setHealtInfo("medicalCondition",e.target.value),
            style:{marginTop: 10 }
        }}
                        formControlProps={{
                          fullWidth: true,
                          
                        }}
                      />
                      <br/>
                       
        <CustomInput
                 multiline
                 labelText="Medical notes"
                    bottomUnderline
        inputProps={{
          defaultValue:props.Onboarding.healthInfo.medicalNotes,
            type: "text",
            placeholder:"Add yours",
            onBlur:(e)=>setHealtInfo("medicalNotes",e.target.value),
    style:{marginTop: 10 }
        }}
                        formControlProps={{
                          fullWidth: true,
                          
                        }}
                      />
                         
                       
        </div>
      </Content>
      <Footer actionButton>
        <Button
          // onClick={()=>props.history.push(`/onboarding/account-name`)}
          onClick={()=>props.history.push(`${props.match.path}/health-info2`,props.location.state)}
          variant="contained"
          fullWidth
          size="lg"
          bold
          startIcon={<span style={{ marginLeft: 22 }}></span>}
          sideIcons
          endIcon={<ArrowRight />}
        >
          Next
        </Button>
        <Button
        onClick={()=>props.history.push(`/onboarding/health-info2`,props.location.state)}
         style={{color:"#172A44",marginTop:10}}
          fullWidth
          size="lg"
          bold
        
        >
          Skip
        </Button>
      </Footer>
    </Container>
  );
}
