import React, { Component } from "react";
import Container from "../../components/Layout/Container";
import Header from "../../components/Layout/Header";
import Content from "../../components/Layout/Content";
import Button from "../../components/CustomButtons/Button";
import Footer from "../../components/Layout/Footer";
import axios from "utils/axios";
import api from "utils/api"
import { makeStyles } from "@material-ui/core/styles";
import Primary from "../../components/Typography/Primary";
import ArrowRight from "assets/svg/ArrowRight";
import InsAthlete from "components/Card/InsAthlete";
import DietIcon from "assets/svg/DietIcon";
import Instructor from "assets/svg/Coach"
import Athlete from "assets/svg/WeightLifting"
import List from '@material-ui/core/List';
import ListItem from '@material-ui/core/ListItem';
import ListItemText from '@material-ui/core/ListItemText';
import ListItemAvatar from '@material-ui/core/ListItemAvatar';
import Earth from "assets/svg/Earth"
import Money from "assets/svg/Money"
import CustomTabs from "components/CustomTabs/CustomTabs.js";
import CustomInput from "components/CustomInput/CustomInput.js";
import PhoneInput from 'react-phone-input-2'
import Grid from "@material-ui/core/Grid"
import FormControlLabel from "@material-ui/core/FormControlLabel";
import Checkbox from '@material-ui/core/Checkbox';
import 'react-phone-input-2/lib/style.css'
const useStyles = makeStyles((theme) => ({
  root: {
    padding: "0px 30px 0px 30px",
  },
  title: {
    fontFamily: "Proxima Nova",
    fontWeight: "700",
    marginBlockStart: 0,
    marginBottom: 5,
    color:"#172A44",
    paddingLeft: 25,
  },
  mainDiv: {
    display: "flex",
    flex: 1,
    padding: 25,
    paddingTop:10,
    flexDirection: "column",

    fontFamily: "Proxima Nova",
  },
  child1: {
    display: "flex",
    paddingBottom: "10px",
    flex: 1,
    width: "100%",
    flexDirection: "column",
    alignItems: "center",
  },
  child2: {
    flex: 2,
    paddingTop: "10px",
    display: "flex",
    flexDirection: "column",
    alignItems: "center",
    width: "100%",
    justifyContent: "space-around"
  },

  Footer: {
    margin: "0px 20px 20px 20px",
  },
  list:{
    width: '100%',
  },
  primary:{
    fontWeight: "bold",
    fontSize: 18,
    lineHeight: "18px",

  },
  secondary:{
      fontFamily: "Proxima Nova",
      marginTop:12,
      color: "#172A44",
    fontWeight:500,
    fontSize: 16,
    lineHeight: "22px",
    /* or 129% */
    paddingLeft: 25,
    paddingRight:25

  },
  icon:{
      fontSize:45,
      marginRight:25
  },
  label: {
  
    fontSize: "12px",
    color: "#172A44"
  
  },
}));

export default function Screen2(props) {
  const classes = useStyles();
const handleChange=(e)=>{
 if(e.target.checked){
     props.setData({type:e.target.id})
 }
 else{
    props.setData({type:null})
 }

}

const handleNext=()=>{
    if(props.type==""&&props.data.type)
    props.history.push(`/resetPassword/type-email-phone`)
    else{
        if(props.data.type){
            props.setData({uuid:props.data.type=="phone"?props.Profile.phone:props.Profile.email})
            props.updateFeedback({loading:true})
            if(props.data.type=="phone"){
             
               axios.get(`${api.protocol}${api.baseUrl}${api.resetPasswordOtp}${props.Profile.phone}`).then((response)=>{
                props.updateFeedback({loading:false,snackbar:true,message:"Verification code sent to your mobile!",severity:"success"})
                props.history.push(`/resetPassword/verify`)
                
              }).catch((error)=>{
                  if(error.response&&error.response.status===404)
                return props.updateFeedback({loading:false,snackbar:true,message:"Account does not exist with given phone number",severity:"error"})
              })
            
           
              }
            
            else
            {
           
              axios.post(`${api.protocol}${api.baseUrl}${api.ChangePasswordMail2}`,{email:props.Profile.email}).then((response)=>{
                
                props.updateFeedback({loading:false,snackbar:true,message:"Verification mail sent to your email!",severity:"success"})
                props.history.push(`/resetPassword/verify`)
              }).catch((error)=>{
                  if(error.response&&error.response.status===404)
                return props.updateFeedback({loading:false,snackbar:true,message:"Account does not exist with given email",severity:"error"})
              })
            }
           
              
        }
    }
}
  return (
    <Container>
      <Header />

      <Content flex>
        <h2 className={classes.title}>Reset password method</h2>
       
        <div className={classes.mainDiv}>
            <Grid container spacing={1}>
               {((props.type=="profile"&&props.Profile.phone&&props.Profile.phone!=="")||props.type=="")&& <Grid item>
                <FormControlLabel
               
               control={
                 <Checkbox
                 checked={props.data.type=="phone"}
                  color="primary"
                 
                  onChange={handleChange}
                  id="phone"
                  size="medium"
                 />
               }
            
               classes={{label: classes.label}}
               label="Text code to my registered phone "
             />
                </Grid>}


               { 
               ((props.type=="profile"&&props.Profile.email&&props.Profile.email!=="")||props.type=="")&&
               <Grid item>
                    
                <FormControlLabel
               
               control={
                 <Checkbox
                 checked={props.data.type=="email"}
                 onChange={handleChange}
                 id="email"
                  color="primary"
                  size="medium"
                 />
               }
            classes={{label: classes.label}}
              
               label="Email a code to my registered email"
             />
                    </Grid>}


            </Grid>
         
       
        </div>
      </Content>
      <Footer actionButton>
        <Button
        
          variant="contained"
          fullWidth
          size="lg"
          bold
          startIcon={<span style={{ marginLeft: 10 }}></span>}
          sideIcons
          endIcon={<ArrowRight />}
          onClick={handleNext}
        >
         Reset my password
        </Button>
      </Footer>
    </Container>
  );
}
