import React, { Component, useState } from "react";
import Container from "../../components/Layout/Container";
import Header from "../../components/Layout/Header";
import Content from "../../components/Layout/Content";
import Button from "../../components/CustomButtons/Button";
import Footer from "../../components/Layout/Footer";
import IconButton from "@material-ui/core/IconButton";
import { makeStyles } from "@material-ui/core/styles";
import Divider from "@material-ui/core/Divider";
import { theme } from "assets/css/theme";
import Primary from "../../components/Typography/Primary";
import ArrowRight from "assets/svg/ArrowRight";
import InsAthlete from "components/Card/InsAthlete";
import DietIcon from "assets/svg/DietIcon";
import Instructor from "assets/svg/Coach";
import Athlete from "assets/svg/WeightLifting";
import Camera from "assets/svg/Camera";
import AddVideo from "assets/svg/CamVid";
import Grid from "@material-ui/core/Grid";
import WeekCard from "components/Card/workout3";
import CustomTabs from "components/CustomTabs/WeekTabs.js";
import UploadCard from "components/Card/UploadCard";
import AddIcon from "@material-ui/icons/Add";
import Drawer from "@material-ui/core/Drawer";
import InputBase from "@material-ui/core/InputBase";
import Toggle from "assets/svg/Toggle";
import Toggleh from "assets/svg/Toogleh";
import EditDayExercise from "components/CreateProgram/ListDetails";
import EditWeeks from "components/CreateProgram/RepeatWeek";
import {handleuploadImage} from "utils/uploader/"
import VideoThumbnail from 'react-video-thumbnail'
import WorkoutContainer from "components/Card/workout4"
import AddExerciseDrawer from "components/DailyExercise/ExerciseList"
import ScrollList from "components/CustomTabs/Scrolllist"
import { defaultProps } from "recompose";
import DeleteModal from "components/Dialogue/delete"
import Typography from "@material-ui/core/Typography"
const useStyles = makeStyles((thme) => ({
  root: {
    padding: "0px 30px 0px 30px",
  },
  title: {
    fontFamily: "Proxima Nova",
    fontWeight: "bold",
    fontSize: 24,
    marginBottom: 5,
    marginTop: 10,

    paddingLeft: theme.padding,
  },
  mainDiv: {
    display: "flex",
    flexDirection: "column",
    height: "100%",
    padding: 20,
    paddingLeft: theme.padding,
    paddingRight: theme.padding,
    paddingTop: 0,
    fontFamily: "Proxima Nova",
  },

  Footer: {
    margin: "0px 20px 20px 20px",
  },
  label: {
    fontFamily: "Proxima Nova",
    fontSize: "16px",
    padding: 5,
    fontWeight: "bold",
    color: "#172A44",
  },
  text: {
    fontFamily: "Proxima Nova",
    fontSize: "14px",
    padding: 5,
    marginBottom: 10,
    color: "#172A44",
  },

  drawer: {
    borderRadius: "26px 26px 0px 0px",
 
    
  },
  drawerInside: {
    padding: "30px 20px 20px 15px",
    position: "relative",
    height: "100%",
  },
  headDrawer: {
    display: "flex",
    flexDirection: "row",
    width: "100%",
    alignItems: "center",
justifyContent: "space-between",
    fontFamily: "Proxima Nova",
    fontSize: "18px",
    lineHeight: "29px",
    color: "#172A44",
   
   

  },

  icon: {
    fontSize: "16px",
  },
  input: {
    padding: "0px 0px 0px 0px",
    fontSize: "18px",
    width: "80%",
  },
  drawerContent: {
    marginTop: 10,
    width: "100%",
    maxHeight: "45vh",
    overflowY: "scroll",
  },
  HeaderDrawer: {
    display: "inline-flex",
    flexDirection: "row",
justifyContent: "flex-start",
    alignItems: "center",
    fontSize: 18,
  },
  drawerTitle:{
    fontSize:24,
    fontWeight: "bold",
    marginLeft:5,
    marginBottom:15,
    marginTop:5, 
    color: "#172A44",
    fontFamily: "Proxima Nova",
  }
}));
export default function Screen2(props) {
  const classes = useStyles();
  const [value, setValue] = React.useState(0);
  const [drawer, toggleDrawer] = React.useState(false);
  const [drawerVal, setDrawerVal] = React.useState(null);

  const [weeks,setWeekQ] = useState([])
const [deleteModal,setDeleteModal]=useState(false)
const [deleteId,setDeleteId]=useState(null)
const [view,setView]=useState("h")


const currentWeek=props.currentWeek
const currentDay=props.currentDay

const setCurrentWeek=(data)=>{
  props.setState({currentWeek:data})
}
const setCurrentDay=(data)=>{
  props.setState({currentDay:data})
}
  const onChange=(checked,index)=>{
  
    let data=[...weeks]
    if(checked){
data.push(index)
setWeekQ(data)
    }
    else{
      data.splice(data.findIndex(item => item==index),1)
      setWeekQ(data)
    }
    console.log(weeks)
  }



  const handleChange = (value) => {
    setCurrentWeek(value);
  
  };



  const setWeek = (week) => {
    setCurrentWeek(week);
  };

  const addExercise = (week, day) => {
    setCurrentWeek(week);
    setCurrentDay(day);
    if(props.AtheletePlan.Exercises.ExercisePlan[week][day].Exercise.length>0)
   { toggleDrawer(true);
    setDrawerVal("add");}
  };

  const settings = (week, day) => {
  
    setCurrentWeek(week);
    setCurrentDay(day);
    toggleDrawer(true);
    setDrawerVal("setting");
  };

  const repeatDay = () => {
    setDrawerVal("repeat");
    setWeekQ([])
  }


  console.log(props.AtheletePlan)



  return (
    <Container>
      <Header />
     
      <Content>
        <h2 className={classes.title}>Workout Calender</h2>
        {/* <input type="file" id="add workout" onChange={addWorkout}/> */}
        <div className={classes.mainDiv}>
          <CustomTabs
            value={currentWeek}
            onChange={handleChange}
            weekTab
            plainTabs
            scrollButtons="off"
            selected={currentWeek}
           
            hadleClick={setWeek}
            view
            variant="scrollable"
            tabs={props.AtheletePlan.Exercises.ExercisePlan}
          />

          <div style={{ width: "100%",marginTop:10 }}>
            <Grid container spacing={2}>
              {props.AtheletePlan.Exercises.ExercisePlan[currentWeek].map(
                (item, index) => {

                  let placeholder=item.Exercise.length>0?"https://slorge.s3.amazonaws.com/1595612396776-mr-lee-f4RBYsY2hxA-unsplash%20%281%29.jpg":"https://slorge.s3.us-east-2.amazonaws.com/1595612567342-restday.jpg"
                  if(item.Exercise.length)
                  return (
                    <Grid item xs={6}>
                      <WeekCard
                      noDots
                      Image={item.Cover?item.Cover:placeholder}
                      length={item.Exercise.length}
                      icon={false}
                      onClickContainer={() => addExercise(currentWeek, index)}
                        onClickMore={() => settings(currentWeek, index)}
                        onClickImage={() => addExercise(currentWeek, index)}
                        Title={"Day " + (index + 1)}
                        Text={item.Title ? item.Title : ""}
                  
                      />
                    </Grid>
                  );
                }
              )}
            </Grid>
          </div>
        </div>
      </Content>
     

      <Drawer
        anchor={"bottom"}
       
        className={classes.drawer}
        classes={{ paper: classes.drawer }}
      >
        <div className={classes.drawerInside}>
          <div className={classes.headDrawer}>
          &nbsp;&nbsp;<IconButton onClick={()=>setView("h")} size="small" ><Toggle className={classes.icon}  /></IconButton> 
          &nbsp;
            <IconButton onClick={()=>setView("v")} size="small"> <Toggleh className={classes.icon} /></IconButton> 
            &nbsp;&nbsp;Day {currentDay + 1}:&nbsp;&nbsp;

            <Typography>
           { props.AtheletePlan.Exercises.ExercisePlan[currentWeek][currentDay].Title}
            </Typography>
            
            <Button
              style={{ position: "absolute", right: 30, top: 20 }}
              onClick={() => toggleDrawer(false)}
            >
              Done
            </Button>
          </div>
          <div className={classes.drawerContent}>
         
           
               { <AddExerciseDrawer {...props}
                mode={"view"} 
                ProgramDetails={props.AtheletePlan.Exercises} 
                view={view} currentWeek={currentWeek} currentDay={currentDay} 
                startExercise={(index)=>{
props.setState({currentExercise:index})

props.history.push(`${props.match.url}/exercise`)

                }}
                
                
                /> }
        
           
       
        
          </div>
        </div>
      </Drawer>

     
    
      <Drawer
        anchor={"bottom"}
        open={drawer&&drawerVal == "add"}
        onClose={() => toggleDrawer(false)}
        className={classes.drawer}
        classes={{ paper: classes.drawer }}
      >
        <div className={classes.drawerInside}>
          <div className={classes.headDrawer}>
            <div className={classes.HeaderDrawer}>
            <div style={{marginLeft:5}}> Day {currentDay + 1} 
             
           
                </div>
            </div>
            <Button
            size="sm"
            
              onClick={() => toggleDrawer(false)}
            >
              Done
            </Button>
          </div>
<div className={classes.drawerTitle}>

{   props.AtheletePlan.Exercises.ExercisePlan[props.currentWeek][
                    props.currentDay
                  ].Title}
</div>
        <Divider variant="left" style={{width: "50%"}} />
          <div className={classes.drawerContent}>
            <AddExerciseDrawer
            
              mode={"view"} 
              ProgramDetails={props.AtheletePlan.Exercises} 
              view={view} currentWeek={currentWeek} currentDay={currentDay} 
              startExercise={(index)=>{
props.setState({currentExercise:index})

props.history.push(`${props.match.url}/exercise`)

              }}
              view={"v"}
            />
          </div>
         
     
          
          <center>  <Divider variant="middle" style={{width: "50%",marginTop:25,marginBottom:15}} /></center>
         
<center style={{fontSize:18,color:"rgba(23, 42, 68, 0.5)",fontFamily: "Proxima Nova"}}>
          {props.AtheletePlan.Exercises.ExercisePlan[props.currentWeek][
                    props.currentDay
                  ].Exercise.length} Exercises
                  </center>
        </div>
      </Drawer>
    
      
    </Container>
  );
}
