import IconButton from "@material-ui/core/IconButton";
import CalendarTodayIcon from "@material-ui/icons/CalendarToday";
import "react-phone-input-2/lib/style.css";
import CancelIcon from "@material-ui/icons/Cancel";
import AddIcon from "@material-ui/icons/Add";
import PublishIcon from "@material-ui/icons/Publish";
import AddFolder from "assets/svg/addFolder";
import Subscription from "assets/svg/Subscription";
import OneTime from "assets/svg/OneTime";
const useStyles = makeStyles((theme) => ({
  title: {
    fontFamily: "Proxima Nova",
    fontWeight: "700",
    marginBlockStart: 0,
fontWeight: "bold",
fontSize:24,
    color:"#172A44",
    paddingTop: 10,
    paddingLeft: 25,
  },
  mainDiv: {
    padding: 25,
    paddingTop: 25,

    fontFamily: "Proxima Nova",
  },

  Footer: {
    margin: "0px 20px 20px 20px",
  },
  list: {
    width: "100%",
  },
  primary: {
    fontFamily: "Proxima Nova",
    paddingLeft: 3,
    fontWeight: "bold",
    fontSize: "16px",
    lineHeight: "38px",
    color: "#172A44",
  },

  image: {
    width: "100%",
    paddingTop: "60%",
    borderRadius: 16,
    backgroundColor: "grey",
  },

  icon: {
    position: "absolute",

    top: 0,
    right: "10vw",
  },

  Avatar: {
    position: "absolute",
    bottom: -25,
    width: 60,
    height: 60,
    left: 30,
  },

  label: {
    fontFamily: "Proxima Nova",
    color: "#172A44",
    fontSize: "16px",

    fontWeight: "bold",
  },
  prDetails: {
    fontFamily: "Proxima Nova",
    color: "#172A44",
    fontSize: "18px",
    padding: 15,

    lineHeight: "19px",
    fontWeight: "bold",
  },
  label:{
    fontFamily:"Proxima Nova",
fontSize:"16px",
fontWeight: "bold",
color: "#172A44",
display:"flex",
flexDirection:"row",


  },
}));

export default function Screen2(props) {
  const classes = useStyles();

  const sendProgram = () => {
 
    props
      .sendProgram({
        _id: props.ProgramDetails._id,
        Title: props.ProgramDetails.Title,
        SendTo: props.ProgramDetails.SendTo,
        Price: props.ProgramDetails.Price,
        PaymentType: props.ProgramDetails.PaymentType,
        GreetingMessage:props.ProgramDetails.GreetingMessage
      })
      .then((program) => {
        if(props.userId&&(props.returnIndex-props.history.length)-1<-4)
        props.history.go(`${(props.returnIndex-props.history.length)-1}`)
        else
        props.history.replace("/instructor");
      });
  };

  return (
    <Container>
      <Header  />

      <Content>
        <div className={classes.title}>Overview</div>

        <div className={classes.mainDiv}>
          <Grid container spacing={1} justify="center" alignItems="center">
            {props.mode !== "edit" && (
              <Grid item xs={12}>
                <div className={classes.label}>To</div>
                <ChipInput
             
                  fullWidth
                  defaultValue={[...props.ProgramDetails.SendTo]}
                  onAdd={(chip) => console.log(chip)}
                  onDelete={(chip, index) => console.log(chip, index)}
                  disabled
                />
              </Grid>
            )}

            <Grid item xs={12} style={{ marginTop: 15 }}>
             
              <span className={classes.label}>Program</span>
             

              <Grid container style={{ marginTop: 15 }}>
                <Grid item xs={5}>
                  <div
                    className={classes.image}
                    style={{
                      backgroundImage: `url(${
                        props.ProgramDetails.BannerImage
                          ? props.ProgramDetails.BannerImage
                          : "https://img.freepik.com/free-photo/athletes-floor-dumbbell-lift-with-one-hand_94347-858.jpg?size=626&ext=jpg"
                      })`,
                      backgroundSize: "cover",
                    }}
                  ></div>
                </Grid>
                <Grid item xs={7}>
                  <div className={classes.prDetails}>
                    {props.ProgramDetails.Title}
                  </div>
                </Grid>
              </Grid>
              <Divider style={{ marginTop: 15}} />
            </Grid>
          

            {
             
                <Grid item xs={12} style={{ marginTop: 10 }}>
                  <span className={classes.label}>Payments</span>
               

                  <Grid container style={{ marginTop: 15 }}>
                    <Grid item xs={12} style={{ display: "flex",marginBottom:10 }}>
                      <Typography style={{ color: "#172A44", size: 16 }}>
                        Price :
                      </Typography>
                      &nbsp;{" "}
                      <Typography color={"primary"}>
                         {props.ProgramDetails.Price>0?"$ "+props.ProgramDetails.Price:"N/A"}
                      </Typography>
                    </Grid>

                    <Grid item xs={12} style={{ display: "flex" }}>
                      <Typography style={{ color: "#172A44", size: 16 }}>
                        Type :
                      </Typography>
                      &nbsp;{" "}
                      <Typography color={"primary"}>
                        {props.ProgramDetails.Price>0?props.ProgramDetails.PaymentType:"N/A"}
                      </Typography>
                    </Grid>
                  </Grid>
                  <Divider style={{ marginTop: 15 }} />
                </Grid>
              }


                <Grid item xs={12} style={{ marginTop: 10 }}>
              <CustomInput
                labelText="Message"
                multiline={true}
                bottomUnderline
                rows={3}
              
                formControlProps={{
                  fullWidth: true,
                }}
                inputProps={{
                 
                  value: props.ProgramDetails.GreetingMessage,
                  onChange: (e) =>
                    props.updateProgram({ GreetingMessage: e.target.value }),
                  multiline: true,
                  rows: 4,
                  placeholder:
                    "This is the message that user will get from you after buying your program.",
                }}
              />
            </Grid>
          </Grid>
        </div>
      </Content>
      <Footer actionButton>
     
        <Button
          onClick={sendProgram}
          variant="contained"
          fullWidth
          size="lg"
          bold
        >
         Send
        </Button>
    
      </Footer>
    </Container>
  );
}
