import React, { Component } from 'react'
import { Router, Route, Switch } from "react-router-dom";
import SelectType from "../Screens/createProgram/selectType"
import UploadBanner from "../Screens/createProgram/programBanners"
import Description from "../Screens/createProgram/programDescription"
import AddDays from "../Screens/createProgram/AddDays"
import AddExercise from "../Screens/createProgram/AddExercise"
import SelectExercise from "../Screens/createProgram/SelectExercise"
import CreateDiet from "../Screens/createProgram/CreateDiet"
import SetPayment from "../Screens/createProgram/setupPrice"
import SetDiscount from "../Screens/createProgram/setDiscount"
import Greeting from "../Screens/createProgram/greeting"
import Preview from "../Screens/createProgram/preview"
import ExerciseView from "../Screens/common/ExerciseView"
import ClientDetails from "../Screens/createProgram/ClientDetails"
import MessageScreen from "../Screens/createProgram/message"
import {connect} from "react-redux"
import {createProgram,getSpecificProgram,saveProgram} from "../store/actions/createProgram"
import {updateEditProgram as updateProgram} from "../store/actions/createProgram"
import {updateFeedback} from "../store/actions/feedback"
import SelectUploadType from "../Screens/createProgram/SelectUploadType"
import FiggsLibrary from "./FiggsLibrary"
import {store} from "../store"
import ProgramList from 'store/reducers/ProgramList';
class CreateProgram extends Component {
    state={
currentWeek:0,
currentDay:0,
file:null,
fileObject:null,
currentExercise:0


    }


    componentDidMount=()=>{
        if(this.props.match.params.id){
   

    this.props.getSpecificProgram(this.props.match.params.id).then(data =>{
      
      store.dispatch({ type:"SET_BUFFER",payload:data})
    })


        }
if(this.props.figgsId){
    this.props.updateProgram({SendTo:[this.props.figgsId]})
}

       
    }

    addWorkout=(data)=>{
        let program={...this.props.ProgramDetails}
        program.ExercisePlan[this.state.currentWeek][this.state.currentDay].Exercise.push(data)
        this.props.updateProgram({ExercisePlan:program.ExercisePlan})
        this.props.history.replace(`${this.props.match.url}/add-days`)
    }
    editExercise=(data)=>{
        let program={...this.props.ProgramDetails}
        program.ExercisePlan[this.state.currentWeek][this.state.currentDay].Exercise[this.state.currentExercise]=data
        this.props.updateProgram({ExercisePlan:program.ExercisePlan})
        this.props.history.replace(`${this.props.match.url}/add-days`)
    }


    addExercises=(data)=>{
        console.log(data)
        let program={...this.props.ProgramDetails}
        program.ExercisePlan[this.state.currentWeek][this.state.currentDay].Exercise=[...program.ExercisePlan[this.state.currentWeek][this.state.currentDay].Exercise,...data]
        this.props.updateProgram({ExercisePlan:program.ExercisePlan})
        this.props.history.replace(`${this.props.match.url}/add-days`)
    }

    ViewExercise=(index)=>{
        this.setState({currentExercise:index})
        this.props.history.push(`${this.props.match.url}/edit-exercise`)
    }
    render() {
        console.log(this.props.mode)
        return (
            <div>
                   <Route exact  path={`${this.props.match.url}/`} render={()=><Description {...this.props}/>} />
                   {/* <Route exact  path={`${this.props.match.url}/`} render={()=><SelectType {...this.props} />} /> */}
                   <Route exact path={`${this.props.match.url}/exercise-view`} render={()=><ExerciseView {...this.props}  setState={(data)=>this.setState(data)} {...this.state} />} />
                   <Route exact  path={`${this.props.match.url}/select-type`} render={()=><SelectUploadType {...this.props} setState={(data)=>this.setState(data)}/>} />
                   <Route exact  path={`${this.props.match.url}/upload-banner`} render={()=><UploadBanner {...this.props} />} />
                  <Route exact path={`${this.props.match.url}/clientDetails`} render={()=><ClientDetails {...this.props}/>}/>
                  <Route exact  path={`${this.props.match.path}/edit-exercise`} render={()=><AddExercise {...this.props} {...this.state} setState={(data)=>this.setState(data)} data={this.props.ProgramDetails.ExercisePlan[this.state.currentWeek][this.state.currentDay].Exercise[this.state.currentExercise]} editMode={true} editExercise={this.editExercise}/>}  />
                   <Route exact  path={`${this.props.match.path}/message`} render={()=><MessageScreen {...this.props}/>} />
                   <Route exact  path={`${this.props.match.url}/add-days`} render={()=><AddDays {...this.props} setState={(data)=>this.setState(data)} ViewExercise={this.ViewExercise} {...this.state}/>} />
                   <Route exact  path={`${this.props.match.url}/add-exercise`} render={()=><AddExercise {...this.props} file={this.state.file} setState={(data)=>this.setState(data)} fileObject={this.state.fileObject} handleWorkoutSuccess={this.addWorkout}/> } />
                   <Route exact  path={`${this.props.match.url}/create-diet`} render={()=><CreateDiet {...this.props}/>} />
                   <Route exact  path={`${this.props.match.url}/select-exercise`} render={()=><SelectExercise {...this.props} />} />
                   <Route exact  path={`${this.props.match.url}/setup-payment`} render={()=><SetPayment {...this.props} />} />
                   <Route exact  path={`${this.props.match.url}/setup-discount`} render={()=><SetDiscount {...this.props}/>} />
                   <Route exact  path={`${this.props.match.url}/greeting`} render={()=><Greeting {...this.props} mode="editSend"/>} returnIndex={this.props.returnIndex} />
                   <Route exact  path={`${this.props.match.url}/preview`} render={()=><Preview {...this.props}/>} />
                   <Route    path={`${this.props.match.url}/library`} render={(props)=><FiggsLibrary {...props} addExercises={this.addExercises} selectionMode />} />
            </div>
        )
    }
}

const mapStateToProps =(state) => {
    return {
        ProgramDetails:state.ProgramList.Buffer,
        Profile:state.Profile,
        ProgramList:state.ProgramList
    }
}

export default connect(mapStateToProps,{updateProgram,updateFeedback,getSpecificProgram,saveProgram})(CreateProgram)