const list = [
  { name: "item1" },
  { name: "item2" },
  { name: "item3" },
  { name: "item4" },
  { name: "item5" },
  { name: "item6" },
  { name: "item7" },
  { name: "item8" },
  { name: "item9" },
  { name: "item10" },
  { name: "item11" },
  { name: "item12" },
  { name: "item13" },
  { name: "item14" },
  { name: "item15" },
  { name: "item16" },
  { name: "item17" },
  { name: "item18" },
  { name: "item19" },
  { name: "item20" },
  { name: "item21" },
  { name: "item22" },
  { name: "item23" },
  { name: "item24" },
  { name: "item25" },
];

const MenuItem = ({ text, selected }) => {
  return <div className={`menu-item ${selected ? "active" : ""}`}>{text}</div>;
};

const Arrow = ({ text, className }) => {
  return <div className={className}>{text}</div>;
};
Arrow.propTypes = {
  text: PropTypes.string,
  className: PropTypes.string,
};

export const ArrowLeft = Arrow({ text: "<", className: "arrow-prev" });
export const ArrowRight = Arrow({ text: ">", className: "arrow-next" });

class App extends Component {
  state = {
    alignCenter: true,
    clickWhenDrag: false,
    dragging: true,
    hideArrows: true,
    hideSingleArrow: true,
    itemsCount: list.length,
    selected: "item1",
    translate: 0,
    transition: 0.4,
    wheel: true,
    deleteModal: false,
    deleteId: null,
  };

  constructor(props) {
    super(props);
    this.menu = null;
  }

  onUpdate = ({ translate }) => {
    console.log(`onUpdate: translate: ${translate}`);
    this.setState({ translate });
  };

  componentDidUpdate(prevProps, prevState) {
    const { alignCenter } = prevState;
    const { alignCenter: alignCenterNew } = this.state;
    if (alignCenter !== alignCenterNew) {
      this.menu.setInitial();
    }
  }

  Menu = (list) => {
    let items = this.props.ProgramDetails.ExercisePlan[this.props.currentWeek][
      this.props.currentDay
    ].Exercise.map((el, index) => {
      const { name } = el;

      return (
        <div style={{ minWidth: "150px", margin: 10 }} key={index}>
          <WorkoutContainer
           onClick={()=>this.props.startExercise(index)}
            banner={el.banner}
            title2={"Exercise " + (index + 1)}
            sub1={el.title}
            Icon={<>
             {this.props.mode!=="view"&& <IconButton
                onClick={() =>
                  this.setState({ deleteModal: true, deleteId: index })
                }
              >
                <Delete style={{ color: "white" }} />
              </IconButton>}
              </>
            }
          />
        </div>
      );
    });

    return items;
  };
  setSelected = (ev) => {
    const { value } = ev.target;
    this.setState({ selected: String(value) });
  };

  render() {
    const {
      alignCenter,
      clickWhenDrag,
      hideArrows,
      dragging,
      hideSingleArrow,
      itemsCount,
      selected,
      translate,
      transition,
      wheel,
    } = this.state;

    const menu = this.Menu();

    const checkboxStyle = {
      margin: "5px 10px",
    };
    const valueStyle = {
      margin: "5px 10px",
      display: "inline-block",
    };

    return (
      <div className="App">
        <DeleteModal
          open={this.state.deleteModal}
          handleClose={() =>
            this.setState({ deleteModal: false, deleteId: null })
          }
          id={this.state.deleteId}
          delete={(id) => {
            this.props.deleteExercise(id);
            this.setState({ deleteModal: false, deleteId: null });
          }}
        />

     {this.props.view=="h"&&   <ScrollMenu data={this.Menu()} selected={null} alignCenter={false} />}
        {this.props.view=="v"&&
        <div style={{marginTop:20}}>
        {  this.props.ProgramDetails.ExercisePlan[this.props.currentWeek][
      this.props.currentDay
    ].Exercise.map((el, index) => {

      return(
      <>
      <WorkoutCard
      {...el}
      onClick={()=>this.props.startExercise(index)}
      index={index+1}
        Icon={
          <>
            {this.props.mode!=="view"&& <IconButton
            onClick={() =>
              this.setState({ deleteModal: true, deleteId: index })
            }
          >
            <Delete style={{ color: "black" }} />
          </IconButton>
        }
          </>
        }
      />
      <br/>
      </>
      )

    })


    }
       
        
        </div>
        }
      </div>
    );
  }
}

export default App;
