import React from 'react';
import clsx from 'clsx';
import { makeStyles } from '@material-ui/core/styles';
import SwipeableDrawer from '@material-ui/core/SwipeableDrawer';
import Button from '@material-ui/core/Button';
import List from '@material-ui/core/List';
import Divider from '@material-ui/core/Divider';
import ListItem from '@material-ui/core/ListItem';
import ListItemIcon from '@material-ui/core/ListItemIcon';
import ListItemText from '@material-ui/core/ListItemText';
import InboxIcon from '@material-ui/icons/MoveToInbox';
import MailIcon from '@material-ui/icons/Mail';
import ListSubheader from "@material-ui/core/ListSubheader";
import {withRouter} from "react-router-dom"
import ListInstructor from "./Drawer/InstructorList"
import ListAthlete from "./Drawer/AthleteList"
import Header from "./Drawer/Navbar.js"
import Logo from 'assets/img/logo.png'
import CloseIcon from '@material-ui/icons/Close';
import IconButton from '@material-ui/core/IconButton';
import {connect } from "react-redux"
import {updateProfile} from "store/actions/Profile"
const useStyles = makeStyles({
  list: {
    width: 250,
  },
  fullList: {
    width: 'auto',
  },
  header:{
    flex:1,
    flexDirection: 'row',
    display: 'flex',
    justifyContent: 'space-between',
    padding:15,
    alignItems: 'center',
    paddingTop:20,
    paddingLeft:30,
    borderBottom:"0.5px solid rgba(212, 215, 220, 0.5)"
  },
  title: {
    fontFamily: "Proxima Nova",
    fontSize:18,
    color:"rgba(23, 42, 68, 0.75);"
  },
  subtitle: {
    color: "#007EA0",
    fontFamily: "Proxima Nova",
    fontSize: 20,

  },
  container:{
    display: "flex",
    justifyContent:"space-between",
    flexDirection: "row",
    flex:1,
    padding:25
  },
  content:{
    display: "block",
    marginBottom:10
  },
  bottomText: {
    position:"absolute",
    bottom:10,
    width: "100%",
    color: "#172A44",
    fontFamily: "Proxima Nova",
    marginBottom: "20px",
    textAlign: "center",
    fontSize: 14
  },
});

function SwipeableTemporaryDrawer(props) {
  const classes = useStyles();
  const [state, setState] = React.useState({
    top: false,
    left: false,
    bottom: false,
    right: false,
  });

  const toggleDrawer = (anchor, open) => (event) => {
    if (event && event.type === 'keydown' && (event.key === 'Tab' || event.key === 'Shift')) {
      return;
    }

    setState({ ...state, [anchor]: open });
  };

  const list = (anchor) => (
    <div
      className={clsx(classes.list, {
        [classes.fullList]: anchor === 'top' || anchor === 'bottom',
      })}
      role="presentation"
      onClick={toggleDrawer(anchor, false)}
      onKeyDown={toggleDrawer(anchor, false)}
    >
      <List
        subheader={
            <ListSubheader component="div" id="nested-list-subheader">
            OnBoarding Screens
           </ListSubheader>
        }
      >

        {["home-onboarding",'account-type', 'account-summary', 'account-details', 'account-verification',"account-name","account-dob","account-welcome","account-photo","account-profile"].map((text, index) => (
          <ListItem button key={text} onClick={()=>props.history.push(`/onboarding/${text}`)}>
          
            <ListItemText primary={text} />
          </ListItem>
        ))}
      </List>
      <Divider />


      <List
        subheader={
            <ListSubheader component="div" id="nested-list-subheader">
           Account settings
           </ListSubheader>
        }
      >

        {["/"].map((text, index) => (
          <ListItem button key={text} onClick={()=>props.history.push(`/account-settings/`)}>
          
            <ListItemText primary={"Account Settings"} />
          </ListItem>
        ))}

      </List>
      <Divider />
      <List
        subheader={
            <ListSubheader component="div" id="nested-list-subheader">
           Create Profile
           </ListSubheader>
        }
      >
  <ListItem button  onClick={()=>props.history.push(`/create-profile-instructor/${""}`)}>
          
          <ListItemText primary={"create profile"} />
        </ListItem>
        {["profile-preview","private-info","private-plan"].map((text, index) => (
          <ListItem button key={text} onClick={()=>props.history.push(`/create-profile-instructor/${text}`)}>
          
            <ListItemText primary={text} />
          </ListItem>
        ))}
        
      </List>
    </div>
  );

  return (

        <React.Fragment >

          <SwipeableDrawer
            anchor={"top"}
            open={props.open}
            onClose={() =>props.toggleDrawer(false)}
            onOpen={() =>props.toggleDrawer(true)}
          >
                 
        <div style={{width:"100vw",height:"100vh"}}>
           

<div className={classes.header}>
<img src={Logo} style={{width:84,height:"auto"}}/>
<IconButton onClick={() =>props.toggleDrawer(false)}>

<CloseIcon style={{color:"#172A44",fontWeight:"bold"}}/>
</IconButton>
</div>
<div className={classes.container} style={{borderBottom:"0.5px solid rgba(212, 215, 220, 0.5)"}}>

<div className={classes.content}>
<div className={classes.title}>FIGGS FOR</div><br/>
<div className={classes.subtitle}>Instructor</div><br/>
<div className={classes.subtitle}>Clients</div><br/>
<div className={classes.subtitle}>Gyms</div><br/>
  </div>


  <div className={classes.content}>


  </div>
</div>
<div className={classes.container} >

<div className={classes.content}>
<div className={classes.title}>MORE</div><br/>
<div className={classes.subtitle}>About</div><br/>
<div className={classes.subtitle}>Careers</div><br/>
<div className={classes.subtitle}>Payments</div><br/>
<div className={classes.subtitle}>Support</div><br/>
  </div>


  <div className={classes.content}>
  <div className={classes.title}>SOCIAL</div><br/>
<div className={classes.subtitle}>Twitter</div><br/>
<div className={classes.subtitle}>Discourd</div><br/>
<div className={classes.subtitle}>Reddit</div><br/>

  </div>
</div>


<div className={classes.bottomText}>
         &#169; copyright are legally owned by figgs.co
              {/* Already have an accont? <b style={{ color: "#007EA0" }} onClick={()=>props.history.push("onboarding/signin")}>Sign in</b> */}
            </div>
        </div>
          </SwipeableDrawer>
        </React.Fragment>

  );
}

export default withRouter(SwipeableTemporaryDrawer)