import React, { Component, useState } from "react";
import Container from "../../components/Layout/Container";
import Header from "../../components/Layout/Header";
import Content from "../../components/Layout/Content";
import Button from "../../components/CustomButtons/Button";
import Footer from "../../components/Layout/Footer";
import Typography from "@material-ui/core/Typography";

import { makeStyles } from "@material-ui/core/styles";
import Primary from "../../components/Typography/Primary";
import ArrowRight from "assets/svg/ArrowRight";
import PriceCard from "components/Card/priceCard";
import DietIcon from "assets/svg/DietIcon";
import Instructor from "assets/svg/Coach";
import Athlete from "assets/svg/WeightLifting";
import List from "@material-ui/core/List";
import ListItem from "@material-ui/core/ListItem";
import ListItemText from "@material-ui/core/ListItemText";
import ListItemAvatar from "@material-ui/core/ListItemAvatar";

import ProfileImg from "assets/img/screens/profile.png";
import CustomTabs from "components/CustomTabs/CustomTabs.js";
import CustomInput from "components/CustomInput/CustomInput.js";
import PhoneInput from "react-phone-input-2";
import Grid from "@material-ui/core/Grid";
import Chip from "@material-ui/core/Chip";
import Avatar from "@material-ui/core/Avatar";
import Camera from "assets/svg/Camera";

import DateFnsUtils from "@date-io/date-fns";
import "date-fns";
import MomentUtils from "@date-io/moment";
import {
  MuiPickersUtilsProvider,
  KeyboardTimePicker,
  KeyboardDatePicker,
} from "@material-ui/pickers";
import InputAdornment from "@material-ui/core/InputAdornment";
import IconButton from "@material-ui/core/IconButton";
import CalendarTodayIcon from "@material-ui/icons/CalendarToday";
import "react-phone-input-2/lib/style.css";
import CancelIcon from "@material-ui/icons/Cancel";
import AddIcon from "@material-ui/icons/Add";
import PublishIcon from "@material-ui/icons/Publish";
import AddFolder from "assets/svg/addFolder";
import Subscription from "assets/svg/Subscription";
import OneTime from "assets/svg/OneTime";
const useStyles = makeStyles((theme) => ({
  title: {
    fontFamily: "Proxima Nova",
    fontWeight: "700",
    marginBlockStart: 0,
    marginBottom: 5,
    paddingTop: 10,
    paddingLeft: 25,
    color:"#172A44",
    fontSize:24
  },
  mainDiv: {
    display: "flex",
    flexDirection: "column",
    height: "100%",
    padding: 25,
    paddingTop: 15,

    fontFamily: "Proxima Nova",
  },

  Footer: {
    margin: "0px 20px 20px 20px",
  },
  list: {
    width: "100%",
  },
  primary: {
    fontFamily: "Proxima Nova",
    paddingLeft: 3,
    fontWeight: "bold",
    fontSize: "16px",
    lineHeight: "38px",
    color: "#172A44",
  },

  icon: {
    position: "absolute",

    top: 0,
    right: "10vw",
  },

  AvatarContainer: {
    display: "flex",
    justifyContent: "space-between",
    flexDirection: "row",
    width: "100%",
    padding: 10,
  },
  Avatar: {
    display: "flex",
    alignItems: "center",
  },

  priceMain: {
    fontFamily: "Proxima Nova",
    fontWeight: "bold",
    fontSize: "24px",
    color: "#F73B3B",
    marginRight: 10,
  },
  priceStrike: {
    fontSize: "16px",
    lineHeight: "29px",

    color: "#747F8F",
  },

  label: {
    fontFamily: "Proxima Nova",
    fontSize: "16px",
    fontWeight: "bold",
    color: "#172A44",
  },
  banner: {
    width: "100%",
    paddingBottom: "56.6%",
    borderRadius: "22px",
    position: "relative",
  },
  bannerName: {
    position: "absolute",
    bottom: 0,
    fontSize: 18,
    fontWeight: "bold",
    background: "rgba(0,0,0,0.5)",
    padding: "10px 0px 10px 0px",
    borderRadius: "22px",
    color: "white",
    width: "100%",
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
  },
  content: {
    lineHeight: "24px",
    color: "#172A44",
    whiteSpace: "pre-wrap",
  },
}));

export default function Screen2(props) {
  const classes = useStyles();
  const createProgram = () => {
    if (props.editMode) {
      props.saveProgram({...props.ProgramDetails}).then((program) => {
        props.updateFeedback({
          loading: false,
          snackbar: true,
          message: "Program updated succesfully",
          severity: "success",
        });
        props.history.push("/instructor");
      });
    
    } 
    
    
    else {
      props.createProgram(props.ProgramDetails).then((program) => {
        props.updateFeedback({
          loading: false,
          snackbar: true,
          message: "Program created succesfully",
          severity: "success",
        });
        props.history.push("/instructor");
      });
    }
  };

  let {
    Title,
    Description,
    BannerImage,
    Category,
    Benifits,
    Requirements,
    GreetingMessage,
  } = props.ProgramDetails;

  return (
    <Container>
      <Header button={<Button>Publish</Button>} />

      <Content>
        <h2 className={classes.title}>Workout Overview</h2>

        <div className={classes.mainDiv}>
          <div
            className={classes.banner}
            style={{
              backgroundImage: props.ProgramDetails.BannerImage
                ? `url(${props.ProgramDetails.BannerImage})`
                : `url(${require("assets/img/fitness.jpg")})`,
              backgroundSize: "cover",
            }}
          >
            <div className={classes.bannerName}>{Title}</div>
          </div>

          <div className={classes.AvatarContainer}>
            <div className={classes.Avatar}>
              <Avatar
                src={props.Profile.profilePic}
                style={{ width: 30, height: 30 }}
              />
              <span style={{ textTransform: "capitalize" }}>
                &nbsp;{props.Profile.name}
              </span>
            </div>

            <div className={classes.Price}>
              <span className={classes.priceMain}>
                $
                {Math.trunc(
                  props.ProgramDetails.Price - props.ProgramDetails.Discount
                )}
                <sup>
                  &nbsp;.
                  {Math.round(
                    ((
                      props.ProgramDetails.Price - props.ProgramDetails.Discount
                    ).toFixed(2) -
                      Math.trunc(
                        props.ProgramDetails.Price -
                          props.ProgramDetails.Discount
                      )) *
                      100
                  ) == 0
                    ? "00"
                    : Math.round(
                        ((
                          props.ProgramDetails.Price -
                          props.ProgramDetails.Discount
                        ).toFixed(2) -
                          Math.trunc(
                            props.ProgramDetails.Price -
                              props.ProgramDetails.Discount
                          )) *
                          100
                      )}
                </sup>
              </span>
              <span className={classes.priceStrike}>
                <strike>${props.ProgramDetails.Price}</strike>
              </span>
            </div>
          </div>

          <Grid container spacing={2} style={{ marginTop: 10 }}>
            <Grid item xs={12}>
              <div className={classes.label}>Description</div>
              <p className={classes.content}>{Description}</p>
            </Grid>
            <Grid item xs={12}>
              <div className={classes.label} style={{ marginBottom: 10 }}>
                Category
              </div>
              <div style={{ display: "inline" }}>
                {Category.map((item) => {
                  return (
                    <Button
                      bold
                      variant="contained"
                      size="sm"
                      style={{ marginRight: 5 }}
                    >
                      {item}
                    </Button>
                  );
                })}
              </div>
            </Grid>
            <Grid item xs={12}>
              <div className={classes.label}>Benifits</div>
              <p className={classes.content}>{Benifits}</p>
            </Grid>
            <Grid item xs={12}>
              <div className={classes.label}>Requirments</div>
              <p className={classes.content}>{Requirements}</p>
            </Grid>
            <Grid item xs={12}>
              <div className={classes.label} style={{ marginBottom: 10 }}>
                Invitation
              </div>
              <div style={{ display: "inline" }}>
                <Button
                  bold
                  variant="contained"
                  size="sm"
                  style={{ marginRight: 5 }}
                >
                  m.galeziowski
                </Button>
                <Button
                  bold
                  variant="contained"
                  size="sm"
                  style={{ marginRight: 5 }}
                >
                  s.khaled
                </Button>
              </div>
            </Grid>
            <Grid item xs={12}>
              <div className={classes.label}>Greeting message</div>
              <p className={classes.content}>{GreetingMessage}</p>
            </Grid>
          </Grid>
        </div>
      </Content>
      <Footer actionButton>
        <Button
          onClick={createProgram}
          variant="contained"
          fullWidth
          size="lg"
          bold
          startIcon={<span style={{ marginLeft: 10 }}></span>}
          sideIcons
          endIcon={<ArrowRight />}
        >
          Publish
        </Button>
      </Footer>
    </Container>
  );
}
