export default function Screen2(props) {
  const classes = useStyles();
const [open,close]=useState(false)
let [data,setData]=useState(props.Onboarding.bodyImages)

let saveData=()=>{
    props.updateOnboarding({bodyImages:data}).then(res=>{
        props.history.replace("/profile/profile-preview")
      })
}
  return (
    <Container>
      <Header />

      <Content>
      
        
    
        <div className={classes.mainDiv}>
        <div>
   <UploadCard  files={data} sm Title={""} Icon={(cls)=><Camera color="primary" style={{fontSize:40}}/>}  handleUpdate={(files)=>setData(files)} />
    </div>
        </div>
      </Content>
      <Footer actionButton>
        <Button
        onClick={()=>saveData()}
          variant="contained"
          fullWidth
          size="lg"
          bold
          startIcon={<span style={{ marginLeft: 10 }}></span>}
          sideIcons
          endIcon={<ArrowRight />}
        >
          Save
        </Button>
      </Footer>
    </Container>
  );
}
