import React, { Component } from 'react'
import { Router, Route, Switch,Redirect } from "react-router-dom";
import Home from "../Screens/instructorTabs/Home"
import ExerciseAlbum from "../Screens/instructorTabs/ExerciseMain"
import ExerciseList from "../Screens/instructorTabs/ExerciseItemMain"
import Feedback from "../Screens/instructorTabs/Feedback"
import Notification from "../Screens/instructorTabs/Notification"
import SelectProgram from "../Screens/instructorTabs/SelectProgramToSell"
import {connect} from "react-redux"
import {getChatUsers} from "../store/actions/chat"
import {getClients} from "store/actions/clientExercise"
import {updateProgram,getAllPrograms,deleteProgram} from "../store/actions/createProgram"

class CreateProgram extends Component {
    render() {
        return (
            <div>
            
                   <Route exact  path={`${this.props.match.path}/`} render={()=><Home {...this.props} tab={0} />} />
                   <Route
          exact
          path={`${this.props.match.path}/view/:val`}
          render={(props) => (
            <Home
              {...this.props}
              setState={(data) => this.setState(data)}
              tab={props.match.params.val}
            />
          )}
        />
                   <Route exact  path={`${this.props.match.path}/exercise-album`} render={()=><ExerciseAlbum {...this.props}/>} />
                   <Route exact  path={`${this.props.match.path}/exercise-list`} render={()=><ExerciseList {...this.props}/>} />
                   <Route exact  path={`${this.props.match.path}/feedback`} render={()=><Feedback {...this.props}/>} />
                   <Route exact  path={`${this.props.match.path}/notification`} render={()=><Notification {...this.props}/>} />
                   <Route exact path={`${this.props.match.path}/SelectProgram/:type`} render={()=><SelectProgram {...this.props}/>}/>
                 
            </div>
        )
    }
}

const mapStateToProps =(state) => {
    return {
        ProgramDetails:state.NewProgram,
        ProgramList:state.ProgramList,
        Notifications:state.Notifications.Notifications,
        Chat:state.Chat
    }
}

export default connect(mapStateToProps,{updateProgram,getAllPrograms,getClients,deleteProgram,getChatUsers})(CreateProgram)