import React, { Component } from "react";

import ReactDOM from "react-dom";
import { createBrowserHistory } from "history";
import { Router, Route, Switch, Redirect } from "react-router-dom";
import { hydrate, render } from "react-dom";
import Backdrop from "@material-ui/core/Backdrop";
import CircularProgress from "@material-ui/core/CircularProgress";
import Snackbar from "@material-ui/core/Snackbar";
import Alert from "@material-ui/lab/Alert";
import { updateFeedback } from "store/actions/feedback";
import Screen13 from "./Screens/accountSettings/Screen13.js";
import Screen14 from "./Screens/accountSettings/Screen14.js";
import Screen15 from "./Screens/accountSettings/Screen15.js";
import Screen16 from "./Screens/accountSettings/Screen16.js";
import Onboarding from "./containers/Onboarding.js";
import AccountSettings from "./containers/AccountSettings";
import Profile from "./containers/Profile";
import CreateProgram from "./containers/CreateProgram";
import EditProgram from "./containers/EditProgram";
import SelectProgram from "./containers/SelectProgram";
import InstructorTabs from "./containers/InstructorTabs";
import Common from "./containers/Common";
import ClientView from "./containers/ClientViewInstructor";
import Components from "views/Components/Components.js";
import ResetPassword from "./containers/PasswordReset";
import FiggsLibrary from "./containers/FiggsLibrary";
import PublicScreens from "./containers/PublicScreens";
import { store, persistor } from "./store";
import { MuiThemeProvider, createMuiTheme } from "@material-ui/core";
import { Provider } from "react-redux";
import { PersistGate } from "redux-persist/integration/react";
import { connect } from "react-redux";
import requireLogin from "utils/requireLogin";
import ClientTabs from "./containers/clientTabs";
import DailyExercise from "./containers/AthleteDailyExercise.js";
import socketIOClient from "socket.io-client";
import SocketContext from "context/SocketContext";
import Chat from "containers/Chat"
import {fetchNotification} from "store/actions/Notifications"
import {socketConnection} from "store/actions/common"
import api from "utils/api";
import "./index.css";
var hist = createBrowserHistory();

class Routes extends Component {
  state = { socket: null };

  componentDidMount = () => {
    if (this.props.token) {
    socketConnection()
    }
    // var socket= socketIOClient(`http://localhost:3001/${this.props._id}`)
    // socket.on('hi',function(data) {

    // });

    // if (this.props.token) {
    //   const socket = socketIOClient(`http://localhost:3001`, {
    //     query: "token=" + this.props._id,
    //   });

    //   socket.on("connect", () => {});

    //  socket.on(this.props._id,(data)=>{
      
         
    //      if(data.type=="new-notification" )
    //    { 
         
    //     fetchNotification()

 
        
        
    //     }
        
    //   })

    //   this.setState({ socket: socket });
    // }
  };

  handleClose = () => {
    this.props.updateFeedback({ snackbar: false });
  };

  render() {
    const { snackbar, message, severity, loading } = this.props.Feedback;
    let socket = this.props.socket;
    return (
      <>
        <SocketContext.Provider value={socket}>
          <Snackbar
            open={snackbar}
            autoHideDuration={6000}
            onClose={this.handleClose}
            anchorOrigin={{ vertical: "top", horizontal: "center" }}
          >
            <Alert
              onClose={this.handleClose}
              severity={severity}
              elevation={6}
              variant="filled"
            >
              {message}
            </Alert>
          </Snackbar>

          <Backdrop style={{ zIndex: 2500, color: "#fff" }} open={loading}>
            <CircularProgress color="inherit" />
          </Backdrop>

          <Router history={hist}>
            {!this.props.token && (
              <Switch>
                <Route exact path="/" component={Onboarding} />
                <Route  path="/resetpassword" component={ResetPassword}/>
                <Route path="/onboarding" component={Onboarding} />
                <Route path="/public" component={PublicScreens}/>
                <Redirect from="*" to="/" component={Components} />
              </Switch>
            )}

            {this.props.token && this.props.type == "Athlete" ?
              <Switch>
 

                <Route path="/public" component={PublicScreens}/>
                <Route path="/profile" component={requireLogin(Profile)} />
                <Route path="/common" component={Common} />

                <Route path="/resetPassword" component={ResetPassword} />
                  <Route path="/chat" component={Chat} />
                <Route path="/daily-exercise" component={DailyExercise} />

         

                <Route path="/athlete" component={ClientTabs} />

                <Route path="/create-program" component={CreateProgram} />

          
                <Route path="/library" component={FiggsLibrary} />
                <Route path="/clientView/:id" component={ClientView} />

                <Route path="/account-settings" component={AccountSettings}/>
                <Route path="/reset-password" component={ResetPassword}/>
                <Route path="/ui-kit" component={Components} />
                <Redirect from="*" to="/athlete" component={Components} />
              </Switch>
         :this.props.token&&
              <Switch>
                
                <Route path="/profile" component={requireLogin(Profile)} />
                <Route path="/common" component={Common} />
                <Route path="/chat" component={Chat} />
                <Route path="/resetPassword" component={ResetPassword} />

                <Route path="/daily-exercise" component={DailyExercise} />

                <Route
                  path="/edit-program/:id"
                  render={(props) => <EditProgram {...props} editMode />}
                />
<Route 
path="/sendProgram"
component={SelectProgram}
/>
<Route 
path="/sendProgramTo/:figgsID/:userId/:returnIndex"
component={SelectProgram}
/>
                <Route path="/create-program" component={CreateProgram} />
                <Route path="/public" component={PublicScreens}/>
                <Route path="/instructor" component={InstructorTabs} />
                <Route path="/library" component={FiggsLibrary} />
                <Route path="/clientView/:id" component={ClientView} />
                 <Route path="/account-settings" component={AccountSettings}/>
                <Route path="/ui-kit" component={Components} />
                <Route path="/reset-password" component={ResetPassword}/>
                <Redirect from="*" to="/instructor" component={Components} />
              </Switch>
            
            
            }
          </Router>
        </SocketContext.Provider>
      </>
    );
  }
}
const mapStateToProps = (state) => {
  return {
    type: state.Profile.type,
    _id: state.Profile._id,
    token: state.Profile.token,
    Feedback: state.Feedback,
    socket:state.Common.socket
  };
};
export default connect(mapStateToProps, { updateFeedback })(Routes);
