import React from "react";
// nodejs library to set properties for components
import PropTypes from "prop-types";
// nodejs library that concatenates classes
import classNames from "classnames";
import DietIcon from "assets/svg/DietIcon";
// @material-ui/core components
import makeStyles from "@material-ui/core/styles/makeStyles";
import Avatar from "@material-ui/core/Avatar";
import MoreHorizIcon from "assets/svg/MoreIcon";
import IconButton from "@material-ui/core/IconButton";
import AddIcon from "assets/svg/AddIcon";
import MoreHorizIcon2 from "assets/svg/MoreIcon";
import CameraAddIcon from "assets/svg/CameraAdd"
import Dumbell from "assets/svg/Dumbell"
const makeComponentStyles = makeStyles(() => ({
  mainDiv: {
    borderRadius: "22px",
    fontFamily: "Proxima Nova",
    background: "#fff",
    border: "3px solid rgba(0, 126, 160, 0.2)",
    paddingBottom: "105%",
    position: "relative",
  },

  white: {
    background: "#fff",
    boxShadow:
      "15px 15px 35px rgba(112, 124, 151, 0.05), 10px 10px 25px rgba(112, 124, 151, 0.05)",
    border: "1px solid rgba(112, 124, 151, 0.1)",
    boxSizing: "border-box",
  },
  content: {
    width: "100%",

    display: "flex",
    flexDirection: "row",
    justifyContent: "space-between",
    alignItems: "center",
  },

  childDiv: {
    top: 0,
    left: 0,
    bottom: 0,
    width: "100%",
    height: "100%",
    display: "flex",
    flexDirection: "column",
    justifyContent: "space-between",
    position: "absolute",
    borderRadius: "22px",
    overflow: "hidden",
  },

  icon: {
    fontSize: 60,
  },
  title: {
    color: "#172A44",

    fontSize: "16px",
    fontWeight: "500",
    lineHeight: "16px",
    padding: 12,
    marginTop: 5,
    paddingBottom: 0,
    textOverflow: "ellipsis",
    overflow: "hidden",
    whiteSpace: "nowrap",
  },

  subTitle: {
    color: "#172A44",
    fontWeight: 500,
    paddingLeft: 12,
    fontSize: "14px",
    lineHeight: "16px",
    textOverflow: "ellipsis",
    overflow: "hidden",
    whiteSpace: "nowrap",
    textTransform: "capitalize",
  },

  image: {
    width: "100%",

    position: "relative",
    paddingTop: "66.6%",
    display: "flex",
    justifyContent: "center",
    borderRadius: "16px",
  },
  buttonAdd: {
    width: "100%",

    position: "relative",
    height: "100%",

    borderRadius: "22px",
  },
  insideIcon: {
    position: "absolute",
    top: 0,
    height: "100%",
    width: "100%",
    display: "flex",
    flexDirection: "column",
    justifyContent: "center",
    alignItems: "center",
    background: "#fff",
    borderRadius: "22px",
  },
  iconMore: {
    paddingTop: 10,
    paddingRight: 12,
    paddingLeft: 0,
  },
  data: {
    /* or 161% */

    color: "#F73B3B",
    fontWeight: "bold",
    fontSize: "18px",
    lineHeight: "28px",
  },
  sub: {
    fontWeight: "bold",
    fontSize: "14px",
    lineHeight: "28px",
    textDecorationLine: "line-through",
    marginLeft: 10,
    color: "#CECECE",
  },
  BackgroundChange: {
    backgroundColor: "rgba(236, 238, 239, 0.5)",
  },
  ExerciseCount: {
    background: "#FFFFFF",
    border: "0.5px solid #172A44",
    boxSizing: "border-box",
    borderRadius: "12px",
    padding: "5px 10px 5px 10px",

    position: "absolute",
    bottom: 10,
    fontSize: 14,
    color: "#172A44",
  },
  InfoBack: {
    position: "absolute",
    top: 10,
    textAlign: "center",
    paddingLeft: 5,
    paddingRight: 5,
    fontSize: 14,
    color: "rgba(23, 42, 68, 0.5)",
  },

  div1: {
    flex: 2.7,
    display: "flex",
    flexDirection: "column",
    justifyContent: "center",
    alignItems: "center"
  },
  div2: {
    flex: 3,
    background: "rgba(0,0,0,0.25)",
    display: "flex",
    flexDirection: "column",
    padding:15,
    paddingTop:10,
    paddingBottom:10,
    justifyContent: "space-between"
  },
  ImgTitle:{
    color: "#fff",
    fontFamily: "Proxima Nova",
    fontSize:16,
   alignItems:"center",
    display: "flex",
    flexDirection: "row",
    textShadow: "0px 4px 4px rgba(0, 0, 0, 0.5)",
    justifyContent: "space-between",
  },
  imgText:{
    color: "#fff",
    fontFamily: "Proxima Nova",
    fontSize:16,
    display: "flex",
    textShadow: "0px 4px 4px rgba(0, 0, 0, 0.5)",
    flexDirection: "row",
   fontWeight:"bold",
   
   textTransform:"capitalize"

  },
  imgExercise:{
    color: "#fff",
    display: "flex",
    flexDirection: "row",
    fontFamily: "Proxima Nova",
    fontSize:16,
    alignItems:"center"
  
   
  }

}));

const AnnouncCard = React.forwardRef((props, ref) => {
  const {
    selected,
    Title,
    Text,
    Icon,
    Time,
    white,
    Image,
    exercise,
    length,
  } = props;
  const classes = makeComponentStyles();
  const mainDiv = classNames({
    [classes.mainDiv]: true,
  });

  const icon = classNames({
    [classes.icon]: true,
    [classes.selected]: selected,
  });

  const title = classNames({
    [classes.title]: true,
    [classes.selected]: selected,
  });

  const subtitle = classNames({
    [classes.subTitle]: true,
  });

  const childDiv = classNames({
    [classes.childDiv]: true,
    [classes.BackgroundChange]: props.length > 0,
  });

  return (
    <div className={mainDiv} onClick={props.noDots&&props.onClickContainer}>
      <div
        className={childDiv}
        style={
          Image ? {
          
            backgroundImage: `url(${Image})`,
            backgroundSize: "cover",
          }:length?{
            backgroundColor:"rgba(0,126, 160,0.75)",
          }:{}
        }
      >
        {Image || length ? (
          <>
            <div className={classes.div1}   onClick={(e) =>{e.stopPropagation();props.onClickMore()}}>
{!Image&&<>
<CameraAddIcon style={{fontSize:28,color:"white"}}/>
<div style={{color:"white",fontFamily:"Proxima Nova",marginTop:5,fontSize:14}}>background</div>
</>}
            </div>

            <div className={classes.div2} onClick={props.onClickAdd}>
              <div className={classes.ImgTitle}>
                {" "}
                {Title}{" "}
                {!props.noDots&&<MoreHorizIcon
                onClick={(e) =>{e.stopPropagation();props.onClickMore()}}
                  style={{
                    color: "#fff",
                    width:27,
                    height:6
                
                  }}
                />}{" "}
              </div>
              <div className={classes.imgText}> {Text}</div>
              <div className={classes.imgExercise}><Dumbell style={{marginRight:5}}/> {" "+props.length }</div>
            </div>
          </>
        ) : (
          <>
            <div>
              <div className={classes.content}>
                <div className={title}>
                  {Title}&nbsp;
                  <br />
                </div>

                <div className={classes.iconMore} onClick={props.onClickMore}>
                 {!props.noDots&& <MoreHorizIcon
                    style={{
                      color: "rgba(23, 42, 68, 0.6)",
                      width:18,
                      height:4
                    }}
                  />}
                </div>
              </div>

              {Text ? (
                <div
                  className={classes.subTitle}
                  style={{ fontSize: 16, color: "#172A44" }}
                >
                  {" "}
                  {Text}
                </div>
              ) : (
                ""
              )}
            </div>

            <div
              style={
                !length
                  ? {
                      display: "flex",
                      flexDirection: "column",
                      justifyContent: "center",
                      alignItems: "center",
                      height: "100%",
                      width: "100%",
                    }
                  : { padding: 5 }
              }
            >
              <div
                className={length ? classes.image : classes.buttonAdd}
                onClick={props.onClickAdd}
                style={
                  Image && {
                    backgroundImage: `url(${Image})`,
                    backgroundSize: "cover",
                  }
                }
              >
                {length ? (
                  <div className={classes.ExerciseCount}>
                    {props.length + " " + "Exercises"}
                  </div>
                ) : null}

                {/* {!Image&&length?<div className={classes.InfoBack}>No background Image</div>:null} */}

                {props.icon && (
                  <div className={classes.insideIcon}>
                    <IconButton
                      onClick={props.onClickAdd}
                      style={{
                        background: "#F9FCFD",
                        borderRadius: 12,
                        height: 48,
                        width: 48,
                        border: "0.5px solid rgba(0, 126, 160, 0.5)",
                        padding: 0,
                        boxSizing: "border-box",
                      }}
                    >
                      <AddIcon color="primary" style={{ fontSize: 18 }} />
                    </IconButton>
                    <div
                      style={{
                        fontWeight: "normal",
                        color: !exercise ? "rgba(0, 126, 160, 0.5)" : "#172A44",
                        fontSize: 14,
                        marginTop: 10,

                        borderRadius: 12,
                        padding: "5px 8px 5px 8px",
                        textAlign: "center",
                      }}
                    >
                      {exercise ? exercise + " Exercises" : 0 + " Exercises"}
                    </div>
                  </div>
                )}
              </div>
            </div>
          </>
        )}
      </div>
    </div>
  );
});

export default AnnouncCard;
