const useStyles = makeStyles((theme) => ({
 
  title: {
    fontFamily: "Proxima Nova",
    fontWeight: "700",
    marginBlockStart: 0,
    marginBottom: 5,
paddingTop:10,
    paddingLeft: 25,
    fontSize:24,
    color:"#172A44"
  },
  mainDiv: {
    display: "flex",
    flexDirection: "column",
    height: "100%",
    padding: 25,
    paddingTop:15,
   

    fontFamily: "Proxima Nova",
  },
 
 

  Footer: {
    margin: "0px 20px 20px 20px",
  },
  list:{
    width: '100%',
  },
  primary:{
    fontFamily: "Proxima Nova",
   paddingLeft:3,
       fontWeight: "bold",
       fontSize: "16px",
       lineHeight: "38px",
       color: "#172A44"
  },
  
  image:{
width:"100%",
paddingTop:"60%",
borderRadius: 16,
backgroundColor:"grey"
  },

  icon:{
position: "absolute",

top:0, 
right:"10vw"
  },
 
  Avatar:{
      position:"absolute",
      bottom:-25,
      width:60,
      height:60,
      left:30
  },
 
  label:{
    fontFamily:"Proxima Nova",
fontSize:"16px",
fontWeight: "bold",
color: "#172A44",
display:"flex",
flexDirection:"row",



  },
  prDetails:{
    fontFamily:"Proxima Nova",
    color: "#172A44",
    fontSize: "18px",
  padding:15,
  fontWeight: "bold",
  lineHeight:"19px",
   

  }
  ,
 Divider:{
backgroundColor:"#E8EAEC",
height:0.5
  }
}));

export default function Screen2(props) {
  const classes = useStyles();

  const createProgram = () => {
    if (props.mode=="edit") {
      props.saveProgram({...props.ProgramDetails}).then((program) => {
 
        props.updateFeedback({
          loading: false,
          snackbar: true,
          message: "Program updated succesfully",
          severity: "success",
        });
        props.history.push("/instructor");
      });
    
    } 
    
    
    if(props.mode=="editSend"){
      props
      .sendProgram({
      ...props.ProgramDetails,
      
      })
      .then((program) => {
        props.updateFeedback({
          loading: false,
          snackbar: true,
          message: "Program sent succesfully",
          severity: "success",
        });
        if(props.returnIndex&&(props.returnIndex-props.history.length)-1<-4)
        props.history.go(`${(props.returnIndex-props.history.length)-1}`)
        else
        props.history.push("/instructor");
      });
    }


    if(!props.mode)
    {
      props.createProgram(props.ProgramDetails).then((program) => {

        props.updateFeedback({
          loading: false,
          snackbar: true,
          message: "Program created succesfully",
          severity: "success",
        });
        props.history.push("/instructor");
      });
    }
  };

  return (
    <Container>
      <Header  />

      <Content flex>
        <h2 className={classes.title}>Overview</h2>
      
        <div className={classes.mainDiv}>

      
       <Grid container spacing={1} justify="center" alignItems="center">
       {props.mode!=="edit"&&props.ProgramDetails.SendTo.length>0&&
       
       <Grid item xs={12}>
            <div className={classes.label}>To</div>
       <ChipInput
    
       fullWidth
       defaultValue={[...props.ProgramDetails.SendTo]}
    
       disabled
       
       
       />
       <Divider className={classes.Divider} style={{ marginTop:20}}/>
       </Grid>}

 
<Grid item xs={12} style={{ marginTop:20}} >
<span className={classes.label}>
  Program
</span>


<Grid container style={{marginTop:15}} >
  <Grid item xs={5}>
<div className={classes.image} style={{backgroundImage:`url(${props.ProgramDetails.BannerImage?props.ProgramDetails.BannerImage:"https://img.freepik.com/free-photo/athletes-floor-dumbbell-lift-with-one-hand_94347-858.jpg?size=626&ext=jpg"})`,backgroundSize: "cover"}}></div>
  </Grid>
  <Grid item xs={7}>
  <div className={classes.prDetails}>
{props.ProgramDetails.Title}
</div>
    </Grid>
</Grid>
<Divider className={classes.Divider} style={{ marginTop:20}}/>
  </Grid>
  {   (props.ProgramDetails.Price!==null&&Number(props.ProgramDetails.Price)>0)&&
<Grid item xs={12} style={{ marginTop:20}}>
<span className={classes.label}>
  Payments
</span>

<Grid container style={{marginTop:15}} >
  <Grid item xs={12} style={{display:"flex"}}>
<Typography style={{color: "#172A44",size:16}}>Price :</Typography>&nbsp;  <Typography color={"primary"}>$ {props.ProgramDetails.Price}</Typography>
  </Grid>

  <Grid item xs={12} style={{display:"flex",marginTop:5}}>
  <Typography style={{color: "#172A44",size:16}}>Type :</Typography>&nbsp;  <Typography color={"primary"}>{props.ProgramDetails.PaymentType}</Typography>
    </Grid>


</Grid>
<Divider className={classes.Divider} style={{ marginTop:20}}/>
  </Grid>}

  <Grid item xs={12} style={{ marginTop:20}} >

  <div className={classes.label}>Message</div>
  
  <Typography style={{color: "#172A44",size:16,marginTop:15}}>
  {props.ProgramDetails.GreetingMessage}
  </Typography>

{/* <CustomInput
                
                labelText="Message"
                multiline={true}
                bottomUnderline
                rows={4}
               
                formControlProps={{
                 
                  fullWidth: true
                }}
                inputProps={{
                  style:{marginTop:10,color},
                  value:props.ProgramDetails.GreetingMessage,
                  onChange:(e)=>props.updateProgram({GreetingMessage:e.target.value}),
                    multiline: true,
                    rows:4,
                  placeholder:"This is the message that user will get from you after buying your program.",
               
                }}
              /> */}
              <Divider className={classes.Divider} style={{ marginTop:20}}/> 
</Grid>



 </Grid>
        </div>
      </Content>
      <Footer actionButton>
   
        <Button
      onClick={createProgram}
          variant="contained"
          fullWidth
          size="lg"
          bold
        
        >
              {props.mode=="edit"?"Save": props.mode=="editSend"?"Send":"Publish"}
        </Button>
   
      </Footer>
    </Container>
  );
}
