import React from "react";
// nodejs library to set properties for components
import PropTypes from "prop-types";
// nodejs library that concatenates classes
import classNames from "classnames";
import DietIcon from "assets/svg/DietIcon"
// @material-ui/core components
import makeStyles from "@material-ui/core/styles/makeStyles";
import Avatar from "@material-ui/core/Avatar"

const makeComponentStyles = makeStyles(() => ({
  mainDiv: {
    position: "relative",
    width: "98%",
paddingTop: "42%",
borderRadius:"22px",
fontFamily:"Proxima Nova",

 borderRadius:22,


  },

  white:{
    background:"#fff",
    boxShadow: "15px 15px 35px rgba(112, 124, 151, 0.05), 10px 10px 25px rgba(112, 124, 151, 0.05)",
    border: "1px solid rgba(112, 124, 151, 0.1)",
boxSizing: "border-box",
  }
,
  content:{
      
      display:"flex",
      flex:8,
      flexDirection: "column",
      alignItems:"flex-start",
      justifyContent:"space-around",
      padding:25,
      paddingBottom:15,
      paddingTop:30,
      fontSize: "14px"
     
  },


  childDiv:{
    position:  "absolute",
    top: 0,
    left: 0,
    bottom: 0,
    width: "100%",
    height: "100%",
    display:"flex",
    flexDirection:"row",
 
    borderRadius:"22px"
    
    
  },

 icon:{
  position:"absolute",
top:8,
zIndex:1000,
right:8
 },
  title:{ 
     
    color: "#707C97",
      fontWeight:"normal",
    
      fontSize: "14px",
lineHeight: "20px",

    },

    subTitle:{
        color: "#172A44",
        fontWeight:"bold",
      
        fontSize: "16px",
  lineHeight: "20px",
    
    },

  image:{
   
    margin:5,
    display: "flex",
    flexDirection:"row",
    flex:7,
     background:"grey",
     borderRadius:"22px",
     position:"relative",
    
    
  },

data:{
    color: "#172A44",
     
      
        fontSize: "14px",
  lineHeight: "20px",
}
,
rowElement:{
  display:"flex",
  flexDirection:"row",
},
index:{
  position:"absolute",
  top:0,
  right:0,
width:30,
height:30,
alignItems:"center",
background: "rgba(0, 126, 160, 0.75)",
boxShadow: "0px 17px 31px rgba(0, 126, 160, 0.1)",
 fontWeight: "bold",
 color:"#fff",
 display: "flex",
 flexDirection: "row",
 justifyContent:"center",
  borderRadius:"50%"
},
Detail:{
  fontSize:16,
  fontFamily: "Proxima Nova",
  color:"#172A44"
}

}));

const AnnouncCard = React.forwardRef((props, ref) => {

const {selected, 
Title, 
Text, 
Icon,
Time,
white,
Images

}=props
  const classes = makeComponentStyles();
  const mainDiv=classNames({
    [classes.mainDiv]: true,

})
  
    const icon=classNames({
[classes.icon]: true,
[classes.selected]: selected
    })

    const title=classNames({
        [classes.title]: true,
        [classes.selected]: selected
    })

    const subtitle=classNames({
        [classes.subTitle]: true,
 
    })
  
  return (
  
     <div className={mainDiv}>
     <div className={classes.index}>{props.index}</div>
         <div className={classes.childDiv} onClick={props.onClick}>
         <div className={classes.image} style={{backgroundImage:props.banner?`url(${props.banner})`:`url(https://img.freepik.com/free-photo/athletes-floor-dumbbell-lift-with-one-hand_94347-858.jpg?size=626&ext=jpg)`,backgroundSize: "cover"}} >
         <div className={classes.icon} onClick={e=>e.preventDefault()}>{Icon}</div>
</div>

         <div className={classes.content} >
<div  style={{fontSize:18,textTransform:"capitalize" ,marginBottom:6,width: "90%"}}>
 <b>{props.title}</b>

</div>
<div className={classes.Detail} >
Repetition : <b>{props.reps?props.reps:"-"}</b>

</div>
<div className={classes.Detail} >
Sets : <b>{props.sets?props.sets:"-"}</b>

</div>
<div className={classes.Detail} >
Rest : <b>{props.rest?props.rest:"-"}s</b>

</div>


          
</div>
         </div>

     </div>


 
  );
});


export default AnnouncCard;
