export default function Screen2(props) {
  const classes = useStyles();
const [open,close]=useState(false)
  return (
    <Container>
      <Header button={<Button>Skip</Button>} />

      <Content>
        <br/>
        
        <span className={classes.title}>Create description</span>
        <div className={classes.Banner}>
            <Camera className={classes.bannerIcon}/>
        <Avatar className={classes.Avatar}>

        </Avatar>
        </div>
        <div className={classes.mainDiv}>
       <Grid container spacing={0}>
<Grid item xs={12}>
<CustomInput
                        labelText="Username"
                        id="float"
                      
        inputProps={{
          
            placeholder:"Username"
           
        }}
                        formControlProps={{
                          fullWidth: true,
                          
                        }}
                      />
</Grid>
<Grid item xs={12}>
<CustomInput
                        labelText="Location"
                        id="float"
        inputProps={{
         
            placeholder:"Your current location"
           
        }}
                        formControlProps={{
                          fullWidth: true,
                          
                        }}
                      />
</Grid>
<Grid item xs={12}>
<CustomInput
                        labelText="Category"
                        id="float"
        inputProps={{
            type: "number",
            placeholder:"fitness category"
           
        }}
                        formControlProps={{
                          fullWidth: true,
                          
                        }}
                      />
</Grid>

<Grid item xs={12}>
<CustomInput
                        labelText="Instructor Bio"
                        id="float"
        inputProps={{
            placeholder:"Small brief about yourself"
           
        }}
        multiline
        rows={4}
                        formControlProps={{
                          fullWidth: true,
                          
                        }}
                      />
</Grid>

<Grid item xs={12}>
<CustomInput
                        labelText="Website"
                        id="float"
        inputProps={{
          
           placeholder:"www.example.com"
        }}
                        formControlProps={{
                          fullWidth: true,
                          
                        }}
                      />
</Grid>


<Grid item xs={12}>
<CustomInput
                        labelText="Link"
                        id="float"
        inputProps={{
            placeholder:"Link to page"
           
        }}
                        formControlProps={{
                          fullWidth: true,
                          
                        }}
                      />
</Grid>
{/* <Grid item xs={12}>
<Typography variant="h6" color="primary" style={{fontWeight:700}}>View private information </Typography>
</Grid> */}
       </Grid>
        </div>
      </Content>
      <Footer actionButton>
        <Button
        
          variant="contained"
          fullWidth
          size="lg"
          bold
          startIcon={<span style={{ marginLeft: 10 }}></span>}
          sideIcons
          endIcon={<ArrowRight />}
        >
          Continue
        </Button>
      </Footer>
    </Container>
  );
}
