const useStyles = makeStyles(
    {
        primary: {
            fontSize:18,
            fontFamily: "Proxima Nova",
            lineHeight: "29px",
            color:"#172A44"
        },
        secondary:{
          fontSize:18,
          fontFamily: "Proxima Nova",
          lineHeight: "29px",
          color:"grey"
        },

        icon:{
            color:"#172A44"
        }
    }
);

export default function SectionTabs(props) {
  const classes = useStyles();
  const [weeks,setWeek] = useState([])

  const onChange=(checked,index)=>{
  
    let data=[...weeks]
    if(checked){
data.push(index)
setWeek(data)
    }
    else{
      data.splice(data.findIndex(item => item==index),1)
      setWeek(data)
    }
    console.log(weeks)
  }


  return (
 
  
<div style={{backgroundColor:"#fff"}}>
      <List component="nav" aria-label="main mailbox folders">
       

          {props.ProgramDetails&&props.ProgramDetails.ExercisePlan.map((item,index) =>{

            if(index==props.currentWeek){
              return(
                <>
                <ListItem >
                <ListItemText primary={"Week "+(index+1)} classes={{primary: classes.secondary}} />
              
                 
              </ListItem>
              <Divider />
              </>
              )
            }
            else
            {
              return(
              <>
              <ListItem >
              <ListItemText primary={"Week "+(index+1)} classes={{primary: classes.primary}} />
              <ListItemSecondaryAction>
                  <Checkbox
                  rounded={true}
                  checked={props.weeks.findIndex(week => week==index)>-1}
                  onChange={(e)=>props.onChange(e.target.checked,index)}
                  />
                </ListItemSecondaryAction>
            </ListItem>
            <Divider />
            </>
            )
            }
          })}
         
         
        
       
      </List>
      {/* <Divider />
      <List component="nav" aria-label="secondary mailbox folders">
        <ListItem button>
          <ListItemText primary="Trash" />
        </ListItem>
        <ListItem href="#simple-list">
          <ListItemText primary="Spam" />
        </ListItem >
      </List> */}
    </div>
 





      
  );
}
