import React from "react";
import {useRef,useEffect,useState} from "react"
// @material-ui/core components
import { makeStyles } from "@material-ui/core/styles";
import { theme } from "assets/css/theme";


const useStyles = makeStyles((theme) => ({
  root: {
    
   
    position: "fixed",
    bottom:0,
    width: "100%",
    

  },
 
}));
export default function SectionNavbars(props) {
  const classes = useStyles();
  const myRef = useRef(null);
  const [height,setHeight] =useState(0)
 useEffect(() => {
if(myRef.current){
  setHeight(myRef.current.clientHeight)
}
 },[myRef]);

  console.log(height)
  return (
    <div style={{height:props.actionButton?height+20:height}}>
        <div className={classes.root} ref={myRef} {...props} style={props.actionButton?{ backgroundColor: "#fff", marginBottom: 20 }:{}} >

{props.actionButton?<div
          style={{
            marginLeft: theme.padding,
            marginRight: theme.padding,
         
          }}
        >
  {props.children}
</div>:
 props.children
}

           



          </div>
          </div>
  );
}
