export default function Screen2(props) {
  const classes = useStyles();

  const [open,toggle]=useState(false)
  const [selectedDate, setSelectedDate] = React.useState(new Date('2014-08-18T21:11:54'));
  const handleDateChange = (date) => {
    setSelectedDate(date);
  };
  return (
    <Container>
      <Header/>

      <Content>
        <h2 className={classes.title}>Private information</h2>
       
        <div className={classes.mainDiv}>
        <ListItem 
        title="Email"
        value={props.Profile.email?props.Profile.email:""}
        onClick={()=>props.history.push(`/profile/edit-phone-email/email`)}
        />
        <ListItem 
        title="Phone"
        value={props.Profile.phone?"+"+props.Profile.phone:"N/A"}
        onClick={()=>props.history.push(`/profile/edit-phone-email/phone`)}
        bordered/>
         <ListItem 
        title="Gender"
        value={props.Profile.gender?props.Profile.gender:"N/A"}
        onClick={()=>props.history.push(`/profile/update-gender`)}
        bordered/>
         <ListItem 
        title="Date of birth"
        value={props.Profile.DOB?moment(props.Profile.DOB).format('ll'):""}
        onClick={()=>props.history.push(`/profile/edit-dob`)}
        bordered/>
         <ListItem 
        title="Password"
        value="******"
        onClick={()=>props.history.push(`/resetPassword/profile`)}
        bordered/>
        
        </div>
      </Content>
      <Footer actionButton>
        <Button
        onClick={()=>props.history.push('/create-profile-instructor/profile-preview')}
          variant="contained"
          fullWidth
          size="lg"
          bold
          startIcon={<span style={{ marginLeft: 10 }}></span>}
          sideIcons
          endIcon={<ArrowRight />}
        >
          Continue
        </Button>
      </Footer>
    </Container>
  );
}
