export default function Screen2(props) {
  const classes = useStyles();
  const [open,toggle]=useState(false)
  const [selectedDate, setSelectedDate] = React.useState(new Date(props.Profile.DOB));
  const handleDateChange = (date) => {
    setSelectedDate(date);
  
  };

 const handleNext =()=>{
props.updateProfile({DOB:selectedDate}).then(res=>{
  props.history.goBack()
})





}

  
  return (
    <MuiPickersUtilsProvider utils={DateFnsUtils}>
    <Container>
      <Header />

      <Content flex>
        <span className={classes.title}>Update your birthday</span>
        <p className={classes.secondary}>For security make sure to add your birthday. this information will be private for you and wont be shown in public.</p>
        <div className={classes.mainDiv}>
        
        <KeyboardDatePicker
         disableFuture
         openTo="year"
          views={["year", "month", "date"]}
          variant="inline"
          value={selectedDate}
          onChange={handleDateChange}
          format="MM/dd/yyyy"
          margin="normal"
          open={open}
          onClose={()=>toggle(false)}
variant="dialog"
       
       
          
          TextFieldComponent={(props)=> <CustomInput inputProps={{...props, onFocus:()=>toggle(true)
            ,placeholder:"MM/dd/yyyy",
             endAdornment: (
            <InputAdornment position="end" onClick={()=>toggle(true)}>
            <CalendarTodayIcon/>
            </InputAdornment>
          )}}/>}
          KeyboardButtonProps={{
            'aria-label': 'change date',
          }}
        />
      
       
        </div>
      </Content>
      <Footer actionButton>
        <Button
        onClick={handleNext}
          variant="contained"
          fullWidth
          size="lg"
          bold
          startIcon={<span style={{ marginLeft: 10 }}></span>}
          sideIcons
          
        >
         Save
        </Button>
      </Footer>
    </Container>
    </MuiPickersUtilsProvider>
  );
}
