export default function Screen2(props) {
  const classes = useStyles();
  const [value, setValue] = React.useState("");
  useEffect(() => {
    props.getChatUsers()
  },[])
  


  const options = {
    minMatchCharLength:2,
    keys: [
      
      "Message",
      "name"
    ]
  }
  const fuse = new Fuse(props.Chat.recentChatUsers, options);



  let clientsList=value?fuse.search(value):props.Chat.recentChatUsers



  return (
   

      <Content flex>
         
        {/* <h2 className={classes.title}>Message</h2> */}
       
        <div style={{padding:20,paddingBottom:10}}>
        <CustomInput
               
               id="material"
     

               inputProps={{
                style:{ background: "#fafafa"},
                 placeholder: "Search message",
                 value:value,
                 onChange:(e)=>setValue(e.target.value),
                 startAdornment: (
                   <InputAdornment position="start">
                     <SearchIcon style={{color: "rgba(23,42,68,0.3)"}} />
                   </InputAdornment>
                 ),
                 endAdornment: (
                  <>{value?<InputAdornment position="end" onClick={e=>setValue("")}>
                   <CancelIcon />
                 </InputAdornment>:""}</>
                  )
               }}
               formControlProps={{
                 fullWidth: true
               }}
              
             />
       
        </div>
       
        
        <div className={classes.mainDiv}>
         {clientsList.length==0&&<div className={classes.secondary}>
            No message available
          </div>}
      
          {clientsList.map(itemMap =>{

let item=value?itemMap.item:itemMap

console.log(item)
                return(  
                <div style={{borderBottom: '0.5px solid #DDDDDD'}} onClick={()=>props.history.push(`/chat/dt/${item._id}`)}>
                < AnnouncCard  
                    Title={item.name}
                    IconAv={<Avatar src={item.profilePic}  userId={item._id}/>}
                    Text={item.Message?item.Message:"[Attachments]"}
                  Images={[]}
                    />
                    </div>
                    )})} 
              

      
        </div>
      </Content>
    
  );
}
