import {saveProgram} from "store/actions/createProgram"
import DeleteModal from "components/Dialogue/delete";
import {createOrder,getStats} from "store/actions/common"
import { getSpecificProgram } from "store/actions/createProgram";
import EyeButton from "assets/svg/NewIcons/Eye"
import ShareButton from "assets/svg/NewIcons/share"
import SendButton from "assets/svg/NewIcons/send"
const useStyles = makeStyles((theme) => ({
  title: {
    fontFamily: "Proxima Nova",
 
    textTransform: "capitalize",
    fontSize: 18,
    marginBlockStart: 0,
    marginBottom: 15,
    paddingTop: 15,

  },
  mainDiv: {
    padding: 25,
    paddingTop: 0,
    fontFamily: "Proxima Nova",
  },

  Footer: {
    margin: "0px 20px 20px 20px",
    background: "#FAFAFA",
    border: "1px solid #F3F3F3",
  },
  list: {
    width: "100%",
  },
  primary: {
    fontFamily: "Proxima Nova",
    paddingLeft: 3,
    fontWeight: "bold",
    fontSize: "16px",
    lineHeight: "38px",
    color: "#172A44",
  },

  icon: {
    position: "absolute",

    top: 0,
    right: "10vw",
  },

  AvatarContainer: {
    display: "flex",
    justifyContent: "space-between",
    flexDirection: "row",
    width: "100%",
    paddingTop: 0,
    marginBottom:25
  },
  iconContainer: {
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
    flexDirection: "column",
    fontSize: "12px",
    color: "#172A44",
    fontFamily: "Proxima Nova",
  },

 

  label: {
    fontFamily: "Proxima Nova",
    fontSize: "16px",
    fontWeight: "bold",
    marginBottom:15,
    color: "#172A44",
  },

  icons: {
    display: "flex",
  },
 
  content: {
    lineHeight: "24px",
    color: "#172A44",
    whiteSpace: "pre-wrap"
  },
  ListItem:{
      display: "flex",
      flexDirection: "row",
      justifyContent: "space-between",
      alignItems:"center",
      padding:"0px 0px 10px 0px",
       fontFamily:"Proxima Nova",
  },
  ListContent: {
    color:"#172A44",
    fontSize:16,
    lineHeight:"24px"
  },
  drawer: {
    borderRadius: "26px 26px 0px 0px",
    maxHeight:"80vh"
  },
  drawerInside: {
    padding: "30px 15px 20px 15px",
    position: "relative",
    height: "100%",
  },
  Controls:{
    display: "flex",
    flex:"1",
    flexDirection: "row",
    justifyContent:"flex-end",
  marginTop:15, 
  marginBottom:15,
  },
  IconTop:{
    fontSize:40,
    padding:"0px 5px 0px 15px"
  },
  banner:{
    width:"50vw",
    paddingBottom:"33%",
    borderRadius:12,
    marginTop: 10
  },
  banner2:{
    width:"100%",
    paddingBottom:"56%",
    borderRadius:12
  }
}));

function Screen2(props) {
  const classes = useStyles();
  const [stats,setStats]=useState({clients:0,programSold:0,total:0})
  const [drawer, toggleDrawer]=useState(false)
  const [deleteModal, setDeleteModal] = useState(false);
  const [data, setData] = useState({
    BannerImage: null,
  });
  console.log(props.Profile)
  useEffect(() => {

    getStats(props.id).then(statsdata => {
     let data={}
      if(statsdata.clients.length>0){
data.clients=statsdata.clients[0].count
      }
      if(statsdata.total.length>0){
        data.programSold=statsdata.total[0].count
        data.total=statsdata.total[0].totalAmount
      
      }
      setStats({ ...stats, ...data})
    })

    props.getSpecificProgram(props.id).then((data) => {
      setData({ ...data, name:data.createdBy.name ,profilePic: data.createdBy.profilePic,});
    },(err)=>props.history.goBack());
  }, [props.id]);


  const onEdit=()=>{

    store.dispatch({ type:"EDIT_ID",payload:{editId:props.id}})
    props.history.push(`/edit-program/${props.id}`)
  }
  console.log(stats)

  const deleteProgram=()=>{
    props.deleteProgram(props.id).then((res)=>{
props.history.push("/instructor")
    })


  }

  const switchPublic=(val)=>{
    setData({...data,IsPublished:val})
    props.saveProgram({IsPublished:val,_id:props.id}).then((res)=>{
      
    },err=>{
      setData({...data,IsPublished:!val})
    })
  }


  const shareWorkout=()=>{
console.log(navigator)
    if(navigator.share)
    navigator.share({
      title: `${props.Profile.name} shared a fitness program : ${data.Title}`,
      url: `https://figgs.co/public/sharedProgram/${data._id}`
    }).then(() => {
     
    })
  }
  return (
   
    <Container>

      
<DeleteModal open={deleteModal}  delete={()=>{deleteProgram();setDeleteModal(false)}} handleClose={()=>setDeleteModal(false) } />


        <Header button={  <div className={classes.Controls}>
       <EyeButton className={classes.IconTop}
onClick={() =>props.history.push(`${props.match.url}/programControl/${data._id}/view`)}
/>
<ShareButton className={classes.IconTop} onClick={() =>shareWorkout()}/>
<SendButton className={classes.IconTop} onClick={()=>props.history.push(`/sendProgram/send/${data._id}`)}/>
<MoreHorizIcon className={classes.IconTop} style={{color:"rgba(23,42,68,0.75)"}} onClick={() =>toggleDrawer(true)}/>
       </div>} />
      <Content >
       

      {!props.match.params.view?  <div className={classes.mainDiv}>
          {/* <div className={classes.title}>{data.Title}</div> */}
     
<br/>
       <div
          className={classes.banner}
          style={{
            backgroundImage: data.BannerImage
              ? `url(${data.BannerImage})`
              : `url(${require("assets/img/fitness.jpg")})`,
            backgroundSize: "cover",
          }}
        >

          </div>

          <div className={classes.title}>{data.Title}</div>
        
<div style={{marginBottom:25}}>
  <div style={{marginBottom:10 ,lineHeight:"24px",color:"#172A44"}}>Price: <span style={{color:"#007EA0"}}>{data.Price?"$"+data.Price:"N/A"}</span></div>
  <div style={{lineHeight:"24px" ,color:"#172A44"}}>Type: <span style={{color:"#007EA0"}}>{data.PaymentType?data.PaymentType:"N/A"}</span></div>
</div>



          <div className={classes.AvatarContainer}>
            <div className={classes.Price}>
                <div className={classes.label} style={{marginBottom:7}}>Program Status</div>
              <small style={{color:"#172A44"}}>
              {data.IsPublished?"Program can be now viewed on your profile.":"Program are hidden on your profile."}
              </small>
            </div>
            <div className={classes.icons}>
             <Switch
             checked={data.IsPublished}
             onChange={event => switchPublic(event)}
             />
            </div>
          </div>

<div className={classes.label}>Statistics</div>

<div className={classes.ListItem}>
    <div className={classes.ListContent}>Clients active</div>
    <div className={classes.ListContent}>{stats.clients}</div>
</div>
<div className={classes.ListItem}>
    <div className={classes.ListContent}>Programs sold</div>
    <div className={classes.ListContent}>{stats.programSold}</div>
</div>
<div className={classes.ListItem}>
    <div className={classes.ListContent}>Total profits</div>
    <div className={classes.ListContent}>${stats.total}</div>
</div>

        </div>:


<div className={classes.mainDiv}>

<div style={{padding:"18px 0px 0px 0px"}}>
<div
  className={classes.banner2}
  style={{
    backgroundImage: data.BannerImage
      ? `url(${data.BannerImage})`
      : `url(${require("assets/img/fitness.jpg")})`,
    backgroundSize: "cover",
  }}
>
 
 

</div>
</div>
 <div className={classes.title} style={{fontWeight:"bold"}}>{data.Title}</div>
  <p>{data.Description}</p>

 
</div>
        
      
      
      }




        <Drawer
        anchor={"bottom"}
        open={drawer}
        onClose={() => toggleDrawer(false)}
        className={classes.drawer}
        classes={{ paper: classes.drawer }}
      >
 <div className={classes.drawerInside}>


<Editlist
onEdit={onEdit}
onDelete={()=>setDeleteModal(true)}
onView={()=>props.history.push(`/common/programViewInstructor/${props.id}`)}
/>
 </div>
          </Drawer>

      </Content>
     
    </Container>
  );
}

export default connect(null, { getSpecificProgram,saveProgram })(Screen2);
