import React, { Component ,useState} from "react";
import Container from "../../components/Layout/Container";
import Header from "../../components/Layout/Header";
import Content from "../../components/Layout/Content";
import Button from "../../components/CustomButtons/Button";
import Footer from "../../components/Layout/Footer";
import axios from "utils/axios";
import api from "utils/api"
import { makeStyles } from "@material-ui/core/styles";
import Primary from "../../components/Typography/Primary";
import ArrowRight from "assets/svg/ArrowRight";
import InsAthlete from "components/Card/InsAthlete";
import DietIcon from "assets/svg/DietIcon";
import Instructor from "assets/svg/Coach"
import Athlete from "assets/svg/WeightLifting"
import List from '@material-ui/core/List';
import ListItem from '@material-ui/core/ListItem';
import ListItemText from '@material-ui/core/ListItemText';
import ListItemAvatar from '@material-ui/core/ListItemAvatar';
import Earth from "assets/svg/Earth"
import Money from "assets/svg/Money"
import CustomTabs from "components/CustomTabs/CustomTabs.js";
import CustomInput from "components/CustomInput/CustomInput.js";
import PhoneInput from 'react-phone-input-2'
import OtpInput from 'react-otp-input';
import 'react-phone-input-2/lib/style.css'
const useStyles = makeStyles((theme) => ({
  root: {
    padding: "0px 30px 0px 30px",
  },
  title: {
    fontFamily: "Proxima Nova",
    fontWeight: "700",
    marginBlockStart: 0,
    marginBottom: 5,
    color:"#172A44",
    paddingLeft: 25,
  },
  mainDiv: {
    display: "flex",
    flex: 1,
    padding: 25,
    paddingTop:10,
    justifyContent: "center",
    alignItems: "center",
    marginBottom:100,
    flexDirection: "column",

    fontFamily: "Proxima Nova",
  },
  child1: {
    display: "flex",
    paddingBottom: "10px",
    flex: 1,
    width: "100%",
    flexDirection: "column",
    alignItems: "center",
  },
  child2: {
    flex: 2,
    paddingTop: "10px",
    display: "flex",
    flexDirection: "column",
    alignItems: "center",
    width: "100%",
    justifyContent: "space-around"
  },

  Footer: {
    margin: "0px 20px 20px 20px",
  },
  list:{
    width: '100%',
  },
  primary:{
    fontWeight: "bold",
    fontSize: 18,
    lineHeight: "18px",

  },
  secondary:{
      fontFamily: "Proxima Nova",
      marginTop:12,
      color: "#172A44",
    fontWeight:500,
    fontSize: 16,
    lineHeight: "28px",
    /* or 129% */
    paddingLeft: 25,
    paddingRight:25

  },
  icon:{
      fontSize:45,
      marginRight:25
  }
}));

export default function Screen2(props) {
  const classes = useStyles();
  const[verificationCode,setCode]=useState("")
  const email=props.Onboarding.email
const password=props.Onboarding.password
const authType=props.Onboarding.authType
const phone=props.Onboarding.phone
  const inputCode=(otp)=>{
     const regexp = /^[0-9]*$/

 let code=otp.toString()
console.log(code)
     if ( regexp.test(code)) {
       setCode(code)
   }
   if ( code.length==0) {
    setCode("")
}
   }


   const resendOTP=()=>{
    props.updateFeedback({loading:true})
    if(authType==0){
     
       axios.get(`${api.protocol}${api.baseUrl}${api.sendOtp}${phone}`).then((response)=>{
        props.updateFeedback({loading:false,snackbar:true,message:"Verification code sent to your mobile!",severity:"success"})
        props.history.push("/onboarding/account-verification",props.location.state)
        
      }).catch((error)=>{
        if(error.response.status ===406)
        return props.updateFeedback({loading:false,snackbar:true,message:"Acccount with give phone number already exists!",severity:"error"})
        else
        return props.updateFeedback({loading:false,snackbar:true,message:"Oops caught some error! Please try again",severity:"error"})
      })
    
    
      }
    
    else
    {
     
      axios.post(`${api.protocol}${api.baseUrl}${api.SendVerifyMail}`,{email:email}).then((response)=>{
        
        props.updateFeedback({loading:false,snackbar:true,message:"Verification mail sent to your email!",severity:"success"})
        props.history.push("/onboarding/account-verification",props.location.state)
      }).catch((error)=>{
        if(error.response.status ===406)
        return props.updateFeedback({loading:false,snackbar:true,message:"Acccount with give email address already exists!",severity:"error"})
        else
        return props.updateFeedback({loading:false,snackbar:true,message:"Oops caught some error! Please try again",severity:"error"})
      })
   
      }
   }

   const verifyAccount=()=>{
    if(verificationCode.length>2){


      if(props.Onboarding.authType==0){
        axios.get(`${api.protocol}${api.baseUrl}${api.verifyOtp}${props.Onboarding.phone}&otp=${verificationCode}`).then((res)=>{
          props.updateOnboarding({token:res.data.token})
           props.updateFeedback({loading:false,snackbar:true,message:"Account verification completed",severity:"success"})
          props.history.push(`/onboarding/account-password`,props.location.state)
        }).catch((err)=>{
          if(err.response.status ===400)
          return props.updateFeedback({loading:false,snackbar:true,message:"Invalid code!!",severity:"error"})
          if(err.response.status ===404)
          return props.updateFeedback({loading:false,snackbar:true,message:"Invalid code!",severity:"error"})
        })
      }
      else{

        axios.post(`${api.protocol}${api.baseUrl}${api.verifyMail}`,{email:props.Onboarding.email,token:verificationCode}).then((res)=>{
          props.updateOnboarding({token:res.data})
           props.updateFeedback({loading:false,snackbar:true,message:"Account verification completed",severity:"success"})
          props.history.push(`/onboarding/account-password`,props.location.state)
        }).catch((err)=>{
          if(err.response.status ===406)
          return props.updateFeedback({loading:false,snackbar:true,message:"Acccount with give email address already exists!",severity:"error"})
          if(err.response.status ===404)
          return props.updateFeedback({loading:false,snackbar:true,message:"Invalid code!",severity:"error"})
        })
      }
     
  
  }
  else
  {
    return props.updateFeedback({loading:false,snackbar:true,message:"Please enter a valide code!",severity:"warning"})
  }
  }
  return (
    <Container>
      <Header />

      <Content flex>
        <h2 className={classes.title}>Verification code</h2>
        <p className={classes.secondary}>
        {props.Onboarding.authType==0&&
        "Enter the code send to "+
        "number ending *** *** "+props.Onboarding.phone.substring(props.Onboarding.phone.length - 3,props.Onboarding.phone.length)
        }
        
        {props.Onboarding.authType==1&&
        "Enter the code we have texted to the "+
        "email ending "+props.Onboarding.email.substring(0,2)+" *** ***@"+props.Onboarding.email.split("@")[1]
        }
       
        
        
        
        
        <br/> 
        <span style={{color:"#007ea0"}} 
        onClick={()=>props.history.goBack()}
        >Change {props.Onboarding.authType==0?"phone":"email"}</span> or <span  onClick={resendOTP} style={{color:"#007ea0"}}>send again</span>
        </p>
        <div className={classes.mainDiv}>
         
        <OtpInput
        value={verificationCode}
        onChange={inputCode}
        numInputs={6}
        isInputNum={true}
        shouldAutoFocus={true}
        separator={<span>&nbsp;</span>}
        containerStyle={{border:"none",width:"100%",justifyContent:"space-around"}}
        inputStyle={{borderTop:"none" ,borderLeft:"none",borderRight:"none",padding:10,fontSize:24,color:"#007ea0"}}
        focusStyle={{ outline: "none",borderBottom:"2px solid #007ea0" ,color:"#007ea0"}}
        
        />
        </div>
      </Content>
      <Footer actionButton>
        <Button
          // onClick={()=>props.history.push(`/onboarding/account-name`)}
          onClick={verifyAccount}
          variant="contained"
          fullWidth
          disabled={verificationCode.length<6}
          size="lg"
          bold
          startIcon={<span style={{ marginLeft: 10 }}></span>}
          sideIcons
          endIcon={<ArrowRight />}
        >
          Submit
        </Button>
      </Footer>
    </Container>
  );
}
