import React, { Component } from "react";
import { Router, Route, Switch } from "react-router-dom";
import MoveFolder from "../Screens/figgsLibrary/MoveFolder";
import SelectFolder from "../Screens/figgsLibrary/fileManager";
import RecentFolder from "../Screens/figgsLibrary/recentFiles"
import { connect } from "react-redux";
import { updateFeedback } from "../store/actions/feedback";
import { updateProgram } from "../store/actions/createProgram";
import ExerciseView from "../Screens/common/ExerciseViewLib";
import {
  updateLibrary,
  createObject,
  fetchLibrary,
  deleteObject,
  fetchRecent
} from "../store/actions/figgsLibrary";
import AddExercise from "../Screens/createProgram/AddExercise";
class Library extends Component {
  state = {
    file: null,
    fileObject: null,
    folderData: [],
    selected: [],
    exerciseData: null,
  };

  addWorkout = (data) => {
    this.props
      .createObject({
        title: data.title,
        type: "file",
        ancestors: this.props.Library.ancestors,
        parent: this.props.Library.parent._id
          ? this.props.Library.parent._id
          : null,
        file: { ...data, otherDetails: { ...data }, type: "exercise" },
      })
      .then((res) => {
        this.props.Library.parent._id
          ? this.props.history.replace(
              `${this.props.match.path}/${this.props.Library.parent._id}`
            )
          : this.props.history.replace(`${this.props.match.path}`);
      });
  };

  setExerciseView = (item) => {
    this.setState({ exerciseData: item }, () => {
      this.props.history.push(`${this.props.match.url}/exercise/view`);
    });
  };

  setEditMode=(item)=>{
    this.setState({ exerciseData: item }, () => {
      this.props.history.push(`${this.props.match.url}/action/edit-exercise`);
    });
  }
  editExercise=(data)=>{

    this.props.updateLibrary({
      updateCondition: {_id:this.state.exerciseData._id} ,
      updateData:{title:data.title,file:{title:data.title,otherDetails:{...data}}}
     
     }).then(res=>{
      this.props.history.goBack();
     })
  }

  render() {
    

    return (
      <div>
        {/* <Route
          exact
          path={`${this.props.match.path}/`}
          render={() => (
            <SelectFolder
              {...this.props}
              {...this.state}
              setExerciseView={this.setExerciseView}
              addExercises={() => this.props.addExercises(this.state.selected)}
              setEditMode={this.setEditMode}
              parent={null}
              setState={(data) => this.setState(data)}
            />
          )}
        /> */}

        <Route
          exact
          path={`${this.props.match.path}/exercise/view`}
          render={() => (
            <ExerciseView
              {...this.props}
              library
              Program={{_id:"null"}}
              data={this.state.exerciseData}
            />
          )}
        />

        <Route
          exact
          path={`${this.props.match.path}/`}
          render={() => (
            <SelectFolder
              {...this.props}
              {...this.state}
              setEditMode={this.setEditMode}
              setExerciseView={this.setExerciseView}
              addExercises={() => this.props.addExercises(this.state.selected)}
              parent={null}
              setState={(data) => this.setState(data)}
            />
          )}
        />

        <Route
          exact
          path={`${this.props.match.path}/:parent`}
          render={(props) => (
            <SelectFolder
              {...this.props}
              {...this.state}
              setEditMode={this.setEditMode}
              setExerciseView={this.setExerciseView}
              addExercises={() => this.props.addExercises(this.state.selected)}
              parent={props.match.params.parent}
              setState={(data) => this.setState(data)}
            />
          )}
        />


<Route
          exact
          path={`${this.props.match.path}/folder/recent`}
          render={(props) => (
            <RecentFolder
              {...this.props}
              {...this.state}
              setEditMode={this.setEditMode}
              setExerciseView={this.setExerciseView}
              addExercises={() => this.props.addExercises(this.state.selected)}
              parent={null}
              setState={(data) => this.setState(data)}
            />
          )}
        />


        <Route
          exact
          path={`${this.props.match.path}/move/to/:parent`}
          render={(props) => (
            <MoveFolder
              {...this.props}
              {...this.state}
              setEditMode={this.setEditMode}
              setExerciseView={this.setExerciseView}
              parent={props.match.params.parent}
              setState={(data) => this.setState(data)}
            />
          )}
        />
        <Route
          exact
          path={`${this.props.match.path}/move/to`}
          render={(props) => (
            <MoveFolder
              {...this.props}
              {...this.state}
              setEditMode={this.setEditMode}
              setExerciseView={this.setExerciseView}
              parent={null}
              setState={(data) => this.setState(data)}
            />
          )}
        />
        <Route
          exact
          path={`${this.props.match.path}/action/add-exercise`}
          render={() => (
            <AddExercise
              {...this.props}
              file={this.state.file}
              setExerciseView={this.setExerciseView}
              setState={(data) => this.setState(data)}
              fileObject={this.state.fileObject}
              handleWorkoutSuccess={this.addWorkout}
         
            />
          )}
        />

<Route
          exact
          path={`${this.props.match.path}/action/edit-exercise`}
          render={() => (
            <AddExercise
              {...this.props}
              file={this.state.file}
              setExerciseView={this.setExerciseView}
              setState={(data) => this.setState(data)}
              fileObject={this.state.fileObject}
              handleWorkoutSuccess={this.addWorkout}
              editMode
              data={this.state.exerciseData}
              editExercise={this.editExercise}
            />
          )}
        />
      </div>
    );
  }
}

const mapStateToProps = (state) => {
  return {
    ProgramDetails: state.NewProgram,
    Library: state.Library,
  };
};

export default connect(mapStateToProps, {
  updateProgram,
  updateLibrary,
  createObject,
  fetchLibrary,
  deleteObject,
  updateFeedback,
  fetchRecent,
})(Library);
